-- Poems batch 280
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('62c9b89e-1da0-4e4a-ac5e-0538f59732d3','白雲寺','黄義貞','宋','宋诗','song-poetry','','[]','巘雲寶剎誦瑶編，屋上靈雲每見連。',64,'全唐诗/poet.song.247000.json','["巘雲寶剎誦瑶編，屋上靈雲每見連。", "知是蒼穹相表異，却教瑞氣日纏緜。", "絪緼像護清虛界，潔白光涵兜率天。", "老我欲過金子嶴，細探靈跡恨無緣。"]'),
('3a1df656-2a91-4d67-9c29-a5206fd88eb2','寄南海郭憲使','陳供','宋','宋诗','song-poetry','','[]','一望天涯萬里舟，波濤如掌見安流。',64,'全唐诗/poet.song.247000.json','["一望天涯萬里舟，波濤如掌見安流。", "霜威清逼珠光夜，海怪寒驚劍氣秋。", "人在西風何處夢，書回南雁隔年愁。", "政成載月歸來後，須到滄洲訪白頭。"]'),
('a4870d98-3666-452a-b805-4d9728d8cfe3','句','唐梅臞','宋','宋诗','song-poetry','','[]','水落一階翻碎玉。',8,'全唐诗/poet.song.247000.json','["水落一階翻碎玉。"]'),
('a3469644-b90c-4123-8eaa-29643093abd3','題曹娥廟','袁豢龍','宋','宋诗','song-poetry','','[]','不是沉淵效楚平，愛親念重愛身輕。',64,'全唐诗/poet.song.247000.json','["不是沉淵效楚平，愛親念重愛身輕。", "一抔殘土今如昨，千載英魂死亦生。", "辭詫外孫堪稱德，書傳列女永揚名。", "哀哀銜痛無時極，猶聽江猨似哭聲。"]'),
('fbef12e1-97bb-4850-9d7c-ed35db2ed4cd','伍子胥廟','鮑壽孫','宋','宋诗','song-poetry','','[]','百世子胥廟，猶存寂寞中。',48,'全唐诗/poet.song.247000.json','["百世子胥廟，猶存寂寞中。", "鞭屍生快怨，抉眼死遺忠。", "故國古今夢，怒濤朝夕風。", "登臨一長嘯，斜日海門紅。"]'),
('a4207f9c-0cf4-4fd1-a7f8-8f84e6c19d81','平山','鮑壽孫','宋','宋诗','song-poetry','','[]','平岡橫亙北城頭，一上青冥目數州。',64,'全唐诗/poet.song.247000.json','["平岡橫亙北城頭，一上青冥目數州。", "吳岫南從京口出，蜀江東赴海門流。", "香銷后土花如夢，煙鎖雷塘草亦愁。", "惟有依然淮泗水，年年吹浪到瓜洲。"]'),
('f7f745ba-b0c9-4c89-af8e-1a49bc88a95e','松聲','鮑壽孫','宋','宋诗','song-poetry','','[]','千丈森森磥砢生，風來巖壑韻琮琤。',64,'全唐诗/poet.song.247000.json','["千丈森森磥砢生，風來巖壑韻琮琤。", "耳根一洗俗塵淨，木末時聞天籟鳴。", "洶洶銀濤朝拍岸，蕭蕭鐵馬夜還營。", "山中宰相殷勤聽，說與傍人笑絕纓。"]'),
('4ddd83c4-82b9-47dd-afbf-e01b898922ac','蔣山八功德水','鮑壽孫','宋','宋诗','song-poetry','','[]','功德河沙七寶池，可如甘露降三危。',32,'全唐诗/poet.song.247000.json','["功德河沙七寶池，可如甘露降三危。", "鍾山一滴曹溪水，好及蕭郎索蜜時。"]'),
('29b9a0e3-b349-45fc-be2b-bb9c0e13b490','維揚懷古','鮑壽孫','宋','宋诗','song-poetry','','[]','江北江南水一涯，迷樓結綺兩堪悲。',32,'全唐诗/poet.song.247000.json','["江北江南水一涯，迷樓結綺兩堪悲。", "雷塘草綠人安在，曾見黄奴坐井時。"]'),
('cd609fc7-d576-4c44-a7e2-e17d1c3277bf','句  其一','鮑壽孫','宋','宋诗','song-poetry','','[]','我無孤雁句，君有倚樓詩。',12,'全唐诗/poet.song.247000.json','["我無孤雁句，君有倚樓詩。"]'),
('a39ee4db-6eef-4b7c-be17-730c68373b80','句  其二','鮑壽孫','宋','宋诗','song-poetry','','[]','一樽浮大白，千里策飛黄。',12,'全唐诗/poet.song.247000.json','["一樽浮大白，千里策飛黄。"]'),
('05f239bc-1320-45c3-80f2-f7dc55864e17','句  其三','鮑壽孫','宋','宋诗','song-poetry','','[]','千篇異代垂金薤，一曲當年忤玉環。',16,'全唐诗/poet.song.247000.json','["千篇異代垂金薤，一曲當年忤玉環。"]'),
('58306b1e-a317-4bba-a539-52a7b422bf82','句  其四','鮑壽孫','宋','宋诗','song-poetry','','[]','但喜親庭健，何愁客路長。',12,'全唐诗/poet.song.247000.json','["但喜親庭健，何愁客路長。"]'),
('5898dade-b0d2-4fbc-902f-31b8a6180155','句  其五','鮑壽孫','宋','宋诗','song-poetry','','[]','少日從游今老矣，殘冬話別各淒然。',16,'全唐诗/poet.song.247000.json','["少日從游今老矣，殘冬話別各淒然。"]'),
('5c71ada8-54ab-4917-b549-7cc188e17cc3','句  其六','鮑壽孫','宋','宋诗','song-poetry','','[]','重生子厚爲師範，更與宣尼續廟碑。',16,'全唐诗/poet.song.247000.json','["重生子厚爲師範，更與宣尼續廟碑。"]'),
('0325f5d7-fbb6-48d5-850c-e6a9d88ddd5c','送梁必大歸杭省親  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','悠悠楚水，靄靄吳雲。',40,'全唐诗/poet.song.247000.json','["悠悠楚水，靄靄吳雲。", "孰作之合，胡然而分。", "豈無良朋，我獨子忻。", "於穆令德，有粲其文。"]'),
('3bb6407d-5e95-4f5a-bb94-b3c4c28ce1a5','送梁必大歸杭省親  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','吳雲靄靄，楚水悠悠。',40,'全唐诗/poet.song.247000.json','["吳雲靄靄，楚水悠悠。", "眷念庭闈，道阻且修。", "爲貧而仕，匪食孰求。", "曷不偕來，以解爾憂。"]'),
('9f75c8bc-be3b-4a7d-904d-f7ebcbef3ebb','送梁必大歸杭省親  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','瞻彼日月，有望有弦。',40,'全唐诗/poet.song.247000.json','["瞻彼日月，有望有弦。", "慨彼中年，別友實難。", "有芹於池，有芝於山。", "式遄其歸，勿遠其還。"]'),
('d2f0e9f0-aea0-4fb6-9e64-b4ec9d717bf6','李泌二首','黎廷瑞','宋','宋诗','song-poetry','','[]','一副黄臺話，離離詠種瓜。',24,'全唐诗/poet.song.247000.json','["一副黄臺話，離離詠種瓜。", "都來三十字，救得兩官家。"]'),
('dc5a25e7-44fc-4df7-8283-5868565c5fe0','食新有感','黎廷瑞','宋','宋诗','song-poetry','','[]','盡道豐年好，停餐意惘然。',24,'全唐诗/poet.song.247000.json','["盡道豐年好，停餐意惘然。", "離離洛都黍，莽莽建州田。"]'),
('de27907b-8b27-4399-976e-fa05e039ddd8','題趙氏曉山  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','旦氣炯清明，曙色淡空凈。',24,'全唐诗/poet.song.247000.json','["旦氣炯清明，曙色淡空凈。", "悠然見青山，盡見天地性。"]'),
('9b63f45b-94e8-4cee-95e8-30958102776d','題趙氏曉山  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','烟雲亂晝陰，雨雹交晚風。',24,'全唐诗/poet.song.247000.json','["烟雲亂晝陰，雨雹交晚風。", "道人定眼觀，祇與清曉同。"]'),
('23660eb3-c1b4-4c7a-84b6-ea63365328d4','張良','黎廷瑞','宋','宋诗','song-poetry','','[]','博浪揮椎處，惓惓報國仇。',24,'全唐诗/poet.song.247000.json','["博浪揮椎處，惓惓報國仇。", "如何銷印事，獨不爲韓謀。"]'),
('0b754799-6507-4036-a2e8-7ebe34330de0','鳳凰臺二首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','泪落零陽酒一杯，赤藤遺墨亦堪哀。',32,'全唐诗/poet.song.247000.json','["泪落零陽酒一杯，赤藤遺墨亦堪哀。", "蒼梧雲去簫聲冷，莫是當年也誤來。"]'),
('38aaa92a-4c15-480e-9856-43adef208072','鳳凰臺二首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','三山二水年年在，向日浮雲處處多。',32,'全唐诗/poet.song.247000.json','["三山二水年年在，向日浮雲處處多。", "醉拍欄桿呼李白，東風吹雨下新河。"]'),
('232df48a-0ca1-4c9f-852e-54533c930c25','半山寺謁謝太傅像','黎廷瑞','宋','宋诗','song-poetry','','[]','狐精解唱桂枝香，一曲中洲禾黍黄。',32,'全唐诗/poet.song.247000.json','["狐精解唱桂枝香，一曲中洲禾黍黄。", "辦得蒼生謝安石，東山絲竹又何妨。"]'),
('a26d158d-558d-4e5e-8dcb-f5169c686b9c','舟行','黎廷瑞','宋','宋诗','song-poetry','','[]','深深人語轉蒼崖，牽路如梯滑似苔。',32,'全唐诗/poet.song.247000.json','["深深人語轉蒼崖，牽路如梯滑似苔。", "睡起擁篷看奇石，一方新綠入船來。"]'),
('21cd6760-8555-4565-992b-424851f0127f','寄龍山譚使君五首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','萬里雲濤海嶠秋，倩人扶上黑雲兜。',32,'全唐诗/poet.song.247000.json','["萬里雲濤海嶠秋，倩人扶上黑雲兜。", "一簾新雨西樓晚，卧聽烏衣說舊愁。"]'),
('2af75d1f-a023-4095-9b43-8e0d8ca851a8','寄龍山譚使君五首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','流離遷徙古今同，澹沲青山往事空。',32,'全唐诗/poet.song.247000.json','["流離遷徙古今同，澹沲青山往事空。", "四壁蟲聲秋思苦，夢中猶自奏豳風。"]'),
('e852e004-aa05-45b3-ae18-96f4bb4cd790','寄龍山譚使君五首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','霧閣雲窗罨畫開，半栽松竹半栽梅。',32,'全唐诗/poet.song.247000.json','["霧閣雲窗罨畫開，半栽松竹半栽梅。", "不須更種桃花樹，怕引漁郎入洞來。"]'),
('574fa307-6144-44a2-851b-7895fd147c22','寄龍山譚使君五首  其四','黎廷瑞','宋','宋诗','song-poetry','','[]','題遍寒巖古佛廬，唐人詩句晉人書。',32,'全唐诗/poet.song.247000.json','["題遍寒巖古佛廬，唐人詩句晉人書。", "山靈亦恨無清福，消得君侯此卜居。"]'),
('105b9f2a-b667-4da3-9d70-fdbdff827686','夜坐','黎廷瑞','宋','宋诗','song-poetry','','[]','梧桐月轉影翩翩，竹屋抄書夜未眠。',32,'全唐诗/poet.song.247000.json','["梧桐月轉影翩翩，竹屋抄書夜未眠。", "林下不知秋遠近，西風一葉墮燈前。"]'),
('9cb58e84-df95-4f56-9611-82d5e4c5339f','湖上夜坐二首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','露坐空庭竹四圍，夜深更不掩柴扉。',32,'全唐诗/poet.song.247000.json','["露坐空庭竹四圍，夜深更不掩柴扉。", "茫茫雲海月未上，蒼耳滿園螢亂飛。"]'),
('2e84d1e3-90ca-4226-95a6-7323c706b11c','湖上夜坐二首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','平湖漠漠來孤艇，遠樹冥冥見一燈。',32,'全唐诗/poet.song.247000.json','["平湖漠漠來孤艇，遠樹冥冥見一燈。", "翁媼隔籬呼稚子，岸頭猶有未收罾。"]'),
('ab9ab3e9-762e-48c6-bf53-147ab8228723','午坐偶成','黎廷瑞','宋','宋诗','song-poetry','','[]','日高篁竹門長掩，春晚蕪菁花亂開。',32,'全唐诗/poet.song.247000.json','["日高篁竹門長掩，春晚蕪菁花亂開。", "寂寞更無人問字，一雙蝴蝶雨中來。"]'),
('502e5208-4ec4-4987-b898-089e7502bb79','揚州遇雪呈祝靜得二首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','玉珮珊珊怯暮寒，青霄夜半躡飛鸞。',32,'全唐诗/poet.song.247000.json','["玉珮珊珊怯暮寒，青霄夜半躡飛鸞。", "真妃似念尋芳晚，別剪瓊花與客看。"]'),
('3c8d0cb2-36d5-444d-80c0-ad77b27374c4','揚州遇雪呈祝靜得二首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','六合沉冥四壁空，夢魂只繞楚雲東。',32,'全唐诗/poet.song.247000.json','["六合沉冥四壁空，夢魂只繞楚雲東。", "明當掛席黄天蕩，卧看茫茫柳絮風。"]'),
('fdfaf799-135d-4108-b1c6-36f87a068d40','落花','黎廷瑞','宋','宋诗','song-poetry','','[]','紅雪霏霏入燕泥，朝來猶是可憐枝。',32,'全唐诗/poet.song.247000.json','["紅雪霏霏入燕泥，朝來猶是可憐枝。", "春風葵麥玄都觀，可是劉郎見事遲。"]'),
('d0c77a25-216b-41de-ae4d-a2e57c807134','飲百花洲四首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','北嶺尋花雲繞屐，東湖載酒水平船。',32,'全唐诗/poet.song.247000.json','["北嶺尋花雲繞屐，東湖載酒水平船。", "舊游零落令餘幾，回首春風十二年。"]'),
('35b2f094-7c14-4b1f-aa5a-1d902341f6d0','飲百花洲四首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','湖山幾度少年游，散髪吹簫坐小舟。',32,'全唐诗/poet.song.247000.json','["湖山幾度少年游，散髪吹簫坐小舟。", "秋鬢蒼蒼春樹碧，更堪重過百花洲。"]'),
('6ac140b1-a1b1-4d82-aa9d-5ae9f1fcf418','飲百花洲四首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','桃花繞屋竹參天，曾向湖西住五年。',32,'全唐诗/poet.song.247000.json','["桃花繞屋竹參天，曾向湖西住五年。", "回首但餘葵麥在，古今何必更桑田。"]'),
('76fdcad9-5ad7-4558-a103-af5f03fe8dc2','飲百花洲四首  其四','黎廷瑞','宋','宋诗','song-poetry','','[]','歸鴉澹澹夕陽閒，窅窕樓臺紫翠間。',32,'全唐诗/poet.song.247000.json','["歸鴉澹澹夕陽閒，窅窕樓臺紫翠間。", "說向城中應不信，隔湖最好看芝山。"]'),
('f9b328bf-2e5a-4d13-9572-254e121c2802','東湖詩十首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','游絲窈窕織春暉，楊柳人家半掩扉。',32,'全唐诗/poet.song.247000.json','["游絲窈窕織春暉，楊柳人家半掩扉。", "一片暖雲篩雨過，杏花疏處見鶑歸。"]'),
('591bf8e5-b873-4f2c-8ab4-cc30e5575955','東湖詩十首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','梅徑苔花長菉衣，仙翁跨鶴不曾歸。',32,'全唐诗/poet.song.247000.json','["梅徑苔花長菉衣，仙翁跨鶴不曾歸。", "五陵年少無聊頼，幾陣風鈴放鴿飛。"]'),
('426e16eb-44dc-44b3-8fa2-92d009224c68','東湖詩十首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','萬頃湖波水渺茫，兩堤新綠柳絲長。',32,'全唐诗/poet.song.247000.json','["萬頃湖波水渺茫，兩堤新綠柳絲長。", "晚來疏雨浮鷗外，何處漁郎泛小航。"]'),
('b36cdf3b-7cf1-4f31-aa79-44a584edf2d4','田家','黎廷瑞','宋','宋诗','song-poetry','','[]','陌上青裙跣送茶，籬根白髪卧看家。',32,'全唐诗/poet.song.247000.json','["陌上青裙跣送茶，籬根白髪卧看家。", "山禽不語簷陰轉，一樹輕風落柿花。"]'),
('9eafb687-30ba-4564-a932-9bd47823d0c4','山行二絕  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','杖藜窅窕更崎嶇，黄葉漫山路欲無。',32,'全唐诗/poet.song.247000.json','["杖藜窅窕更崎嶇，黄葉漫山路欲無。", "小屋低烟長短竹，曲塘斜日兩三鳬。"]'),
('370082ce-09a6-4478-87c9-73877583249d','山行二絕  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','野老相過一笑迎，黄雞白酒愧深情。',32,'全唐诗/poet.song.247000.json','["野老相過一笑迎，黄雞白酒愧深情。", "山空日落早歸去，昨夜隔籬聞虎聲。"]'),
('e7ccd7d8-5c9b-46c4-9040-d49a8bbaad3c','客舍','黎廷瑞','宋','宋诗','song-poetry','','[]','門前蒼耳與人齊，屋後青蛙作鬼啼。',32,'全唐诗/poet.song.247000.json','["門前蒼耳與人齊，屋後青蛙作鬼啼。", "風雨瀟瀟天正黑，披衣不寐聽鳴鷄。"]'),
('54ff4dff-00ea-4c81-99a6-9c5c1b7b9dbe','大雪過花子峰下有懷仲退南翁兼簡志上人  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','詩人得意吐還休，長要胸中此境留。',32,'全唐诗/poet.song.247000.json','["詩人得意吐還休，長要胸中此境留。", "千載風流今始解，剡溪夜半有行舟。"]'),
('da84a655-c3c5-47ed-b662-e15edc5cb76e','大雪過花子峰下有懷仲退南翁兼簡志上人  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','閣下溪流閣上山，溪山正好此時看。',32,'全唐诗/poet.song.247000.json','["閣下溪流閣上山，溪山正好此時看。", "絕憐孤負臨風約，輸與山僧獨倚闌。"]'),
('fe366aa2-67bb-4950-9c63-5234195f3ef4','九日二首','黎廷瑞','宋','宋诗','song-poetry','','[]','山下驚天動地雷，山頭聽得似嬰孩。',32,'全唐诗/poet.song.247000.json','["山下驚天動地雷，山頭聽得似嬰孩。", "幾回看盡人間世，只好登高莫下來。"]'),
('83825936-de15-43ff-9d35-cddeea949585','予舊遊白鹿洞坐看書臺風泉四面松聲萬壑去三十年猶在吾耳','黎廷瑞','宋','宋诗','song-poetry','','[]','風泉吹滿看書臺，洞口松聲萬壑哀。',32,'全唐诗/poet.song.247000.json','["風泉吹滿看書臺，洞口松聲萬壑哀。", "幾度倚闌聽不足，請君琴裏寫歸來。"]'),
('fbde5a1b-9ebf-4c0d-9492-5d9b3baeeb91','雨後過東山','黎廷瑞','宋','宋诗','song-poetry','','[]','羸驂破帽約輕寒，破費春風半日閒。',32,'全唐诗/poet.song.247000.json','["羸驂破帽約輕寒，破費春風半日閒。", "一事無成年四十，又隨花柳過東山。"]'),
('4a274542-d5d3-4b0b-a100-0fe2a282948a','山行','黎廷瑞','宋','宋诗','song-poetry','','[]','籃輿一路野梅風，午酒濛濛困未鬆。',32,'全唐诗/poet.song.247000.json','["籃輿一路野梅風，午酒濛濛困未鬆。", "側首松梢聽晴哢，數峰殘雪夕陽中。"]'),
('cd948065-e7ce-418e-8fd9-7c67020de074','病目','黎廷瑞','宋','宋诗','song-poetry','','[]','兩眼誰憐著古今，中年贏得淚沾巾。',32,'全唐诗/poet.song.247000.json','["兩眼誰憐著古今，中年贏得淚沾巾。", "冥鴻滅沒看天曉，搔首熏風對玉琴。"]'),
('d0e734f2-d8b5-4012-b4af-941f17e78404','王子猷','黎廷瑞','宋','宋诗','song-poetry','','[]','東晉諸公富貴癡，風流千載使人悲。',32,'全唐诗/poet.song.247000.json','["東晉諸公富貴癡，風流千載使人悲。", "子猷欲作袁安卧，還有閒情適剡溪。"]'),
('f35c5be2-de04-4360-8807-e5c0376cd7a5','過馬當祈風','黎廷瑞','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','獨倚危檣數過鴻，家山渺渺楚雲東。',32,'全唐诗/poet.song.247000.json','["獨倚危檣數過鴻，家山渺渺楚雲東。", "吟情不到滕王閣，只乞歸帆一日風。"]'),
('b19b06c1-feaf-45d6-bb76-2a9426084a95','楚翁別五年丙午四月來山中風雨數日因話舊作再賦三絕僕與楚翁至是三聽雨矣不知自此又幾聽雨耶  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','舍前舍後竹冥冥，山雨瀟瀟徹夜聽。',32,'全唐诗/poet.song.247000.json','["舍前舍後竹冥冥，山雨瀟瀟徹夜聽。", "還似當年談舊夢，兩翁相對一燈青。"]'),
('6c5a7bc1-d9e2-4ec2-ba6e-1f6f73790e92','楚翁別五年丙午四月來山中風雨數日因話舊作再賦三絕僕與楚翁至是三聽雨矣不知自此又幾聽雨耶  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','五載期君君不來，悠悠世路忽相猜。',32,'全唐诗/poet.song.247000.json','["五載期君君不來，悠悠世路忽相猜。", "從今無事長相見，縱使百年能幾回。"]'),
('b6c762a0-21ea-4b55-ad10-4efcd26e4c3f','楚翁別五年丙午四月來山中風雨數日因話舊作再賦三絕僕與楚翁至是三聽雨矣不知自此又幾聽雨耶  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','三千年待桃花結，五百歲還銅狄磨。',32,'全唐诗/poet.song.247000.json','["三千年待桃花結，五百歲還銅狄磨。", "我輩相期非旦暮，五年離別未爲多。"]'),
('b177afdb-0c76-4495-9715-4f1b96c3f61b','新城宴集夜歸','黎廷瑞','宋','宋诗','song-poetry','','[]','獵獵天風吹酒醒，茅茨籬落尚燈明。',32,'全唐诗/poet.song.247000.json','["獵獵天風吹酒醒，茅茨籬落尚燈明。", "梅花屋背無人見，殘角疏鐘雪一城。"]'),
('2de34a18-26a9-4dd4-b8ce-261ebffc1bcd','清溪許希賢自號拙逸爲賦四絕  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','結繩已是散洪濛，書契紛紛日更工。',32,'全唐诗/poet.song.247000.json','["結繩已是散洪濛，書契紛紛日更工。", "無極已前誰得似，一簾草色自春風。"]'),
('2fd9cc2f-add8-48dc-a169-f46d083b2976','清溪許希賢自號拙逸爲賦四絕  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','瓜果蛛絲五綵針，年年兒女費精神。',32,'全唐诗/poet.song.247000.json','["瓜果蛛絲五綵針，年年兒女費精神。", "世間巧盡天無巧，更要如何巧與人。"]'),
('1ae3e337-4ac1-4c8b-a1be-c0a158fd7737','清溪許希賢自號拙逸爲賦四絕  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','能言鸚鵡鎖金籠，夜夜家山桂子風。',32,'全唐诗/poet.song.247000.json','["能言鸚鵡鎖金籠，夜夜家山桂子風。", "羨殺雙鳩有閒福，相呼相喚柳陰中。"]'),
('00d11fc7-1b86-4a3e-be81-b6bd9c7093e2','清溪許希賢自號拙逸爲賦四絕  其四','黎廷瑞','宋','宋诗','song-poetry','','[]','莫笑區區老漢陰，桔橰省力却勞心。',32,'全唐诗/poet.song.247000.json','["莫笑區區老漢陰，桔橰省力却勞心。", "甕頭別有天機在，春雨半畦新綠深。"]'),
('077ae6e2-942b-40e2-b654-8504bb8cf8ef','次韵張龍使君十絕  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','泠泠流水山圍洞，漠漠桃花春閉門。',32,'全唐诗/poet.song.247000.json','["泠泠流水山圍洞，漠漠桃花春閉門。", "蛇去馬來多少夢，桃源還是舊乾坤。"]'),
('c5ca92fa-6c7b-4656-ac67-4495f1b8ec55','次韵張龍使君十絕  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','雨餘秧馬各相先，綠滿平疇斷復連。',32,'全唐诗/poet.song.247000.json','["雨餘秧馬各相先，綠滿平疇斷復連。", "喜得人間機事息，桔橰閒在槿籬邊。"]'),
('71ca0e00-24e7-4a4d-97b3-69f6758cdb43','次韵張龍使君十絕  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','塵裏一籠天地窄，樓頭萬幅水雲寬。',32,'全唐诗/poet.song.247000.json','["塵裏一籠天地窄，樓頭萬幅水雲寬。", "何當化作千年鶴，却伴遼東管幼安。"]'),
('499c1bdc-ba37-4c2f-b14d-6bcafe423e67','端午東湖觀競渡','黎廷瑞','宋','宋诗','song-poetry','','[]','記得當年年少時，蘭湯浴罷試新衣。',32,'全唐诗/poet.song.247000.json','["記得當年年少時，蘭湯浴罷試新衣。", "三三五五垂楊底，守定龍舟看不歸。"]'),
('e51a9703-9510-4208-beb6-71003b884303','贈山翁','黎廷瑞','宋','宋诗','song-poetry','','[]','浮雲鬰鬰成蒼狗，黄鵠高高化白鳬。',32,'全唐诗/poet.song.247000.json','["浮雲鬰鬰成蒼狗，黄鵠高高化白鳬。", "惟有大程窺此妙，不將算法問堯夫。"]'),
('43a94081-12c1-46f6-ab57-34cf54bb6da7','丁丑元夕','黎廷瑞','宋','宋诗','song-poetry','','[]','嫋嫋條風至，悠悠桂影升。',48,'全唐诗/poet.song.247000.json','["嫋嫋條風至，悠悠桂影升。", "黄昏村市鼓，紅日社林燈。", "節序更悲樂，乾坤幾廢興。", "龍城舊游處，說著淚沾膺。"]'),
('a2065fca-02fc-47c2-8c57-1d7976854e55','戊寅人日','黎廷瑞','宋','宋诗','song-poetry','','[]','滿飲東風酒，悠悠自醉眠。',48,'全唐诗/poet.song.247000.json','["滿飲東風酒，悠悠自醉眠。", "英雄悲往運，兒女樂新年。", "楊柳嬌無頼，梅花老更妍。", "半窗晴日晚，欹枕聽春鳶。"]'),
('36887776-f692-4e67-897f-726a6ba97379','贈地理方生','黎廷瑞','宋','宋诗','song-poetry','','[]','桑田還變海，深谷或爲陵。',48,'全唐诗/poet.song.247000.json','["桑田還變海，深谷或爲陵。", "物化全難料，山經果可憑。", "小溪春綠繞，新樹午陰層。", "且了登臨事，風烟擁瘦藤。"]'),
('ac6f2ac4-c095-43fa-b37b-b90270e89bf9','入夏','黎廷瑞','宋','宋诗','song-poetry','','[]','入夏纔幾日，新晴已不禁。',48,'全唐诗/poet.song.247000.json','["入夏纔幾日，新晴已不禁。", "闌珊花晚景，掩映樹初陰。", "西照山河影，南風天地心。", "物情殊可笑，團扇已駸駸。"]'),
('31ee3842-279c-4a3b-85b5-224e5c38c17e','聽琴','黎廷瑞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','虛籟起還休，輕絲斷復抽。',48,'全唐诗/poet.song.247000.json','["虛籟起還休，輕絲斷復抽。", "鬼啼湘竹雨，木落洞庭秋。", "因子作浙操，令人悲楚囚。", "蒼梧不可叫，杳杳暮雲愁。"]'),
('856164f0-c379-4a61-917c-0e4131b93e29','江行','黎廷瑞','宋','宋诗','song-poetry','','[]','卷縴崖形斷，開帆浦意孤。',48,'全唐诗/poet.song.247000.json','["卷縴崖形斷，開帆浦意孤。", "長天低去鳥，落日蘸平湖。", "渺渺千年夢，悠悠萬化途。", "倚篷成晤歎，漁唱在菰蒲。"]'),
('a19014fb-cdc3-4f5d-9820-6dd18e7ae35c','新亭','黎廷瑞','宋','宋诗','song-poetry','','[]','不復新亭淚，其如感慨何。',48,'全唐诗/poet.song.247000.json','["不復新亭淚，其如感慨何。", "北風吹草木，西照滿山河。", "王謝聞孫少，蕭陳短夢多。", "庭芳摇落盡，江上有漁歌。"]'),
('eecf962e-0ce4-4f02-a4cd-2b3fa560a8b4','聽琴','黎廷瑞','宋','宋诗','song-poetry','','[]','凄凉烏夜啼，怨抑雉朝飛。',48,'全唐诗/poet.song.247000.json','["凄凉烏夜啼，怨抑雉朝飛。", "有室寧非願，無枝可得依。", "天涯心獨苦，歲晚淚頻揮。", "莫作將歸操，風塵久念歸。"]'),
('177691db-d4f7-4ec0-bf9c-6a6706fe871b','社日飲烏衣園','黎廷瑞','宋','宋诗','song-poetry','','[]','夜夜桃花雨，年年燕子春。',48,'全唐诗/poet.song.247000.json','["夜夜桃花雨，年年燕子春。", "同傾社日酒，還憶故園人。", "孤塔蒼烟迥，空堂翠草新。", "醉歸還自笑，吾亦素衣塵。"]'),
('584c15dd-778e-4a3d-8927-ed93796ddb6c','故宮','黎廷瑞','宋','宋诗','song-poetry','','[]','麥飯苦經營，桑田許變更。',48,'全唐诗/poet.song.247000.json','["麥飯苦經營，桑田許變更。", "饑鴉啼古井，獨鸛下荒城。", "落日關河迥，東風草木榮。", "蒼蒼十二檜，顔色尚承平。"]'),
('dc3e2600-94a3-48a2-9f06-63b4ad2f05f0','甲子雨次日清明','黎廷瑞','宋','宋诗','song-poetry','','[]','政須晴甲子，早作雨清明。',48,'全唐诗/poet.song.247000.json','["政須晴甲子，早作雨清明。", "萬樹朝烟濕，一溪春雨平。", "農謠若果驗，歲事已堪驚。", "天意非人料，西疇且力耕。"]'),
('3cc0ca7b-a40a-4f1e-be1e-f29d15ddc217','輓王水監','黎廷瑞','宋','宋诗','song-poetry','','[]','庾嶺梅千樹，貪閒不肯看。',48,'全唐诗/poet.song.247000.json','["庾嶺梅千樹，貪閒不肯看。", "鳬歸玉棺下，鶴去碧桃寒。", "海嶽遺文在，乾坤短夢殘。", "蓬萊都水監，應復署仙官。"]'),
('cf654056-409c-4d05-87ad-7ae090395561','聞蛙','黎廷瑞','宋','宋诗','song-poetry','','[]','族處汙池底，氣張新雨餘。',48,'全唐诗/poet.song.247000.json','["族處汙池底，氣張新雨餘。", "交交還閣閣，疾疾更徐徐。", "別製鼓吹曲，自吟蝌蚪書。", "道人喧寂等，欹枕到華胥。"]'),
('5a05cf8d-756a-4201-a370-9691c9e153cb','湖上觀螢','黎廷瑞','宋','宋诗','song-poetry','','[]','依依起草際，煜煜點荷心。',48,'全唐诗/poet.song.247000.json','["依依起草際，煜煜點荷心。", "應是地生火，得非天雨金。", "神奇出臭腐，光怪發幽陰。", "莫說太陽近，明蟾已不禁。"]'),
('fe748fb0-42c7-4727-bafc-9ff15a86d06c','六月郡庠尊經閣前種竹三得雨書喜示同舍','黎廷瑞','宋','宋诗','song-poetry','','[]','移種來數日，三沾沛雨恩。',48,'全唐诗/poet.song.247000.json','["移種來數日，三沾沛雨恩。", "雷公念同族，龍伯愛諸孫。", "鞭活金髯走，梢寒翠鬣翻。", "拂雲吾所望，好爲護霜根。"]'),
('d021e4fd-ec41-44c6-88ad-1133908d5bd9','題李子厚萬梅','黎廷瑞','宋','宋诗','song-poetry','','[]','樹樹都吟遍，須還千億身。',48,'全唐诗/poet.song.247000.json','["樹樹都吟遍，須還千億身。", "未應分寸地，能著許多春。", "丈室來諸佛，懸珠內衆真。", "閉門參此妙，一笑月痕新。"]'),
('504593fa-bfb1-4fc2-a23c-277f48d50388','視穫','黎廷瑞','宋','宋诗','song-poetry','','[]','漠漠稻粱稀，紛紛鳥雀飛。',48,'全唐诗/poet.song.247000.json','["漠漠稻粱稀，紛紛鳥雀飛。", "吾田空竭力，汝族更求肥。", "舌在談何用，躬耕計又非。", "悵然還獨笑，落日掩郊扉。"]'),
('6badf8ea-9af1-49d2-81d0-f0c808f3052c','江行阻風','黎廷瑞','宋','宋诗','song-poetry','','[]','遠涉仍多病，那堪正藴隆。',48,'全唐诗/poet.song.247000.json','["遠涉仍多病，那堪正藴隆。", "黄沙吹白浪，赤日照青楓。", "天地支頤內，江山散髪中。", "一凉端足快，莫恨打頭風。"]'),
('cf0a1a4e-c2f5-44cf-8089-0322a574502f','送族兄太初再遊廬山','黎廷瑞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','家山豈不好，更欲訪廬君。',48,'全唐诗/poet.song.247000.json','["家山豈不好，更欲訪廬君。", "應意麋鹿友，其如鴻雁群。", "江湖秋渺渺，道路雨紛紛。", "歲晚成歸否，高山有白雲。"]'),
('88c78145-507e-4bf3-9062-d33eb7e0dc9a','雨中旅懷','黎廷瑞','宋','宋诗','song-poetry','','[]','驟雨半日許，新泥一尺餘。',48,'全唐诗/poet.song.247000.json','["驟雨半日許，新泥一尺餘。", "鷓鴣憂我馬，杜宇愛吾廬。", "問宿忻逢竹，停餐遲買蔬。", "明朝踏歸路，晴霽定何如。"]'),
('eeb5a74d-125e-471b-ab75-79376f7c5244','過鎮巢','黎廷瑞','宋','宋诗','song-poetry','','[]','過盡黄蕪岸，開橋小雨時。',48,'全唐诗/poet.song.247000.json','["過盡黄蕪岸，開橋小雨時。", "城居懸似燕，山勢縮如龜。", "歲旱圩田薄，天寒土屋宜。", "呼童沽白酒，巢口賽新祠。"]'),
('242ca00d-73d1-4f3c-a604-548d94b0773c','答客問','黎廷瑞','宋','宋诗','song-poetry','','[]','錫號翛閒客，山中管白雲。',48,'全唐诗/poet.song.247000.json','["錫號翛閒客，山中管白雲。", "自稱前進士，人喚故參軍。", "花影供吟課，茶香策睡勳。", "客來談外事，去去不煩君。"]'),
('624eae36-53e1-459e-90c9-c647f67f7f91','晉元帝廟','黎廷瑞','宋','宋诗','song-poetry','','[]','不知牛繼馬，却道馬爲龍。',48,'全唐诗/poet.song.247000.json','["不知牛繼馬，却道馬爲龍。", "得士能成帝，生兒不亢宗。", "荒祠烟樹晚，殘碣雨苔封。", "往事憑誰問，春城起暮鐘。"]'),
('21fff2e0-5f0a-4ff5-b663-b93e56f93268','病歸','黎廷瑞','宋','宋诗','song-poetry','','[]','渺渺江淮夢，還持一笑歸。',48,'全唐诗/poet.song.247000.json','["渺渺江淮夢，還持一笑歸。", "遠遊諳世路，危病得天機。", "慢火煎凉藥，清泉浣暑衣。", "閉門謝來客，不是客來稀。"]'),
('88a56ddc-0f27-4035-abb0-be27f23db08c','被葛','黎廷瑞','宋','宋诗','song-poetry','','[]','被葛起視夜，梧心正露零。',48,'全唐诗/poet.song.247000.json','["被葛起視夜，梧心正露零。", "浮生多夢境，幽客獨中庭。", "星斗三更動，天河萬里橫。", "尋秋無覓處，四壁但蟲聲。"]'),
('294e591a-4918-46c7-8975-f1564ff813e8','登鄱江樓','黎廷瑞','宋','宋诗','song-poetry','','[]','江城一登眺，寒色有無間。',48,'全唐诗/poet.song.247000.json','["江城一登眺，寒色有無間。", "帆拂沙頭樹，僧歸雲外山。", "樓高西照急，葉盡北風閒。", "世事何時足，悠悠飛鳥還。"]'),
('07bd82e9-700b-4cf5-a061-e5c17741c494','歲晏','黎廷瑞','宋','宋诗','song-poetry','','[]','歲晏甘離索，山扉午不開。',48,'全唐诗/poet.song.247000.json','["歲晏甘離索，山扉午不開。", "凍蜂粘病菊，饑雀啄疏梅。", "美睡拋書冊，清齋遠酒杯。", "殷勤謝塵客，無事莫頻來。"]'),
('2c3764cb-ce6d-431e-bdbc-adb595b73afc','送史水東訪餘干張千林','黎廷瑞','宋','宋诗','song-poetry','','[]','永夜一燈青，相逢話苦心。',48,'全唐诗/poet.song.247000.json','["永夜一燈青，相逢話苦心。", "悠悠拾翠夢，嫋嫋採芝吟。", "小雨黄花健，西風荷葉深。", "何須笑摇落，春意在山林。"]'),
('ac67da2e-9464-4d27-b596-fb5eaa1ba381','送友遊淮','黎廷瑞','宋','宋诗','song-poetry','','[]','君行不少住，明日是清明。',48,'全唐诗/poet.song.247000.json','["君行不少住，明日是清明。", "驛路垂楊暗，淮河新水平。", "天晴紆野興，地逈暢離情。", "故友如相問，深山戴笠耕。"]'),
('01be9ccd-e69a-44e3-b856-8e1b24efe6fb','樂平樊主簿捧檄北行來別賦此奉餞','黎廷瑞','宋','宋诗','song-poetry','','[]','拊字心空悴，清寒節太高。',48,'全唐诗/poet.song.247000.json','["拊字心空悴，清寒節太高。", "無人相料理，惟我獨賢勞。", "萬里隨歸雁，孤帆渺暮濤。", "歸期應不遠，新月點梅梢。"]'),
('6e1eac0e-22ac-4713-9416-78ba1c119438','上灘','黎廷瑞','宋','宋诗','song-poetry','','[]','歲月川流駛，風霜行路難。',48,'全唐诗/poet.song.247000.json','["歲月川流駛，風霜行路難。", "忽聞喧怒瀑，始覺上層灘。", "月落雞聲曉，沙空雁夢寒。", "雲林摇落盡，敢卜一枝安。"]'),
('8a6ff3c1-7fe6-4a42-bfc9-e15a82bdf8a1','船尾夜坐','黎廷瑞','宋','宋诗','song-poetry','','[]','船尾夜深深，無人伴苦吟。',48,'全唐诗/poet.song.247000.json','["船尾夜深深，無人伴苦吟。", "萬山黄葉夢，一路早梅心。", "度縴驚村犬，移篙動水禽。", "誰家搗衣急，殘月數砧聲。"]'),
('04a936fe-1107-4bdd-8703-14b551c3f531','新城呈王明父明日立春','黎廷瑞','宋','宋诗','song-poetry','','[]','晚歲寒無力，新晴雪未消。',48,'全唐诗/poet.song.247000.json','["晚歲寒無力，新晴雪未消。", "江聲連去雁，燈影見來潮。", "野闊鄉心遠，風高客夢遥。", "梅邊有新意，明日是春朝。"]'),
('c692471f-d9fe-4808-a225-317f911bafcb','贈畫龍章道人','黎廷瑞','宋','宋诗','song-poetry','','[]','幾載湖中住，歸來筆有神。',48,'全唐诗/poet.song.247000.json','["幾載湖中住，歸來筆有神。", "青天雙劍氣，破壁一梭塵。", "舉世惟看畫，何人更識真。", "千巖冰復雪，雷雨動青春。"]'),
('841cc205-0aa5-4152-ac89-4fe5f5ff2eb2','夜泊城下大風雨友人約明日遊芝山','黎廷瑞','宋','宋诗','song-poetry','','[]','沉沉春夜黑，寒客泊孤舟。',48,'全唐诗/poet.song.247000.json','["沉沉春夜黑，寒客泊孤舟。", "天漏雨平下，風回水倒流。", "干戈吾道在，宇宙此生浮。", "明日還晴雨，芝山要一遊。"]'),
('7e689206-1cf5-4bc1-8b89-c9dca6150a07','宿界首寺施府墓園也次孟使君壁間韻三首','黎廷瑞','宋','宋诗','song-poetry','','[]','沙路抵長夏，入山如早秋。',48,'全唐诗/poet.song.247000.json','["沙路抵長夏，入山如早秋。", "閒房容客卧，老屋欠人修。", "日落蟬多事，雲深鶴自由。", "風塵二十載，復此得清遊。"]'),
('e6f4c92f-8e4e-4258-976c-e95b4eaad4b6','晚泊舒城下','黎廷瑞','宋','宋诗','song-poetry','','[]','卸帆淮南岸，城樓欲鼓天。',48,'全唐诗/poet.song.247000.json','["卸帆淮南岸，城樓欲鼓天。", "遠山雲似雪，近水屋如船。", "樹意紅未了，波光綠可憐。", "乾坤無限事，一笑白鷗前。"]'),
('3fd62e30-5931-42da-a186-1e3a158615e0','淮南聞雁呈何復初同年','黎廷瑞','宋','宋诗','song-poetry','','[]','孤棹翩翩北渡淮，相逢一笑意悠哉。',64,'全唐诗/poet.song.247000.json','["孤棹翩翩北渡淮，相逢一笑意悠哉。", "關河萬里忽秋晚，風雨五更聞雁來。", "好夢驚回頻輾轉，壯心平盡復崔嵬。", "吾生通塞寧須計，但祝乾坤泰運開。"]'),
('682b2552-12e5-447c-8345-7f2b3b1d77aa','金陵歲晚','黎廷瑞','宋','宋诗','song-poetry','','[]','不擬殘年住秣陵，摩挲蠟屐笑平生。',64,'全唐诗/poet.song.247000.json','["不擬殘年住秣陵，摩挲蠟屐笑平生。", "茫茫去雁雲千里，渺渺疏鐘雨一城。", "天地無情催歲月，古今何物是功名。", "梅邊且喜春風近，痛飲挑燈坐到明。"]'),
('bc95a7d2-e435-47a3-96f6-1ddb63bb9cda','思歸','黎廷瑞','宋','宋诗','song-poetry','','[]','目斷飛雲思黯然，獨携樽酒杏花前。',64,'全唐诗/poet.song.247000.json','["目斷飛雲思黯然，獨携樽酒杏花前。", "清明寒食能多雨，白下長干又一年。", "萬里風沙憐雁去，滿村桑柘憶蠶眠。", "家書寫就無歸使，欲問江頭上水船。"]'),
('47972553-4774-4868-b19c-07ac0599012b','巢湖阻風夜起觀天','黎廷瑞','宋','宋诗','song-poetry','','[]','流行坎止信悠然，又泊湖東兩日船。',64,'全唐诗/poet.song.247000.json','["流行坎止信悠然，又泊湖東兩日船。", "客裏風光忙似轂，夢中歸路直如絃。", "西風渺渺方摇夜，北斗離離正掛天。", "寄語龍魚莫相戲，向來此地亦桑田。"]'),
('9d66d747-43d8-4fbb-bf1a-2ba78946c9b5','寄朱野翁兼簡月觀陳同年應子','黎廷瑞','宋','宋诗','song-poetry','','[]','相逢淮楚各凄凉，笑殺三生杜牧狂。',64,'全唐诗/poet.song.247000.json','["相逢淮楚各凄凉，笑殺三生杜牧狂。", "萬樹鶑花春對酒，一燈風雨夜連牀。", "停雲渺渺思何極，大塊茫茫夢正長。", "若見元龍相借問，爲言歸去學耕桑。"]'),
('52e0aade-3b2f-47d1-9d2c-4b2370899e45','里中社','黎廷瑞','宋','宋诗','song-poetry','','[]','蘚石莓牆屋數楹，年年來賽社公靈。',64,'全唐诗/poet.song.247000.json','["蘚石莓牆屋數楹，年年來賽社公靈。", "兒童趁節歡如沸，父老傷春涕欲零。", "海燕邊鴻何日了，夏松殷柏爲誰青。", "村醪如蜜猶堪醉，莫遣東風兩眼醒。"]'),
('c4837637-c128-4288-813d-7b24c2503271','金陵別程萬里教授','黎廷瑞','宋','宋诗','song-poetry','','[]','西風一笑鳳凰城，夢裏相逢各自驚。',64,'全唐诗/poet.song.247000.json','["西風一笑鳳凰城，夢裏相逢各自驚。", "白日共傳蘇軾死，故人寧料范雎生。", "平居慕悅空閭巷，急難周旋如弟兄。", "別去各爲千載計，隋珠彈雀不須輕。"]'),
('f8ed36fc-94e8-48b1-888e-ceca352949aa','蕪湖吉祥寺','黎廷瑞','宋','宋诗','song-poetry','','[]','剎院年來正勃興，此山更不及承平。',64,'全唐诗/poet.song.247000.json','["剎院年來正勃興，此山更不及承平。", "全無估客開囊施，猶有殘燈逐鉢行。", "晉殿唐宮牛一夢，黄書晁篆鼓常鳴。", "摩挲古柳成三歎，歲歲東風綠自榮。"]'),
('d2c8d885-17ff-4f83-bbf3-f5ae383e7869','丞相馬輓章','黎廷瑞','宋','宋诗','song-poetry','','[]','平生甚似洪文惠，暮景惜不如盤洲。',64,'全唐诗/poet.song.247000.json','["平生甚似洪文惠，暮景惜不如盤洲。", "纖兒何人竟悞晉，大夫此日空非周。", "長夜漫漫不復旦，芳草凄凄其奈秋。", "遺書墮淚付千載，往從后軒雲間游。"]'),
('56fb88af-5129-4421-897c-2dfbab3484b0','阻水寄友','黎廷瑞','宋','宋诗','song-poetry','','[]','綿綿風雨暗西窗，悶擁殘編對夜釭。',64,'全唐诗/poet.song.247000.json','["綿綿風雨暗西窗，悶擁殘編對夜釭。", "稚子何知泥污土，良朋共歎陸成江。", "負山鰲重應將壓，戰野龍驕未易降。", "此去城東無百步，明當相就一漁艭。"]'),
('2b9229a3-0e8e-4362-a69d-a4394b4849cb','夜坐風雨忽至','黎廷瑞','宋','宋诗','song-poetry','','[]','山中夜半風雨來，板扉竹戶如人開。',64,'全唐诗/poet.song.247000.json','["山中夜半風雨來，板扉竹戶如人開。", "孤燈淡淡吹欲死，饑烏啞啞啼更哀。", "青陽甫達諸火滿，素志無伸華髪催。", "於呼聞道亦未晚，策驥千里毋徘徊。"]'),
('3b5cc1d7-3a4e-4828-92a6-50bd281e6841','癸巳七月送姚廉訪移司金陵二首','黎廷瑞','宋','宋诗','song-poetry','','[]','十載孤懷鬰不開，二年談麈得重陪。',64,'全唐诗/poet.song.247000.json','["十載孤懷鬰不開，二年談麈得重陪。", "亦知久聚難爲別，縱復相逢有此回。", "野老共遮驄馬路，仙翁合管鳳凰臺。", "慈湖相見如相問，已約鍾山探早梅。"]'),
('83456028-1bed-488d-8549-99c8d1bfa697','院口寫望','黎廷瑞','宋','宋诗','song-poetry','','[]','短艇摇摇對晚屏，推篷念遠不勝情。',64,'全唐诗/poet.song.247000.json','["短艇摇摇對晚屏，推篷念遠不勝情。", "風前落木心猶壯，雨後歸雲氣未平。", "湖汊條條新築塞，圩頭處處薄收成。", "道逢遺老頭如雪，細聽尊前說舊城。"]'),
('a2e167ec-3af0-443f-8e84-6183ed4aa1cc','九日浮梁有約登高者以病不赴','黎廷瑞','宋','宋诗','song-poetry','','[]','老樹荒城噪暮鴉，凄凉節氣滿天涯。',64,'全唐诗/poet.song.247000.json','["老樹荒城噪暮鴉，凄凉節氣滿天涯。", "絕憐多病相疏酒，又是重陽不在家。", "浮世光陰易紅葉，秋籬晚節復黄花。", "閉關寧負登高興，莫遣西風戲孟嘉。"]'),
('0f55095a-511b-42d9-84fe-94e7ce5dbbc3','歸來  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','幸未緇塵染素衣，歸來既避北山移。',64,'全唐诗/poet.song.247000.json','["幸未緇塵染素衣，歸來既避北山移。", "田園有味閒方覺，道路多岐晚始知。", "栗里新銜五柳傳，花蹊舊業四松詩。", "少游款段猶嫌累，到處風塵藤一枝。"]'),
('d959310c-9ccc-4884-ad2c-86fd7d149256','歸來  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','渺渺臯蘭遠路漸，靈龜何必爲余占。',64,'全唐诗/poet.song.247000.json','["渺渺臯蘭遠路漸，靈龜何必爲余占。", "還家早似千年鶴，乖世元無六月蟾。", "元叟爲官猶號漫，陶翁未仕已名潜。", "吳人終未諳羊酪，剛道蓴羹似蜜甜。"]'),
('0a0aa4cb-f2c5-4dff-802e-3bf666c6bffd','庚寅元夕月當蝕雨作不見明日奚相士索詩書此','黎廷瑞','宋','宋诗','song-poetry','','[]','月中八萬四千宮，不管妖蟆啖老瞳。',64,'全唐诗/poet.song.247000.json','["月中八萬四千宮，不管妖蟆啖老瞳。", "白兔藥成無用處，墨龍雲上有奇功。", "且忻玉宇瓊樓在，莫恨銀花火樹空。", "自古庚寅多此事，煩君抬眼相蒼穹。"]'),
('03b092df-e886-4f20-a846-08e36f9256a7','江上夜觀野燒','黎廷瑞','宋','宋诗','song-poetry','','[]','坎離血戰夜茫茫，萬里陰颼更助狂。',64,'全唐诗/poet.song.247000.json','["坎離血戰夜茫茫，萬里陰颼更助狂。", "兔窟那知炷郿塢，蟻封不料火咸陽。", "三更月起雲霞曙，九野冰凝雷電光。", "莽莽黄茅寧暇惜，莫教薰著早梅香。"]'),
('2e8a366e-60f6-49b5-8ca2-f3db5b877e35','題胡氏南園精舍','黎廷瑞','宋','宋诗','song-poetry','','[]','平泉竹石墮荒蕪，金谷池臺莽廢墟。',64,'全唐诗/poet.song.247000.json','["平泉竹石墮荒蕪，金谷池臺莽廢墟。", "今古茫茫竟誰屋，乾坤吶吶有吾廬。", "溪山圍座醉留客，燈火隔林聞讀書。", "此樂輸君先一著，故園吾已賦歸與。"]'),
('8d9e4d3c-b260-4d23-a645-20a84aed9f60','花時留郡歸已初夏即事六首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','黄塵兩鬢欲蒼華，歲歲東風不在家。',64,'全唐诗/poet.song.247000.json','["黄塵兩鬢欲蒼華，歲歲東風不在家。", "不學郭駝歸種樹，却隨劉跛去看花。", "浮名未值蒲萄酒，晚味思參橄欖茶。", "縹緲風烟新綠起，村南村北已桑麻。"]'),
('5a09d99d-d378-457e-9702-a3459942edb1','花時留郡歸已初夏即事六首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','正是花時坐弗邀，出門新綠滿江臯。',64,'全唐诗/poet.song.247000.json','["正是花時坐弗邀，出門新綠滿江臯。", "池塘灧灧鳴姑惡，草樹陰陰度伯勞。", "宿酒轉添胸磊磈，遊絲欲亂鬢蕭騷。", "西疇昨夜春膏滿，免得人間費桔橰。"]'),
('154a2646-f8a6-4851-830a-0d0de2f474a0','花時留郡歸已初夏即事六首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','從來麋鹿合山林，無奈迂疏習已深。',64,'全唐诗/poet.song.247000.json','["從來麋鹿合山林，無奈迂疏習已深。", "食用且空猶種秫，典書未贖更修琴。", "少豪論事唯捫舌，晚靜觀空頗得心。", "莫笑山翁無事業，種花蒔竹自成陰。"]'),
('10de3a94-63a1-45cb-9103-d7fad10509f2','花時留郡歸已初夏即事六首  其四','黎廷瑞','宋','宋诗','song-poetry','','[]','心鏡翛然澹似僧，悠悠觀化寄枯藤。',64,'全唐诗/poet.song.247000.json','["心鏡翛然澹似僧，悠悠觀化寄枯藤。", "雲來雲去閒舒卷，花落花開小廢興。", "吹笛强呼從百里，種瓜清隠學東陵。", "野人知有觀書癖，遠餉松肪續夜燈。"]'),
('6beb9e2b-1c3b-45d3-8240-be7e3a01663f','花時留郡歸已初夏即事六首  其五','黎廷瑞','宋','宋诗','song-poetry','','[]','山中幽興儘無窮，不管蕭蕭四壁空。',64,'全唐诗/poet.song.247000.json','["山中幽興儘無窮，不管蕭蕭四壁空。", "漸覺愚巾便暑戴，偶逢賢酒亦時中。", "映階草色带朝雨，隔屋筍香吹晚風。", "搔首南窗有奇事，綠楊初破石榴紅。"]'),
('3fe29b1f-b86e-4a85-b62a-d32e36e9e42a','花時留郡歸已初夏即事六首  其六','黎廷瑞','宋','宋诗','song-poetry','','[]','多年不訪鳳山春，清賞歸時肯見分。',64,'全唐诗/poet.song.247000.json','["多年不訪鳳山春，清賞歸時肯見分。", "伏虎移來湖上石，瑞龍飛下海南雲。", "眼根磊落祛塵翳，鼻觀清虛發妙聞。", "坐對翛然誰與語，綠陰蝴蝶自成群。"]'),
('831caab9-5b16-431b-bd10-b9d439173dfb','送李性夫赴召時李以端午采藥後行','黎廷瑞','宋','宋诗','song-poetry','','[]','蜃沉海底氣升霏，消得皇皇四牡馳。',64,'全唐诗/poet.song.247000.json','["蜃沉海底氣升霏，消得皇皇四牡馳。", "此去玉堂成故事，未應金馬待多時。", "願儲救世三年艾，更采銷兵萬歲芝。", "特報明時端不負，古今良相即良醫。"]'),
('375ccb2d-8c8b-4a3d-b0d6-1e7b56a2d203','春意郊行','黎廷瑞','宋','宋诗','song-poetry','','[]','卯酒醒來欲午天，意行平陸自悠然。',64,'全唐诗/poet.song.247000.json','["卯酒醒來欲午天，意行平陸自悠然。", "近山欲雨有遠意，老樹得春還少年。", "蝶化不知何宇宙，蝸爭難到好林泉。", "令人長羨崆峒叟，萬壑松風打晝眠。"]'),
('bcd79d73-f600-4b92-99be-cd1a7a6499aa','淮南夜泊','黎廷瑞','宋','宋诗','song-poetry','','[]','低篷矮艇載詩翁，又泊淮南港汊東。',64,'全唐诗/poet.song.247000.json','["低篷矮艇載詩翁，又泊淮南港汊東。", "月黑荒村行獨虎，雲深遠渚拍低鴻。", "詩書落落心如梗，天地悠悠鬢欲蓬。", "輾轉孤衾無限恨，客中此夜與誰同。"]'),
('916af359-bc17-42a7-8fea-889b0eccce95','和張君春晚園','黎廷瑞','宋','宋诗','song-poetry','','[]','知道芳菲只恁休，也應秉燭及春遊。',64,'全唐诗/poet.song.247000.json','["知道芳菲只恁休，也應秉燭及春遊。", "來牛去馬乾坤老，舊燕新鴻歲月流。", "千里空勞芳草夢，一樽聊慰落花愁。", "桃源只在扁舟外，說著仙郎却繆悠。"]'),
('357c470e-0b24-4cf5-b91c-81f85b13ce95','歸來','黎廷瑞','宋','宋诗','song-poetry','','[]','曾奏明光忝末科，青山回首已霜荷。',64,'全唐诗/poet.song.247000.json','["曾奏明光忝末科，青山回首已霜荷。", "偷生甚媿秋胡婦，拊事總成春夢婆。", "早慕功名成事少，晚談空妙得心多。", "斜陽一曲歸牛背，笑殺南山白石歌。"]'),
('91139f75-aa30-4447-9782-7e5d54935b13','過采石懷太白','黎廷瑞','宋','宋诗','song-poetry','','[]','騎馿花縣不相容，却駕長鯨戲遠空。',64,'全唐诗/poet.song.247000.json','["騎馿花縣不相容，却駕長鯨戲遠空。", "采石釣船還夜月，青山破墓幾秋風。", "平生賞識惟狂客，他日功名付令公。", "千載英雄長不死，長庚光徹紫霄中。"]'),
('1909059d-528b-4e84-812b-fc7691539180','送人之淮南','黎廷瑞','宋','宋诗','song-poetry','','[]','淮南稍覺故人稀，幾度拏舟願輒違。',64,'全唐诗/poet.song.247000.json','["淮南稍覺故人稀，幾度拏舟願輒違。", "王粲去鄉應有恨，邴原避地豈無依。", "稻迷絳國鴻初下，酒滿江城蟹正肥。", "想見臨風重回首，芝山日日白雲飛。"]'),
('c20d66c4-063d-4210-ab90-156f0a0cc5a2','次韻答王子賢所寄五首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','釣竿閒却下漁磯，采采香芹不自肥。',64,'全唐诗/poet.song.247000.json','["釣竿閒却下漁磯，采采香芹不自肥。", "舉步毫釐千里錯，回頭四十二年非。", "已將明鏡悲華髪，更遣緇塵染素衣。", "饑食肉糜應是好，倚門日日望兒歸。"]'),
('f77276c4-58c2-4844-a640-a1720291763f','次韻答王子賢所寄五首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','牛奮箕張謗易生，更堪枉矢與攙槍。',64,'全唐诗/poet.song.247000.json','["牛奮箕張謗易生，更堪枉矢與攙槍。", "五窮繾綣奴休送，三至倉皇母亦驚。", "逸少自慚君有誓，李期誰謂爾孤鳴。", "東風吹盡芝山雪，略放梅花一樹明。"]'),
('f9ec6e59-b230-4185-9152-f768d355846e','次韻答王子賢所寄五首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','夜讀新詩重惘然，絕憐塵土過年年。',64,'全唐诗/poet.song.247000.json','["夜讀新詩重惘然，絕憐塵土過年年。", "月供那有千壺俸，日費元無一塊錢。", "龐老何心更城府，陶公素志只園田。", "桃源不在乾坤外，欲問漁郎覓釣船。"]'),
('a3451549-82cf-48e0-9aa4-9cd071254e1d','九月六日發舟齊山下呈祝靜得蔡君瑞','黎廷瑞','宋','宋诗','song-poetry','','[]','齊山山下泊扁舟，尚想三生杜牧游。',64,'全唐诗/poet.song.247000.json','["齊山山下泊扁舟，尚想三生杜牧游。", "南雁喚回千載夢，西風掃碎一江秋。", "黄花落落如相逼，嘉節匆匆也合酬。", "准擬峨眉亭上去，買魚沽酒浣羈愁。"]'),
('93fd9bb0-4421-4da1-bad7-2b2b4aaae4a7','金陵陳月觀同年三首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','已是收枰斂手時，更堪拈起著殘棋。',64,'全唐诗/poet.song.247000.json','["已是收枰斂手時，更堪拈起著殘棋。", "露盤不解相如渴，桃實難充曼倩饑。", "吾末如何真已矣，是知不可復爲之。", "令人長愧商山叟，四海清夷只茹芝。"]'),
('f9c4c386-e297-4833-94c2-cac36c007ea3','金陵陳月觀同年三首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','深衣社裏强婆娑，悞了東臯雨一蓑。',64,'全唐诗/poet.song.247000.json','["深衣社裏强婆娑，悞了東臯雨一蓑。", "麟也可爲宣父泣，鳳兮須信接輿歌。", "懷金暫樂憂方大，投璧能全碎已多。", "此去修行留得力，世間知己是天魔。"]'),
('c0c2b9b8-3d74-4f0a-be77-b888009a1f8e','金陵陳月觀同年三首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','莫道桐花楝實清，比量腐鼠不堪爭。',64,'全唐诗/poet.song.247000.json','["莫道桐花楝實清，比量腐鼠不堪爭。", "鬼應勿復揶揄汝，人亦真難駕馭卿。", "犬子何心求狗監，貛郎到處有魚羹。", "白雲滿地江湖闊，著我逍遥自在行。"]'),
('04114d3c-aa94-4cad-8ff1-d8cc9868c016','九日雨遊薦福寺','黎廷瑞','宋','宋诗','song-poetry','','[]','小瀹孤亭興未闌，共爲長歲坐蒲團。',64,'全唐诗/poet.song.247000.json','["小瀹孤亭興未闌，共爲長歲坐蒲團。", "半林空翠濕晴露，滿院秋香吹晚寒。", "弔古并捫碑字讀，好奇更借藏經看。", "歸舟莫笑清狂絕，得句從來勝得官。"]'),
('22937dac-430b-4826-b8c8-2737ed4685e2','還家二日聞征西軍馬來人家俱避地寒食獨酌有懷諸君','黎廷瑞','宋','宋诗','song-poetry','','[]','閉戶雲山轉盡長，祇消如許送清光。',64,'全唐诗/poet.song.247000.json','["閉戶雲山轉盡長，祇消如許送清光。", "一百六日柳邊綠，五十三年頭已霜。", "頼有孤斟聊勃鬰，惜無共語慰凄凉。", "前時溪上行春處，想見家家避地忙。"]'),
('f89f1903-5894-482f-be4b-a907d7880161','送朱瑞卿','黎廷瑞','宋','宋诗','song-poetry','','[]','長憶揚州笑口開，扁舟何意子能來。',64,'全唐诗/poet.song.247000.json','["長憶揚州笑口開，扁舟何意子能來。", "居然一別又三載，如此相逢能幾回。", "春色漸歸千古樹，雨晴猶有隔年梅。", "歸帆不泊無邠水，少駐東風領一杯。"]'),
('10e873b1-9c98-4bab-ba36-eab8b09897d1','梁必大歸自燕山有詩問訊以詩答之','黎廷瑞','宋','宋诗','song-poetry','','[]','折柳空驚歲月徂，寄梅欲憶雪霜餘。',64,'全唐诗/poet.song.247000.json','["折柳空驚歲月徂，寄梅欲憶雪霜餘。", "君看天上烟花繞，我伴山中木石俱。", "婚媾駸駸難辨老，友朋往往不如初。", "極思一見論心事，城府年來跡漸疏。"]'),
('9b0b80f7-434c-4ab4-8102-2c1c6a1da860','余秋村創書院','黎廷瑞','宋','宋诗','song-poetry','','[]','五鳳樓修謾賦空，不堪四壁老秋風。',64,'全唐诗/poet.song.247000.json','["五鳳樓修謾賦空，不堪四壁老秋風。", "黄金白璧相逢頃，文杏香茅一笑中。", "子美堂資須錄事，堯夫宅契出溫公。", "諸公更使風流盡，千載遥知意氣同。"]'),
('c2b0e554-285e-4eb7-bd75-bd862351f0b7','古離別  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','迢遞君遠遊，纏綿妾孤傷。',84,'全唐诗/poet.song.247000.json','["迢遞君遠遊，纏綿妾孤傷。", "年年望君還，悠悠空斷腸。", "我願陵成江，有車不得襄。", "江復變爲陸，無水通舟航。", "成江路還通，變陸路更長。", "安得微賤軀，乘風墮君傍。", "化爲舟與車，載君還故鄉。"]'),
('c443df1c-9e2f-4a76-b22c-327f992dbacc','古離別  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','團團素明月，隠隠流前除。',72,'全唐诗/poet.song.247000.json','["團團素明月，隠隠流前除。", "卷帷對孤影，涕泗沾羅襦。", "念我玉關人，此心知焉如。", "何方得靈藥，託身爲蟾蜍。", "懸光萬里天，往尋君所居。", "君坐照君席，君行逐君車。"]'),
('147755ed-01a3-4599-8002-9583da286c5c','道傍兒','黎廷瑞','宋','宋诗','song-poetry','','[]','落日古道傍，依依聞哭聲。',156,'全唐诗/poet.song.247000.json','["落日古道傍，依依聞哭聲。", "云是田舍兒，垂髫纔九齡。", "前母久已沒，後母無復情。", "饑寒夙所更，驅役不得停。", "甫課南山樵，又督西疇耕。", "早汲或至晏，夕舂恒達明。", "曾何少懈怠，動輒遭笞刑。", "斑斑膚無完，恍恍神不寧。", "命也可奈何，怨辭安敢形。", "但願後母心，回慈念孤生。", "遲我齒力壯，與母供使令。", "余聞重歎息，爲汝雙涕零。", "憑誰絃履霜，彈與汝母聽。"]'),
('a9f5290c-9714-4990-a256-2495a7fa1461','桐華','黎廷瑞','宋','宋诗','song-poetry','','[]','絕岸有孤桐，日受藤蔓侵。',108,'全唐诗/poet.song.247000.json','["絕岸有孤桐，日受藤蔓侵。", "芳韶歇頳紫，餘暄始相尋。", "粲粲白玉花，照見清溪潯。", "時至聊一吐，豈有東風心。", "乾坤寄孫枝，隠隠孤鳳吟。", "安得太古手，爲斵重華琴。", "奏之巖廊上，和以簫韶音。", "惜哉此妙質，歲晏娛空林。", "渺渺蒼梧雲，興懷一何深。"]'),
('7f67f325-6680-4f7d-aea2-5be7abf785af','夢真三首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','昔夢驂八駿，往赴明宮昭。',72,'全唐诗/poet.song.247000.json','["昔夢驂八駿，往赴明宮昭。", "朝發赤水陽，夕抵崑崙椒。", "恭陪瑶池宴，親聆白雲謠。", "雲來何英英，雲去何飄飄。", "山川悵悠阻，樓臺空閴寥。", "想像雲和笙，青鸞度秋霄。"]'),
('d7279db1-081a-47a4-888a-a81c55d63c21','夢真三首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','昔夢拜綠章，縹緲朝紫微。',72,'全唐诗/poet.song.247000.json','["昔夢拜綠章，縹緲朝紫微。", "鈞天侍清燕，寶書析玄機。", "錫之瑶碧簡，賚之青霞衣。", "微班司玉條，下糾濁世非。", "還家未中道，翠水烟塵飛。", "朝真諒無期，丹忱日依依。"]'),
('4822f43a-4884-4a1f-b82e-0dca8f0f1f69','夢真三首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','昔夢過宛洛，遊戲芙蓉城。',60,'全唐诗/poet.song.247000.json','["昔夢過宛洛，遊戲芙蓉城。", "道逢王子晉，邀我升天行。", "翩翩控鶴駕，依依吹鳳笙。", "銀河未西流，翩然倏遐征。", "碧桃開晚花，緱山空月明。"]'),
('a271ada5-e22c-49d6-a488-25a3adf60317','寶劍化','黎廷瑞','宋','宋诗','song-poetry','','[]','我有二奇物，太阿與龍泉。',96,'全唐诗/poet.song.247000.json','["我有二奇物，太阿與龍泉。", "牀頭雷吼匣，屋角虹貫天。", "刺虎如切瓠，斬蛟猶截絃。", "神光未獲試，所遇乃不然。", "時平會銷兵，一笑甘長捐。", "瀉茲太古水，早被洪爐烟。", "化身作農器，往斸南山田。", "元炁還不死，爲人作豐年。"]'),
('c9de2a78-f67e-40ac-a967-613f14c6a4c0','社日雨','黎廷瑞','宋','宋诗','song-poetry','','[]','今社來無涯，古社喚不回。',60,'全唐诗/poet.song.247000.json','["今社來無涯，古社喚不回。", "社公亦世情，兒劇良可咍。", "新水豈不佳，舊雨令人懷。", "離離芳草生，澹澹桃花開。", "吾聾不須治，聊復盡此杯。"]'),
('eeadde2b-abd1-4828-8da0-d71ee05b978e','醉中放言','黎廷瑞','宋','宋诗','song-poetry','','[]','一器集百蚋，分寸爭營營。',156,'全唐诗/poet.song.247000.json','["一器集百蚋，分寸爭營營。", "醉鄉有太古，長年樂昇平。", "尚不知揖讓，固應無戰爭。", "吾嘗涉其境，信美不可名。", "遺我度世方，南遊釀滄溟。", "蟠桃以供核，釣鯨爲之羹。", "小醉五百年，大醉三千齡。", "俟其變桑田，翩然却歸耕。", "我耕不藝秫，還以供瓶罌。", "哀哉彼衆狂，何不促我行。", "汝行未宜遠，小駐中山程。", "中山有神醪，千日醉不醒。", "三十六番醉，亦足了汝生。"]'),
('43347fa4-e976-4dfa-8761-e4e177f5a988','負暄吟','黎廷瑞','宋','宋诗','song-poetry','','[]','陰風吹蘆花，鋪錦滿汀洲。',108,'全唐诗/poet.song.247000.json','["陰風吹蘆花，鋪錦滿汀洲。", "不充赤子襦，露骭寒蕭颼。", "煌煌扶桑君，懸鏡燭隠幽。", "惻然冰霜晨，被以絳錦裘。", "窮閻一欠伸，僵體回春柔。", "天衣難久戀，向晚復下收。", "南山拾枯樵，寒夜爲衾裯。", "灰冷更正長，展轉何時休。", "東方行且明，小忍君勿憂。"]'),
('04f4c055-75e1-48d9-90f5-13c16d03293b','城中別徐山玉先生歸歸後奉寄','黎廷瑞','宋','宋诗','song-poetry','','[]','北風走平湖，枯荷鳴索索。',132,'全唐诗/poet.song.247000.json','["北風走平湖，枯荷鳴索索。", "握手出城東，歸鳥日欲落。", "人事當語離，抱懷寧不惡。", "孤帆烟雨舟，恨不同李郭。", "吾嘗評此子，宜置在丘壑。", "可憐西極馬，俯首受羈絡。", "何當稅彼駕，與子翔寥廓。", "結廬溪水上，日夕對郭璞。", "清曉林霏開，碧玉峭如削。", "青鞋動高興，安得踐斯約。", "尊酒不復携，巖泉清可酌。"]'),
('10601015-8096-4ee1-9b0f-681028dfcdf5','雜詩三首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','后稷播百穀，粒茲阻饑人。',120,'全唐诗/poet.song.247000.json','["后稷播百穀，粒茲阻饑人。", "新苗化爲舊，舊種還爲新。", "萬代一粒傳，何嘗失其真。", "君看田中秋，穗穗上古春。", "太極生天地，同是有吾身。", "吾身千世前，親見羲與神。", "不失赤子心，是即無懷民。", "云胡逐頹運，澆浮散其貞。", "良苗不自殖，甘與荑稗倫。", "勉哉耕我田，歲晚收陳陳。"]'),
('4f235659-c15c-4212-90fa-296bb00c81eb','雜詩三首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','丘嫂禮金印，故妻赧朱輪。',60,'全唐诗/poet.song.247000.json','["丘嫂禮金印，故妻赧朱輪。", "區區富與貴，祇可夸婦人。", "彼婦一何愚，所羞惟賤貧。", "安知墦間妾，臯此淚沾巾。", "蒼蒼鹿門山，高風清絕塵。"]'),
('daaeb690-d99e-47e2-a77f-361470da59ec','雜詩三首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','西域去中土，荒徑無人開。',60,'全唐诗/poet.song.247000.json','["西域去中土，荒徑無人開。", "誰眩武皇意，極力致龍媒。", "汗血竟何用，空聞悔輪臺。", "茂陵土花碧，石馬秋風哀。", "悠悠數世後，引得金仙來。"]'),
('2b35bca1-05f5-494a-af68-bb7c98db199f','過浩山','黎廷瑞','宋','宋诗','song-poetry','','[]','高樹停歸雲，峭壁下落照。',96,'全唐诗/poet.song.247000.json','["高樹停歸雲，峭壁下落照。", "北風一萬里，絕頂吹野燒。", "行行念高堂，履險心欲掉。", "茅茨者誰家，喧語雜老少。", "開門止我宿，四壁亂蓬藋。", "自言兵火餘，零落僅餘噍。", "世故莽難詰，濁酒寄一笑。", "月黑雲冥冥，屋頭聞虎嘯。"]'),
('95d51a9e-237e-40ad-b488-978fd3372fbc','別何復初教授','黎廷瑞','宋','宋诗','song-poetry','','[]','貂裘日以敝，滄海理歸舟。',72,'全唐诗/poet.song.247000.json','["貂裘日以敝，滄海理歸舟。", "戀友那忍別，思親詎敢留。", "豈無還家樂，而懷索居憂。", "北風吹大江，江水日夜流。", "吾道莽何之，天運良悠悠。", "安得兩黄鵠，與子仍丹丘。"]'),
('053af833-df12-4c2d-8149-1be74c1f3720','陪外舅謹齋洎雅山準軒三吳先生遊西園摘新茶汲泉煮之香味殊勝焙者','黎廷瑞','宋','宋诗','song-poetry','','[]','雲根得奇草，金芽擷芳鮮。',60,'全唐诗/poet.song.247000.json','["雲根得奇草，金芽擷芳鮮。", "石鼎生古瀾，松風語寒烟。", "雖微龍鳳製，而得雨露全。", "玉塵飛素濤，信美非其天。", "臨風勿浪啜，侑以離騷篇。"]'),
('6d96cff9-42bc-4c7c-b3d9-ec638962edf5','庚辰六月陪謹齋準軒雅山游西禪超師院以柳詩道人庭宇靜分韻約有興即賦余得庭字時小寐禪床風雨適至遂賦宇字','黎廷瑞','宋','宋诗','song-poetry','','[]','小憩西禪牀，謝絕半日暑。',108,'全唐诗/poet.song.247000.json','["小憩西禪牀，謝絕半日暑。", "白雲憐倦客，清陰覆停午。", "嫋嫋陂上風，沉沉竹間雨。", "幽幽一室虛，昵昵群葉語。", "冥搜得奇想，熟寐透淳古。", "九衢喧野馬，萬喙爭腐鼠。", "誰能大槐根，擺落半柯土。", "浮生得今辰，幽期况茲宇。", "延緣欲忘歸，落日齋堂鼓。"]'),
('380a085f-f579-4cfd-800e-a66b7d13574c','過太白墓','黎廷瑞','宋','宋诗','song-poetry','','[]','下馬弔太白，壯心重徘徊。',96,'全唐诗/poet.song.247000.json','["下馬弔太白，壯心重徘徊。", "秋風吹破墓，晚氣生孤臺。", "四百六十年，詩魂安在哉。", "神人豈久謫，旋復御炁回。", "元無采石船，而况青山堆。", "攘臂競真僞，世儒良可咍。", "煌煌長庚星，光射天門開。", "携樽立遥夜，勸子鸚鵡杯。"]'),
('c6ad84b6-6814-4549-beb9-ad89b9a5bfd1','壬午再過西禪超師化去一年追感遂賦庭字','黎廷瑞','宋','宋诗','song-poetry','','[]','昔詣超師院，聽雨眠疏櫺。',120,'全唐诗/poet.song.247000.json','["昔詣超師院，聽雨眠疏櫺。", "微吟得深警，小瀹開孤醒。", "四極何浮浮，織烏飛不停。", "重來未三年，杯度已西溟。", "巾屨空掛壁，芳草綠滿庭。", "嘉樹亦剪伐，霜幹無留青。", "人生意何常，孤月行秋冥。", "適來偶流輝，倏去還韜靈。", "旦暮不足計，惜爾猶典刑。", "感慨誰與共，晴簷語風鈴。"]'),
('9cd0a956-8852-4c8a-9f5c-ceb8e5ecdbf3','道過徐山玉吳仲退來會宿別後作寄','黎廷瑞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','扶輿蹋殘照，懷人度青林。',132,'全唐诗/poet.song.247000.json','["扶輿蹋殘照，懷人度青林。", "一笑得二妙，坐看西月沉。", "短燭摇古碧，華樽湛芳斟。", "高歌擊唾壺，琅琅出商音。", "東風行空山，和以蒼松吟。", "飄颻洞庭樂，要渺南薰琴。", "天地空闊遠，歲晚誰知心。", "相對成浩歎，忘言擁單衾。", "東方忽已白，握別西山陰。", "違離未云遠，懷思一何深。", "常恐蕙帳空，此樂難重尋。"]'),
('9442484d-e471-4da1-9b87-c4718e1cb407','種蔬二首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','可憐黄觳𧥆，役役秋畦耕。',48,'全唐诗/poet.song.247000.json','["可憐黄觳𧥆，役役秋畦耕。", "既以謀我飯，又復謀我羹。", "早暮一束芻，所報良亦輕。", "飽食輒自媿，悠悠念吾生。"]'),
('53f85d62-6452-47c1-bc68-daf4b5fbc5c7','種蔬二首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','夫人肉食謀，所喪甚於饑。',48,'全唐诗/poet.song.247000.json','["夫人肉食謀，所喪甚於饑。", "但能咬菜羹，何事不可爲。", "采采首陽蕨，燁燁商山芝。", "此味千載長，雋永當自知。"]'),
('b5ad2c22-e071-43c1-a3e0-89b8e21d0a7e','題李庭秀學隠山房','黎廷瑞','宋','宋诗','song-poetry','','[]','燕坐萬書圍，高吟八窗空。',48,'全唐诗/poet.song.247000.json','["燕坐萬書圍，高吟八窗空。", "是間足佳處，何用丘壑中。", "南山有玄豹，翠霧澤茸茸。", "一朝文章成，平林嘯秋風。"]'),
('bdd41e0a-f356-4524-9d42-7d2568445073','過太常寺簿謝公故第','黎廷瑞','宋','宋诗','song-poetry','','[]','落日廬阜紫，飛砂湖水黄。',204,'全唐诗/poet.song.247000.json','["落日廬阜紫，飛砂湖水黄。", "散倦登古原，含悽眺層岡。", "丹梯遂寥邈，沈思熱中腸。", "當年扣玉墀，抗疏何慨慷。", "拂衣雲壑卧，著書名山藏。", "築園印清流，藝樹條孤芳。", "英彥集文字，燕席開華妝。", "人生既難料，天運亦靡常。", "黯黯玄雲陰，蕭蕭北風凉。", "山流鰲背空，柯改蟻夢荒。", "事往蹟已陳，名存道彌光。", "獨念平生遊，使我重感傷。", "破壁嘶瘦馬，疊鼓發暝航。", "屐痕難重尋，寒苔日蒼蒼。", "高丘渺烟霧，不得酹一觴。", "懷哉我先銘，翠琰垂千霜。", "俯仰落清淚，目斷江流長。"]'),
('2b20a4b6-fc0f-4f06-bb2a-ca77735ae301','憶巢雲居','黎廷瑞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','棄家錦宮城，結屋廬山前。',144,'全唐诗/poet.song.247000.json','["棄家錦宮城，結屋廬山前。", "退鷁空悠悠，冥鴻自翩翩。", "吟章一傾蓋，見賞朱絲絃。", "及此再承晤，交情重纏綿。", "冥賞富雲壑，清聽窮風泉。", "携壺流雪臺，吹笙落星船。", "重陰閟華景，平陸成修川。", "君應有先識，化鶴不待年。", "重來訪舊隠，滿目空悽然。", "琴書竟奚屬，詩畫知誰傳。", "拊懷重感歎，回首還延緣。", "摇摇松梢雲，疑是巢中仙。"]'),
('cfae3422-9719-4d82-9c5d-50477d7c420d','過干越宿熊氏澹園偕東采駕閣西玉國正二同年登羊角峰觀天池訪昌國寺陸羽茶竈拏船過琵琶洲迴延休觀聽琴記遊四首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','倚策試新晴，扶摇上羊角。',60,'全唐诗/poet.song.247000.json','["倚策試新晴，扶摇上羊角。", "山空葉自語，天近雲欲落。", "危亭渺何許，高木黯猶昨。", "悠悠念物化，漫漫悲世濁。", "何當擊天池，與子翔寥廓。"]'),
('6099e4c1-f6cf-4f6d-a6ff-980937f2a791','過干越宿熊氏澹園偕東采駕閣西玉國正二同年登羊角峰觀天池訪昌國寺陸羽茶竈拏船過琵琶洲迴延休觀聽琴記遊四首  其二','黎廷瑞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','當年曲江燕，並醉西湖舟。',96,'全唐诗/poet.song.247000.json','["當年曲江燕，並醉西湖舟。", "芳夢故依然，落花水空流。", "今晨定何朝，聯裾此夷猶。", "暄風不驚波，小泊琵琶洲。", "無人度新音，松聲澹蕭颼。", "却回羽人觀，復爲瑶琴留。", "俯仰信多感，逍遥且忘憂。", "幸無商人船，喚起青衫愁。"]'),
('8a6a2609-39bd-4c54-8a01-ffdd25a7eafd','登聚遠亭','黎廷瑞','宋','宋诗','song-poetry','','[]','枯筇倚落日，危闌眺西風。',120,'全唐诗/poet.song.247000.json','["枯筇倚落日，危闌眺西風。", "溪水清練練，雲山碧叢叢。", "仰視天宇闊，俯瞰塵世空。", "謫仙有妙音，飛入蓬萊宮。", "鈞天動清聽，雲章照晴虹。", "故殿已秋草，茲地猶青松。", "雙龍護璽文，塵暗珠絲蒙。", "徘徊愜幽賞，感慨懷深忡。", "萬夢天地老，一笑今古同。", "自携白團扇，悠悠遺飛鴻。"]'),
('419ee667-035f-4b49-8362-949379e2c96f','同齊節初遊吳園登四時佳興樓有懷張史君','黎廷瑞','宋','宋诗','song-poetry','','[]','澹澹池中華，離離池上樹。',120,'全唐诗/poet.song.247000.json','["澹澹池中華，離離池上樹。", "緬懷龍山翁，婆娑此成趣。", "相招桃源舟，蹇予莫能赴。", "翁今爲飛仙，乘雲還帝所。", "歸燕隨秋風，翠樓渺烟霧。", "會面良獨難，知心那復遇。", "空餘千歲懷，冷落香珀句。", "平原若爲繡，鍾子安可鑄。", "蕭蕭衆芳盡，冉冉流年度。", "浮生欲如何，三歎出門去。"]'),
('e12e90ad-8def-4261-bf5b-642d54414f11','重陽雨與湯叔巽諸公齋亭小集','黎廷瑞','宋','宋诗','song-poetry','','[]','初余撫奇節，賞事彌穿巒。',168,'全唐诗/poet.song.247000.json','["初余撫奇節，賞事彌穿巒。", "幽躋幾屐換，豪飲百榼乾。", "詎知中年至，况復行路難。", "林谷深且窈，巖岫繞復攢。", "叢疑熊豹伏，穴惴龍蛇蟠。", "晝雨已冥冥，夕雲亦漫漫。", "升高躬易危，居卑心所安。", "蕭齋豈不陋，英集聊相歡。", "東籬獻初華，西風被峨冠。", "泛泛茱萸觴，落落苜蓿盤。", "接此造極談，勝彼登峰觀。", "終然有深懷，悠哉發長歎。", "泰華采香雪，小山訪遺丹。", "憑誰吹玉簫，雲外呼青鸞。"]'),
('52c39e4d-5ab6-4ca1-9c54-26f250994ca8','夜泊彭蠡風大作','黎廷瑞','宋','宋诗','song-poetry','','[]','卸帆月欲墮，泊岸風轉急。',108,'全唐诗/poet.song.247000.json','["卸帆月欲墮，泊岸風轉急。", "驚砂傳鐵箭，飛霰散瓊粒。", "重湖太古水，帝遣龍下吸。", "潜鱗失故穴，蒼黄望舟入。", "寧知政坐窘，衾裘盡沾濕。", "慌慌中夜起，莽莽百憂集。", "披衣視雲漢，慘澹天一笠。", "頗疑廬阜倒，三歎救何及。", "平明笑擁篷，五老猶壁立。"]'),
('f378ea3d-7f28-4728-b6ff-6d1760c6f829','湖上被水有感二首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','汲汲湖上叟，種瓜湖上園。',72,'全唐诗/poet.song.247000.json','["汲汲湖上叟，種瓜湖上園。", "晨夕自抱甕，長此蒼玉丸。", "所希烈日中，消彼行人袢。", "垂垂一月雨，平陸白浪翻。", "屋廬且已沒，根蒂那復存。", "初心竟何如，天意吾奚言。"]'),
('0977eb26-8b05-4923-a395-9d656b7bd56c','湖上被水有感二首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','天公亦兒劇，日縱驕龍嬉。',84,'全唐诗/poet.song.247000.json','["天公亦兒劇，日縱驕龍嬉。", "弄翻鬣上瓢，一壑共渺迷。", "交交蛙出竈，洋洋榻浮龜。", "居者既憂墊，行者復蹈危。", "覆舟誰氏婦，滅頂誰人兒。", "一戲遂如許，高高那得知。", "龍驕未易制，天劇不可爲。"]'),
('c4a97346-7a02-4d7c-a373-3fc7179efcbd','送司命君','黎廷瑞','宋','宋诗','song-poetry','','[]','玄鶴導飈駕，黑螭載雲旂。',156,'全唐诗/poet.song.247000.json','["玄鶴導飈駕，黑螭載雲旂。", "云是司命君，歲暮當賦歸。", "欲將人間事，媺慝奏玉扉。", "昊皇倘垂聽，瑣瑣安足譏。", "一冬天氣燠，占者疑匪機。", "野蔓既頑綠，山桃還僣緋。", "稍稍癡蚋集，紛紛凍蠅飛。", "願言剪銀河，雪花玉成圍。", "驅厲濯春瘴，竄蝗銷歲饑。", "青君且戒嚴，亹亹欲近畿。", "斯人有至望，此事宜速祈。", "君言或見用，帝力亦巍巍。", "一觴贈君行，願君聽勿違。"]'),
('c342e435-f76b-499d-af8b-d0d55165f9b2','東軒白芍藥盛開','黎廷瑞','宋','宋诗','song-poetry','','[]','宿雨卷餘芳，庭戶綠陰靜。',120,'全唐诗/poet.song.247000.json','["宿雨卷餘芳，庭戶綠陰靜。", "玉仙從何來，服佩淡如瑩。", "迎飈薰自遠，承露色彌正。", "尚嫌脂粉涴，肯與頳紫競。", "姚黄花中尊，擇配此其稱。", "寰塵暗京洛，偃蹇誰敢娉。", "當年廣陵譜，艷賞非不盛。", "翛然林下風，政以道韻勝。", "過期知益希，含章隠希病。", "斜日下游蜂，一笑闌獨凭。"]'),
('fb2ae7d1-e33f-491e-ba65-5755bb709205','夜大風明日視新竹無恙','黎廷瑞','宋','宋诗','song-poetry','','[]','牆陰老龍孫，氣欲干雲霄。',84,'全唐诗/poet.song.247000.json','["牆陰老龍孫，氣欲干雲霄。", "共愛秉勁節，終虞忌高標。", "東風撼南極，萬壑翻江潮。", "挑燈不成寐，念爾心摇摇。", "天明報平安，阿龍故自超。", "山翁喜欲狂，呼童傾巨瓢。", "舉酒壽此君，不飲吾當澆。"]'),
('973e6803-af08-44ac-8d1c-59424428e49f','雜感六首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','凄凄寒露下，亹亹孤蛩吟。',36,'全唐诗/poet.song.247000.json','["凄凄寒露下，亹亹孤蛩吟。", "幽人起徬徨，歎息淚盈襟。", "物情正得時，我悲獨何心。"]'),
('f1c0025c-99a4-49a9-9246-eea85cb760df','雜感六首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','翾翾田中雀，貿貿墉下鼠。',36,'全唐诗/poet.song.247000.json','["翾翾田中雀，貿貿墉下鼠。", "朝來啄我粟，暮來食我黍。", "羸牛卧牆陰，枯草閙風雨。"]'),
('70a81639-e54c-4c25-9503-f9f8e1a9338c','雜感六首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','讀書不救饑，山園聊荷鋤。',36,'全唐诗/poet.song.247000.json','["讀書不救饑，山園聊荷鋤。", "蔓既荒我粒，草復亂我蔬。", "大笑非吾事，忍饑還讀書。"]'),
('e881b419-eb38-402d-b0ac-48c2bcbfd5dc','雜感六首  其四','黎廷瑞','宋','宋诗','song-poetry','','[]','元陽秋轉碧，積凍春更好。',36,'全唐诗/poet.song.247000.json','["元陽秋轉碧，積凍春更好。", "草力乃如斯，人生得草草。", "寒暑浩茫茫，哀哉未聞道。"]'),
('ee52ced7-0a36-4722-9f58-16a7866e9669','雜感六首  其五','黎廷瑞','宋','宋诗','song-poetry','','[]','孫子傳世世，木石窮年年。',36,'全唐诗/poet.song.247000.json','["孫子傳世世，木石窮年年。", "太行亦可移，滄海終欲填。", "入聖諒非難，懼君心不堅。"]'),
('f43d484f-c5ee-4cc1-b6f0-4c6d864ac90a','雜感六首  其六','黎廷瑞','宋','宋诗','song-poetry','','[]','一根起千枝，一枝吐千花。',36,'全唐诗/poet.song.247000.json','["一根起千枝，一枝吐千花。", "花復結爲實，種種春無涯。", "開門掃秋風，閉關養靈芽。"]'),
('2b32f763-9fad-4916-a0b3-c6bd2f76b993','樹垣','黎廷瑞','宋','宋诗','song-poetry','','[]','開門俯清池，樹垣因古坡。',60,'全唐诗/poet.song.247000.json','["開門俯清池，樹垣因古坡。", "經營既鹵莽，葺補還蹉跎。", "前冬雪如山，去春雨如河。", "幾微不自慎，迨茲功力多。", "倚杖寄三歎，反躬當如何。"]'),
('dc05d3f2-1ff2-4a42-b7e4-953c3d1497ff','去草','黎廷瑞','宋','宋诗','song-poetry','','[]','佳花日封溉，惡草時剪薅。',84,'全唐诗/poet.song.247000.json','["佳花日封溉，惡草時剪薅。", "花事猶未緒，草意復已高。", "三歎謂老圃，不得償秋毫。", "榮悴豈其天，置之聽所遭。", "老圃顧我歎，吾豈仇莠蒿。", "茲圃吾所職，不爾毋乃叨。", "君言固近厚，吾躬敢辭勞。"]'),
('6094ce22-a63d-48d4-8f70-af6a5fd0b80a','伐木','黎廷瑞','宋','宋诗','song-poetry','','[]','牆角有惡木，據我千畝園。',72,'全唐诗/poet.song.247000.json','["牆角有惡木，據我千畝園。", "蔽虧日月光，壅遏雨露恩。", "其下草不殖，况乃蘭與蓀。", "蒼藤交龍蛇，護擁何雄尊。", "厨人告薪絕，命斧急剪髠。", "終然非遠圖，會當拔其根。"]'),
('8a44f39d-ac3b-4312-875e-347e0a9c4611','除棘','黎廷瑞','宋','宋诗','song-poetry','','[]','萬甲綠未動，棘叢已蓁蓁。',108,'全唐诗/poet.song.247000.json','["萬甲綠未動，棘叢已蓁蓁。", "所害雖尚微，剪薙當及辰。", "舍鋤忽三歎，念爾亦一春。", "是中留復難，惻然爲之顰。", "築垣俯清池，池上插柳青。", "誰能限芻牧，徙之池水濱。", "柳吾所甚愛，護柳吾不嗔。", "美醜無棄材，位置固在人。", "豈特遂物理，亦以成天仁。"]'),
('58f32ae2-6c2e-4e72-a71f-06fee027b121','遷椒','黎廷瑞','宋','宋诗','song-poetry','','[]','椒性惡卑濕，種之必陽坡。',36,'全唐诗/poet.song.247000.json','["椒性惡卑濕，種之必陽坡。", "托根苟失所，美質其奈可。", "及早遷高原，薰風丹實多。"]'),
('793273d3-89b2-4e5f-a9a7-6f5c512081c7','春社同梁必大湯景文徐山玉吳昭德吳仲退李思宣周南翁飲芝山五峰亭二羽士來會以范文正公雲飛過江去花落大城東分韻得雲字','黎廷瑞','宋','宋诗','song-poetry','','[]','戊雨敷雉甲，午晴沉幽薰。',120,'全唐诗/poet.song.247000.json','["戊雨敷雉甲，午晴沉幽薰。", "時邁足永慨，景舒聊暫忻。", "聯屐得英彥，携壺出塵氛。", "亦有丹丘客，共眺青山雲。", "芝空石磊磊，華落川沄沄。", "代遠弔殘柏，甿勞念遺枌。", "吾生竟何如，茲飲又及曛。", "萍流豈易合，星聚還當分。", "深憂愴范老，長謠唁廬君。", "邂逅有千載，寧無感斯文。"]'),
('be97f1ee-36b5-4281-8a84-3fe89d34307c','晚晴','黎廷瑞','宋','宋诗','song-poetry','','[]','欹枕聽殘雨，開門看東風。',120,'全唐诗/poet.song.247000.json','["欹枕聽殘雨，開門看東風。", "春光無尋處，天地綠氣中。", "初旭散平野，快酒瀉怒洪。", "關關枝上禽，舒舒葦間蟲。", "東郊歡且謠，秉耒開歲功。", "緬思陶唐化，坐致黎民雍。", "斯時諒奚如，殆與新春同。", "愚生後千載，不並稷契逢。", "唯應杯中物，上與邃古通。", "取酒且竟醉，山花舒早紅。"]'),
('01b4cdb7-b32f-45ed-b0c3-e1177db216b0','集陶句題吳雅翁心遠堂','黎廷瑞','宋','宋诗','song-poetry','','[]','居止次城邑，性本愛丘山。',72,'全唐诗/poet.song.247000.json','["居止次城邑，性本愛丘山。", "曲肱豈易沖，靈府長獨閒。", "秋菊有佳色，綠酒開芳顔。", "羲農去我久，千里乃相關。", "遥遥望白雲，高操非所攀。", "願言躡輕風，八表須臾還。"]'),
('2e764bae-64fe-400e-b6b5-031209b7e01d','張子房','黎廷瑞','宋','宋诗','song-poetry','','[]','早見滄海君，晚師黄石公。',120,'全唐诗/poet.song.247000.json','["早見滄海君，晚師黄石公。", "力士不得力，驅使芒碭龍。", "仁義以爲椎，氣蓋百代雄。", "一擊函谷碎，再擊烏江空。", "從容一籌畢，全漢酬其功。", "何乃不自知，而以留見封。", "酇侯辱械繫，淮陰歎藏弓。", "彼皆爲人役，詎敢望此翁。", "辟穀豈其然，視世與穀同。", "可憐商山老，亦墮子術中。"]'),
('7ff423ab-4080-434a-9cf3-24b57e29eba4','夜讀馬援傳感少游語','黎廷瑞','宋','宋诗','song-poetry','','[]','生人有恒道，衣食固其須。',132,'全唐诗/poet.song.247000.json','["生人有恒道，衣食固其須。", "裁足諒已難，况復求贏餘。", "所以古聖賢，守道甘窮居。", "緼袍敝弗厭，簞瓢饑自娛。", "徐行豈不安，焉用馬與車。", "掾史亦良勞，抑首畏簡書。", "放曠山澤間，孰與從樵漁。", "無求恒泰然，有繫還多虞。", "但當力爲善，汲汲希舜徒。", "于然守故丘，庶不忝厥初。", "寄語馬少游，斯言定何如。"]'),
('8bf9736a-2d40-4a67-9fea-fce88f0f25ff','杜門','黎廷瑞','宋','宋诗','song-poetry','','[]','有客扣我門，丁丁如啄木。',156,'全唐诗/poet.song.247000.json','["有客扣我門，丁丁如啄木。", "久立門不開，客去嗔此屋。", "僮奴亦怪我，無事許畏縮。", "向來豪俠場，門外車接轂。", "將無晚乏具，效彼龜藏伏。", "山田歲將收，亦可飯脫粟。", "不厭客來頻，所厭客論俗。", "豪辨既多違，强應還自恧。", "但恨平生友，歡聚不得足。", "存者隔川途，沒者卧丘谷。", "精微向誰剖，鬰結滿心曲。", "何如掩關生，黽勉抱吾獨。", "揮絃送征鴻，悠悠楚天綠。"]'),
('2b83289d-5ea4-4a8e-a33a-f4de2fd365aa','讀書','黎廷瑞','宋','宋诗','song-poetry','','[]','卧疴雲林下，寂寂誰與居。',144,'全唐诗/poet.song.247000.json','["卧疴雲林下，寂寂誰與居。", "高風下木葉，泠泠晚窗虛。", "忽思往代事，聊披案上書。", "始得暫欣然，稍久歎以吁。", "衝冠或憤激，反袂還欷歔。", "拊卷忽自歎，毋乃狂且迂。", "此何豫爾事，况復千載餘。", "來今正綿綿，爾心復何如。", "有懷不自展，乃挾冰炭俱。", "因此得沖靜，萬念悉掃除。", "巖花吹幽香，清酒堪滿壺。", "且復舉一觴，冥然聊自娛。"]'),
('eb491b6d-ca1e-4ee6-8c8e-cc51ebc8e226','題汪氏插梅圖卷後','黎廷瑞','宋','宋诗','song-poetry','','[]','插梅元無梅，春風從何來。',96,'全唐诗/poet.song.247000.json','["插梅元無梅，春風從何來。", "菀菀高樹起，燦燦繁花開。", "向來孤山老，鋤雲親自栽。", "寧知歲年晚，更受雪霜摧。", "用意不食實，無心或成材。", "天工未易窺，人力胡爲哉。", "掩卷既三歎，今古寧獨梅。", "終恐事偶然，願君更深培。"]'),
('54322728-fe28-4b46-abcb-dd5879f42c64','孟使君餞行即席以幾時杯重把分韻得幾字','黎廷瑞','宋','宋诗','song-poetry','','[]','平湖澹微雲，小雨凉衆卉。',48,'全唐诗/poet.song.247000.json','["平湖澹微雲，小雨凉衆卉。", "歸懷重依依，把臂還亹亹。", "昔別念彌深，茲聚知復幾。", "離觴不忍銜，清風在船尾。"]'),
('5581aafb-b7bd-46cf-9514-d244c24152ff','飯石壁下逢僧附船還叫巖寺明石山如平臺曰赭亭山也僧至巖下飲要余同遊舟已去矣','黎廷瑞','宋','宋诗','song-poetry','','[]','晝飲石壁下，蒼蒼雲樹寒。',72,'全唐诗/poet.song.247000.json','["晝飲石壁下，蒼蒼雲樹寒。", "忽逢一僧來，欲趁扁舟還。", "云住叫巖寺，共看赭亭山。", "揮袂忽而起，絕磴躋復攀。", "揖我少輟棹，步凉同扣關。", "日落南風起，不知流下灘。"]'),
('636a8849-436b-445c-95c0-9cc3b567b683','甲午九月留浮梁與鄭瑞卿吳可翁方玉父方可大晚出郭飲溪上古樹下以黄葉覆溪分咏得黄字','黎廷瑞','宋','宋诗','song-poetry','','[]','歲晏天蕭蕭，日落山蒼蒼。',84,'全唐诗/poet.song.247000.json','["歲晏天蕭蕭，日落山蒼蒼。", "尋幽度小澗，眺遠躋層岡。", "班坐古道上，落葉滿地黄。", "行人去自急，歸鳥棲亦忙。", "偶茲一餉間，嘅彼千劫長。", "知愚各有殉，博策俱忘羊。", "人生今幾晨，聊復盡此觴。"]'),
('0ba2bb7f-399f-4107-b8b0-e2e32d04602f','田間','黎廷瑞','宋','宋诗','song-poetry','','[]','牛羊散空烟，鳬鴨滿平坂。',84,'全唐诗/poet.song.247000.json','["牛羊散空烟，鳬鴨滿平坂。", "扶藜度西麓，脫屨涉南澗。", "行觀頳肩穫，坐媿綠陰飯。", "田毛信靡贏，井稅亦可辦。", "隔籬新釀熟，要客一笑粲。", "寂寂寧少悰，炎炎故多患。", "但願長如茲，聊爾娛歲晏。"]'),
('b1c7888a-c220-4903-89ec-b0a7f4ebf738','村居晚思','黎廷瑞','宋','宋诗','song-poetry','','[]','清風起層陰，凉雨放疏點。',48,'全唐诗/poet.song.247000.json','["清風起層陰，凉雨放疏點。", "衆木鬰蒼然，芳草綠苒苒。", "山深無來轍，寂寞荆扉掩。", "念遠悵悠悠，殘陽在西崦。"]'),
('7e19cecc-a19c-4d5a-b1b5-0505e2fe4be7','同吳仲退周南翁登法雲寺志上人流玉閣','黎廷瑞','宋','宋诗','song-poetry','','[]','偶與幽人期，頗愜滄洲趣。',72,'全唐诗/poet.song.247000.json','["偶與幽人期，頗愜滄洲趣。", "嵐影倒虛碧，天光澹晴素。", "烟橫雙鷺起，水落孤帆度。", "凭闌足清眺，隠几得玄悟。", "顧茲半日閒，媿彼經年住。", "更遲雪中來，臨風看琪樹。"]'),
('7c5a350d-4957-46c1-a7a7-75ee7ac1f7dc','次韻吳雅翁秋懷四首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','蟋蟀鳴空階，亹亹昏達曙。',84,'全唐诗/poet.song.247000.json','["蟋蟀鳴空階，亹亹昏達曙。", "感此不成眠，推枕覓長句。", "物情欣得時，我乃獨不遇。", "悠悠經世心，歲晚付農圃。", "長歌豳七月，掩卷淚如雨。", "微蟲亦見錄，老我吟謾苦。", "周公不可夢，哀哉弗如汝。"]'),
('a8af2947-203d-49d5-a126-43d1824a02e6','次韻吳雅翁秋懷四首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','憶昔登王畿，花柳春爛爛。',84,'全唐诗/poet.song.247000.json','["憶昔登王畿，花柳春爛爛。", "芳年親與朋，美酒夜復旦。", "參差隔世路，荏苒歲華晏。", "荒地芳草平，廢殿濕螢暗。", "念當弔陳迹，誓以鑄門限。", "仙人詠城郭，釋子說夢幻。", "宇宙幾秋風，悠悠復何歎。"]'),
('a0718118-3192-46a0-b05e-5583ecacb19e','次韻吳雅翁秋懷四首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','蒼忙遺二老，俯仰近十秋。',108,'全唐诗/poet.song.247000.json','["蒼忙遺二老，俯仰近十秋。", "松柏摧高岡，鳳麟隠滄洲。", "吾道遽如許，斯人安可求。", "當年西門路，感涕吟山丘。", "矧我於韓門，忝與李漢儔。", "遺文念當序，舉筆心先愁。", "歲寒頼有公，名節姱以修。", "願言愛體素，一柱迴狂流。", "天倫豈不傷，天運良悠悠。"]'),
('ac470505-65d0-497e-a56f-716a9f54b880','次韻吳雅翁秋懷四首  其四','黎廷瑞','宋','宋诗','song-poetry','','[]','西風吹梧桐，一葉墮寒玉。',96,'全唐诗/poet.song.247000.json','["西風吹梧桐，一葉墮寒玉。", "飄飄轉千崖，亹亹侵萬木。", "霜露行復降，雪霰飛相逐。", "幽居感時運，清夜理商曲。", "堅冰信當辨，昊天有反復。", "但使本根在，陽回奚待祝。", "詞人樂光景，纖艷不足錄。", "焚香對秋山，自取周易讀。"]'),
('817db76c-7421-4f4c-bb71-139127962f03','此張希良書齋去祖壠不百步扁曰望松取后山思亭記中語也','黎廷瑞','宋','宋诗','song-poetry','','[]','老根憐蒼龍，芳粒長新穉。',60,'全唐诗/poet.song.247000.json','["老根憐蒼龍，芳粒長新穉。", "睠言丘中人，苓珀共千歲。", "晨瞻露華明，夕眺烟影翠。", "捫軀發深感，矯首落孤淚。", "思亭有名言，世守宜勿替。"]'),
('88dd8a8c-aaad-4d70-889f-9b166c86529d','溪上桑葉螢食已既今年蠶事頗落寞','黎廷瑞','宋','宋诗','song-poetry','','[]','沿溪十畝桑，綠葉敷且腴。',132,'全唐诗/poet.song.247000.json','["沿溪十畝桑，綠葉敷且腴。", "朝採不盈筐，暮視唯空株。", "乃知飛螢來，竊食無復餘。", "汝饑既云饜，蠶饑當何如。", "豈挾照書勞，我困正在書。", "喫衣諺所笑，思炙計復虛。", "僮奴日捕拾，囊獻如囚拘。", "塵編眊難臯，乾死氣亦紓。", "政爾可得盡，一笑清霜初。", "清霜幾時來，我亦寒無襦。", "及時且封溉，勗哉爲後圖。"]'),
('1542aea1-9f3c-473b-8a2e-9a8372572198','庚寅秋病得語不復詮次名曰感懷  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','炎夏忽已變，西風飄然秋。',60,'全唐诗/poet.song.247000.json','["炎夏忽已變，西風飄然秋。", "親友日已遠，坐感歲月遒。", "登高明不見，涕泗滂沱流。", "天高雁未來，落日空悠悠。", "願爲西北雲，萬里從之遊。"]'),
('a3751e6d-63e5-4ff2-8801-da32a3106c76','庚寅秋病得語不復詮次名曰感懷  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','祖龍制八極，法令如亂麻。',72,'全唐诗/poet.song.247000.json','["祖龍制八極，法令如亂麻。", "儒冠委秋山，王燄明朝霞。", "所以武陵人，入山種桃花。", "如何東陵侯，苟此旦暮華。", "堂堂炎漢叟，却種青門瓜。", "舒卷迷大運，千古爲悲嗟。"]'),
('d8e2c75c-7d93-4515-a0cb-adeca44b9a46','連雨鬰蒸夜不能寐','黎廷瑞','宋','宋诗','song-poetry','','[]','閉門十日雨，簷溜如泉聲。',132,'全唐诗/poet.song.247000.json','["閉門十日雨，簷溜如泉聲。", "沈陰晦蘭燼，潤氣蒸桃笙。", "饞蚤既跋扈，饕蚊復縱橫。", "展轉强就寐，草塘蛙亂鳴。", "亦知夜漏促，安得曙色明。", "晨鐘度深竹，雲岫開新晴。", "隠几補前夢，暫喜身境清。", "聒耳蟬嘒嘒，沿睫蠅營營。", "所響輒如此，吾生安得寧。", "感歎還失笑，此物方施行。", "天運如循環，轉眼秋風生。"]'),
('04daf4d3-d3c9-4676-9785-59b23d7bf3eb','山中視穫','黎廷瑞','宋','宋诗','song-poetry','','[]','歸馬起暝壑，微燈耿深竹。',96,'全唐诗/poet.song.247000.json','["歸馬起暝壑，微燈耿深竹。", "農翁具雞黍，要我林下宿。", "共談隴畝事，未語眉已蹙。", "邑胥邇來稀，每漲卷平陸。", "山中復小旱，一雨僅半熟。", "舉酒屬乃翁，微笑以勝哭。", "湖鄉爾何知，瀰漫正吞屋。", "且共盡此觴，人苦不知足。"]'),
('a11d45f2-7637-4b2e-ab9d-c074bc861fdc','忠烈侯酷好山水作葬書以行於世元翁其族子傳其書侍父仕贛上盡得楊氏術凡談陰陽家者見之輒屈膝余聞其論灑灑然起忘倦矣夫既謂之地理理非儒不精元翁儒者精於理固宜爲賦','黎廷瑞','宋','宋诗','song-poetry','','[]','英英太極翁，器明吳楚甲。',240,'全唐诗/poet.song.247000.json','["英英太極翁，器明吳楚甲。", "馳輅使沙漠，杖鉞帥巴峽。", "南瞻嶺表縮，東睨溟漲狹。", "林居念環轍，簡脫卑藏筴。", "夫君玉樹彥，同祖寶劍匣。", "六籍既淹通，異聞更博洽。", "姬公卜宅洛，成后鼎定郟。", "理也匪荒唐，古甿遺檢柙。", "支分景純書，嫡出楊氏法。", "蒼蒼鬰孤臺，仙枝竹林插。", "芳春適游衍，千金日娛狎。", "厚坤行萬龍，立特飛次夾。", "幽幽何綿綿，意脈能擢掐。", "神文遂爾授，玄鎬了然胠。", "俗師守橐囊，群喙閙鳬鴨。", "青霄孤鶴唳，未吐氣先壓。", "蹇予少狂走，黄塵滿烏帢。", "山川子長筆，天地伯倫鍤。", "某丘可以老，白石盟願歃。", "祝君昌茲術，四海救貧乏。"]'),
('66b4f5e3-c68d-4331-8c56-2ee0a25b882c','山中夜起月色皎然','黎廷瑞','宋','宋诗','song-poetry','','[]','倦寐不知夜，開門風露深。',84,'全唐诗/poet.song.247000.json','["倦寐不知夜，開門風露深。", "明河掛屋角，月出東山岑。", "雙犢卧嚙草，滿地梧桐陰。", "蔌蔌墮落葉，翻翻動棲禽。", "浮生諒餘幾，兩鬢黄塵侵。", "偶此值清賞，泠然得初心。", "幽隠良足尚，吾盟在雲林。"]'),
('9ccd550c-bda9-481e-b7c6-6dc571097daa','晚晴欲適西村不果','黎廷瑞','宋','宋诗','song-poetry','','[]','雨歇無餘春，草木忽而長。',60,'全唐诗/poet.song.247000.json','["雨歇無餘春，草木忽而長。", "東風吹曠野，千里綠莽莽。", "夕陽澹微明，命策赴幽賞。", "徘徊石上坐，鬰鬰念疇曩。", "子規叫重雲，意散不復往。"]'),
('e05f2081-f889-479f-bfd4-9197b427dbfd','學圃','黎廷瑞','宋','宋诗','song-poetry','','[]','西園藝我麻，南園樹我桑。',96,'全唐诗/poet.song.247000.json','["西園藝我麻，南園樹我桑。", "東風吹時雨，青青久成行。", "春服朝猶賒，大布冬可裳。", "十年湖海役，塵暗貂裘黄。", "曾無一事成，祇取三逕荒。", "何如老農圃，卒歲心不忙。", "鄰翁取余喜，笑語傾壺漿。", "擇術子已卜，守之慎勿忘。"]'),
('24093f13-032a-4b9d-84fb-4cbfb6c3b33b','三月二十九日還家花事已過獨碧桃盛開','黎廷瑞','宋','宋诗','song-poetry','','[]','出門紅未芳，還家綠成幄。',48,'全唐诗/poet.song.247000.json','["出門紅未芳，還家綠成幄。", "仙葩獨婉娩，書聲共寥落。", "日暮碧雲合，天寒翠袖薄。", "念遠悵悠悠，緱山緲孤鶴。"]'),
('37f0e507-7555-4445-9187-130e02014bd7','九日和陶','黎廷瑞','宋','宋诗','song-poetry','','[]','開門見秋山，忻然如故交。',96,'全唐诗/poet.song.247000.json','["開門見秋山，忻然如故交。", "烟雲淡相媚，卉木青未彫。", "茲遊忽自念，誰與爲登高。", "目涉已千仞，神遊還九霄。", "世短奚足歎，意多亦徒勞。", "奈何怨遲暮，况復懷覆蕉。", "至樂豈必酒，天真自陶陶。", "長吟對寒花，萬期猶一朝。"]'),
('4c12d541-2ec7-4ad5-b115-0ae832eb76f9','春雪','黎廷瑞','宋','宋诗','song-poetry','','[]','青神怯春寒，頳紫染未辦。',84,'全唐诗/poet.song.247000.json','["青神怯春寒，頳紫染未辦。", "臨河來素女，剪冰作花瓣。", "銀屏移佛地，玉樓墜仙漢。", "朽株繳瓊瑶，斷甓化圭瓚。", "東風翻覆手，轉眼忽吹散。", "乃知太空中，何物當把玩。", "開門見青山，且喜還舊觀。"]'),
('2c8171eb-70e1-4d03-be76-d9f1207bf662','我有綠綺琴','黎廷瑞','宋','宋诗','song-poetry','','[]','我有綠綺琴，寶匣生蛛絲。',84,'全唐诗/poet.song.247000.json','["我有綠綺琴，寶匣生蛛絲。", "拂拭聊一鼓，意淡音愈微。", "隠几忽自笑，持茲將付誰。", "所以絕絃者，痛惜無鍾期。", "吾人天與遊，豈在知音知。", "惆悵簫韶遠，不見鳳來儀。", "后夔不並世，已矣奚所悲。"]'),
('fe47f9af-7b63-4d5b-8958-86ce166715e2','贈初心相士','黎廷瑞','宋','宋诗','song-poetry','','[]','王識九江黥，侯許平陽奴。',144,'全唐诗/poet.song.247000.json','["王識九江黥，侯許平陽奴。", "臭奇恒互出，冠屨奄相踰。", "此說偶奇驗，人人生妄圖。", "曷不返吾照，湛然觀本初。", "天地付我形，森列萬理俱。", "形拘有枯菀，理充無智愚。", "塗人可以禹，爲善即舜徒。", "奈何遺此心，豢此尺寸膚。", "君顓唐舉術，乃取荀卿書。", "論心不論形，名象足啟余。", "宇宙共一軌，紛紛落迷塗。", "願言述吾語，一呼旋其車。"]'),
('9ec0a703-123f-44bc-8799-110f727b27b1','泊三江口','黎廷瑞','宋','宋诗','song-poetry','','[]','潮寒聞雁聲，野霽見虎跡。',108,'全唐诗/poet.song.247000.json','["潮寒聞雁聲，野霽見虎跡。", "眼中無故人，莽莽欲誰適。", "當年此防秋，築壘如鐵壁。", "哀哉不崇朝，遽此陵谷易。", "土道蝕殘磚，沙草埋折戟。", "林墟稍亦集，農畝猶未闢。", "人心嗜新樂，疇復念曩昔。", "亭亭千尺塔，獨立蒼烟碧。", "稽首塔中仙，此心如鐵石。"]'),
('0a215ba7-3eb1-47a4-a125-257711d8ce6e','泊雷江口','黎廷瑞','宋','宋诗','song-poetry','','[]','解纜風雨息，傍晚復大吼。',108,'全唐诗/poet.song.247000.json','["解纜風雨息，傍晚復大吼。", "浪如雪山來，船作騎馬走。", "魚龍欲作勢，問予驚怖否。", "那知狂書生，有膽大如斗。", "莊周論天地，我見僅如缶。", "可憐一勺多，浩蕩夸己有。", "大方付一笑，河伯亦俯首。", "天開鏡面平，蕩槳泊江口。", "新月照船窗，烹魚醖我酒。"]'),
('252d9948-9fb3-46d9-ab89-8cbaa3fcc5b6','虎溪三笑圖','黎廷瑞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','陰壁摻苦竹，秋池淡芙蓉。',204,'全唐诗/poet.song.247000.json','["陰壁摻苦竹，秋池淡芙蓉。", "二老廬山間，風味夙昔同。", "亦有栗里人，心事黄花叢。", "囊中無一錢，眼底四海空。", "羲皇未渠愜，上與無懷通。", "衆羽集新條，雲霄一冥鴻。", "凈社亦可人，念爾名教宗。", "博酒空勤渠，攢眉一聲鐘。", "蒼苔片石在，醉卧空山中。", "良辰入奇懷，杖屨閒相從。", "偶然出岫雲，儵爾風飄蓬。", "虎溪有嚴禁，詎敢待此翁。", "行行不知遠，大笑分西東。", "風流一時散，千載留高蹤。", "溪光與山色，隠隠尚笑容。", "笑意果何如，畫史安能窮。", "按圖付一嘿，翳景生長松。"]'),
('b17d1c2b-9eb7-4bf4-b0c6-0da96d0c0a40','避暑招真觀聽琴','黎廷瑞','宋','宋诗','song-poetry','','[]','驅車畏火傘，投扇倦風箑。',144,'全唐诗/poet.song.247000.json','["驅車畏火傘，投扇倦風箑。", "起行青松徑，往就白雲榻。", "窈窕一壑深，蒼蒼兩崖夾。", "玄菟獰爪齒，白龍老鱗甲。", "竹樹擁青摻，花草靄叢雜。", "渺沫灑空巖，冷飈下危峽。", "始知忘解带，久坐思御裌。", "丹丘逢羽人，瑶琴開寶匣。", "古意鬰蒼茫，秋風淡蕭颯。", "悲蟬爲噫吟，鳴鶴相和答。", "歲華坐晼晚，塵路嗟隘狹。", "飛仙倘來歸，遺我度世法。"]'),
('922b6b63-ac29-409d-8497-f3ae4aacf74b','南北舟','黎廷瑞','宋','宋诗','song-poetry','','[]','東流滔滔江似箭，南船掛帆北船羨。',80,'全唐诗/poet.song.247000.json','["東流滔滔江似箭，南船掛帆北船羨。", "陰雲黯黯天色變，北船搥鼓南船怨。", "焚香釀酒爭祝願，一望風長一祈轉。", "世間萬事無兩便，龍伯應酬毋乃倦。", "龍伯應酬如已倦，祇遣澄江凈如練。"]'),
('135e993f-9a19-4f92-8c46-68766310b05e','二陶','黎廷瑞','宋','宋诗','song-poetry','','[]','清言灑灑南華玄，凈社濟濟東林禪。',64,'全唐诗/poet.song.247000.json','["清言灑灑南華玄，凈社濟濟東林禪。", "一陶運甓不揮麈，一陶採菊不種蓮。", "愛惜分陰樹志業，盤礴千載希聖賢。", "吾評東晉人物藪，惟有二陶真卓然。"]'),
('c1b882cc-6a22-4292-b08d-8a85f05d7247','飲芝山分韻得草字','黎廷瑞','宋','宋诗','song-poetry','','[]','漠漠輕陰送幽討，梅柳之間春正好。',64,'全唐诗/poet.song.247000.json','["漠漠輕陰送幽討，梅柳之間春正好。", "萬古燒痕青未了，一片湖光白如掃。", "永懷雨露涵三秀，頗恨風塵遮五老。", "松根嘯咏欲忘歸，可惜長瓶卧芳草。"]'),
('6406ad97-fde2-4668-b7d2-17f32d4a87c9','探梅','黎廷瑞','宋','宋诗','song-poetry','','[]','山中歲晚甘恬澹，花史時時聞校勘。',112,'全唐诗/poet.song.247000.json','["山中歲晚甘恬澹，花史時時聞校勘。", "天街未省薇藥貴，塵世頗嫌桃李濫。", "南枝相見眼獨明，東風久要交非暫。", "長意孤山訪突兀，徑度平湖浮碧紺。", "暗香疏影夜濛濛，半樹橫枝春淡淡。", "琥珀濃傾酒拍船，珠璣亂唾詩成擔。", "畫角吹寒凄別語，青衣天晚生孤憾。"]'),
('cd2ff0c2-e74e-4ee6-aa9c-3fc77a20f2bb','偕仲退周南翁登曲島山分韻得曲字','黎廷瑞','宋','宋诗','song-poetry','','[]','吳子精悍錦滿腹，周郎英妙人如玉。',320,'全唐诗/poet.song.247000.json','["吳子精悍錦滿腹，周郎英妙人如玉。", "凌晨樽酒惜分携，飛鞚聯翩相趁逐。", "積雨新晴馬氣驕，振鬣長鳴踏平陸。", "村南村北楓葉赤，高田低田麥苗綠。", "坡陀磊落如培塿，一島軒然立於獨。", "平生夢寐千仞岡，第取愜心那計足。", "迢迢鳥道入青天，杳杳鐘聲出喬木。", "遥觀疑雪復疑石，稍動始知樵與牧。", "傳聞隋代高隠君，避世曾茲結茅屋。", "李菀楊枯了不聞，坐擁玉書林下讀。", "靈君冠劍從飛龍，雲雨蒼茫手翻覆。", "瓢中但出是豐年，何惜穿崖懸一瀑。", "毳蟲自得餐松訣，一掃四山寒翠禿。", "天根突兀有孤梅，道氣昂藏自修竹。", "回看下界暗黄塵，蟻垤蜂房幾陵谷。", "山空鳥啼塵慮絕，天寒日暮歸心速。", "會當擺落悠悠談，八極神遊縱吾目。", "玉井蓮花十丈開，瑶池桃子千年熟。", "廓然天地臯方圓，豈但山川見紆曲。", "已呼鸞凰作先導，歲晚期君兩黄鵠。"]'),
('dc463a09-b34a-4975-b7c6-66dc504e6ea5','甲午孟夏祝公輔道過山中遂偕如上饒赴孟史君之約至萬村阻水卧樓上共談己丑同舟雁汊遇風之苦明日水退途中得長句呈公輔','黎廷瑞','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','南山有田不歸種，大瓠濩落無所用。',384,'全唐诗/poet.song.247000.json','["南山有田不歸種，大瓠濩落無所用。", "遂令沉沉走長江，萬里艱危憶君共。", "嘗疑公佩延平劍，引得九淵龍子鬨。", "雁汊渡頭鏖北風，真是脫身人鮓甕。", "當時意氣杯溟渤，笑殺篙師窮欲慟。", "千金之子不垂堂，默坐沉思還自痛。", "歸來結屋萬山中，手植桃花欲成洞。", "敲門者誰吾故人，色筆熒熒如彩鳳。", "連宵劇談山月落，一浣胸中塵土空。", "忻然共駕赴幽期，滿路薰風入吟諷。", "萬村孤館明且潔，浴罷桃笙玉壺凍。", "神君謁帝愁晝熱，夜半騎𬳮不施鞚。", "偷决銀河灌火輪，玄化陰機神簸弄。", "小溪如綫不自容，更奈亂流趨者衆。", "劃爾掀波似轉雷，居然入室如流汞。", "須臾便恐化桑田，咫尺還憂沒茅棟。", "絕憐榻上閙蛙黽，安得天邊明螮蝀。", "午樓欹枕聽濤聲，喚醒六年淮海夢。", "青山淡淡坐神馳，白鷺悠悠空目送。", "明朝水退得新晴，兩鳥故應天所縱。", "乃知處險自有道，一靜可以該百動。", "橫石斷橋沙逕曲，蒼藤翠木烟霏重。", "小車穿壁我徐行，瘦蹇涉流君自控。", "狂遊滿眼驚俗輩，疲役回頭慚僕從。"]'),
('a168e00c-c346-4f44-8615-70d0213bfb1c','有邀余游中原者余以親老辭王子賢未知來餞別并示所和陳君人生貴適意五詩敬次韻奉謝  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','有客六轡濡且均，要我共看中都春。',64,'全唐诗/poet.song.247000.json','["有客六轡濡且均，要我共看中都春。", "孔林喬木故無恙，首陽高風應未泯。", "亦知江山不負我，政恐風塵能涴人。", "故友貽書復相過，但祝自愛千金身。"]'),
('6a7ec063-cff0-4acb-b689-a013097883c3','有邀余游中原者余以親老辭王子賢未知來餞別并示所和陳君人生貴適意五詩敬次韻奉謝  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','飛電歘然度天隙，百歲能堪幾行役。',64,'全唐诗/poet.song.247000.json','["飛電歘然度天隙，百歲能堪幾行役。", "遊子來歸意恐遲，大人幸在何辭白。", "風濤念爾去何之，日暮憐渠行故逆。", "世間步步是危機，綿上可耕聊自適。"]'),
('0193363e-e258-4480-9292-70b46c2e1edd','贈姜卜隠','黎廷瑞','宋','宋诗','song-poetry','','[]','君家鼻祖磻溪釣，何人爲卜非熊兆。',80,'全唐诗/poet.song.247000.json','["君家鼻祖磻溪釣，何人爲卜非熊兆。", "君是磻溪幾代孫，無人卜君君卜人。", "自言避世歸人境，焚香下簾清晝永。", "豈無龍韜老渭濱，英雄自昔多沉淪。", "倘有獵者從君卜，但說後車富狐兔。"]'),
('c8506e1c-a0b8-4b5f-bf1c-094410d0a464','丙申上元喜晴孤坐懷舊二十韻','黎廷瑞','宋','宋诗','song-poetry','','[]','少年意氣凌嵩華，尚記京城逢午夜。',320,'全唐诗/poet.song.247000.json','["少年意氣凌嵩華，尚記京城逢午夜。", "璧月瓊枝彩鳳飛，銀花鐵鎖金鰲跨。", "樓臺上下沸笙韶，巷陌東西暗蘭麝。", "樗蒲百萬不供擲，美酒十千寧論價。", "狂遊但恐星河曙，醉卧不知風露下。", "悠悠人世半悲歡，忽忽天時更代謝。", "蟻國驚心城郭非，蜃樓轉眼烟雲化。", "微生幸爾脫干戈，暮年聊此依桑柘。", "每當佳節强逢迎，忽思往事還驚咤。", "新年半月雨不止，此夕一晴天所借。", "草市鼕鼕村鼓閙，竹簷爛爛華燈掛。", "顛狂社舞喧戲劇，落魄儒冠寄嘲駡。", "亦知陋俗多浮薄，尚喜疲甿少閒暇。", "先生清坐懶出門，諸少並遊惟守舍。", "雖無畫燭千炬圍，猶有殘梅一枝亞。", "孤燈隠隠耿相照，疏影離離淡如畫。", "劃爾喧風撲短檠，炯然霽月明虛榭。", "百念無營冷似灰，一閒有味甘如蔗。", "已拚暮境漁樵侶，獨憶平生詩酒社。", "白雲靄靄隔江山，可惜無人談舊話。"]'),
('9e4c7735-d663-4a38-859b-5632c78edcbf','烏沙夾阻風','黎廷瑞','宋','宋诗','song-poetry','','[]','黄沙滿江日色薄，北風吹天雲欲落。',128,'全唐诗/poet.song.247000.json','["黄沙滿江日色薄，北風吹天雲欲落。", "魚龍賈勇氣凌人，八月海風無此惡。", "書生性命可輕試，拏舟早傍沙灣泊。", "嵯峨萬里下水船，搥鼓張帆無奈樂。", "篙師瘦坐攢兩眉，羨彼何速嗟我遲。", "玄冥行權故應爾，速何足喜遲何悲。", "一年三百六十日，須有一日順風時。", "乘流遇坎姑聽之，濤山雪屋方堪詩。"]'),
('dfffc688-723b-4793-ab8a-edb051c22c74','春鋤行','黎廷瑞','宋','宋诗','song-poetry','','[]','有鳥有鳥鳴春鋤，雪衣楚楚清且癯。',64,'全唐诗/poet.song.247000.json','["有鳥有鳥鳴春鋤，雪衣楚楚清且癯。", "茫然跂立奚所須，蹄涔之中伺遊魚。", "遊魚所得能幾何，鸕鷀同儔失已多。", "若非區區營一飽，如此風標豈不好。"]'),
('ae9082db-0042-4f0c-b176-7bd59ea3fc06','彭蠡阻風','黎廷瑞','宋','宋诗','song-poetry','','[]','玄雲如壘沙如箭，陽侯擊鼓飛廉扇。',96,'全唐诗/poet.song.247000.json','["玄雲如壘沙如箭，陽侯擊鼓飛廉扇。", "穹龜带甲魚負劍，萬怪騰空助龍戰。", "廬君玉立金芙蓉，笑我塊坐如樊籠。", "子胡不來此山中，與子跨鶴蓬萊宮。", "江流茫茫去不息，嗟我棹往何終極。", "靈君如願倘可乞，但覓金丹生羽翼。"]'),
('73755ef4-6575-4a6d-a472-ae7aca0d0899','壬戌正旦日蝕值陰有詩明日雨微雪再賦','黎廷瑞','宋','宋诗','song-poetry','','[]','艷娥煽妖悖且饕，雲師圍之騎周遭。',160,'全唐诗/poet.song.247000.json','["艷娥煽妖悖且饕，雲師圍之騎周遭。", "飛廉喑嗚挾箭號，萬鼓動地助戰鏖。", "吳剛棄斧北且逃，扶桑君還騎巨鰲。", "銀蜍腹聚流清膏，玉兔顙折飛白毛。", "蒼茫殺氣橫四郊，凍鳶無語饑鴻嗷。", "紫皇第功封二豪，汝馬可歸弓可櫜。", "黄道肅穆君請遨，黔首顒顒光勿韜。", "願駕丹轂揚錦旄，疾驅六龍升海濤。", "五色爛爛中天高，衣披水子絳錦袍。", "葵心不寧憂忉忉，矯首東方歌楚騷。"]'),
('91627bdd-5082-4426-92fb-94062106ffe6','朱可紹去秋許椶靸明年夏當見寄今及期矣輒以詩請','黎廷瑞','宋','宋诗','song-poetry','','[]','寥陽宮殿老夜叉，九頭獰獰髪髿髿。',160,'全唐诗/poet.song.247000.json','["寥陽宮殿老夜叉，九頭獰獰髪髿髿。", "朝暮拔本不滿數，謫守鳳山山下花。", "忽生蟻虱若魚子，秋風透頂櫛復爬。", "夫君豈鬻居士屩，履聲漢代尚書家。", "不嫌汝髪污我趾，結鞋遠勝蕭與麻。", "煌煌火輪照萬野，恨不赤脚踏雪車。", "世間褦襶獨何事，黄塵沒骻汗透靴。", "老夫兩鬢亦蕭颯，謝去相帽便烏紗。", "願言得此稱輕爽，宿諾今已期及瓜。", "誓當布襪從此始，上下雲門還若耶。"]'),
('7d124391-3f12-4737-a346-1d98e1bc113a','聽山中談虎賦二章  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','樵夫山下日將暮，忽逢饑虎在中路。',99,'全唐诗/poet.song.247000.json','["樵夫山下日將暮，忽逢饑虎在中路。", "目光如炬齒如霜，舉頭爲城腹爲墓。", "偷生無計就死難，再拜祈哀號且訴。", "我貧且老孤無兒，瘦骨幾何君勿悞。", "垂頭兀坐欲有問，歘爾翻身入雲霧。", "君不見悍吏捉人吮甘膏，千拜萬拜不可逃。"]'),
('5db6cfa7-2a0b-40da-9b40-dd8e7fb3ff7c','聽山中談虎賦二章  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','東村西村稼如雲，欲穫未穫黄紛紛。',114,'全唐诗/poet.song.247000.json','["東村西村稼如雲，欲穫未穫黄紛紛。", "鼠牙雀喙不可算，奈此野彘千百群。", "田頭結舍坐霜夜，敲犁擊杵聲相聞。", "五更一刻少困怠，終歲舉室空辛勤。", "近日南山老虎至，野彘畏之俱遠避。", "遂令一枕得安眠，犬豕時時亦遭噬。", "嗚呼犬豕所噬能幾何，野彘不去爲害多。"]'),
('f6fb4a84-82af-42d2-9d8f-1ccd29364c50','松風','黎廷瑞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','流水渡澗秋泠泠，怒濤拍天風雨驚。',144,'全唐诗/poet.song.247000.json','["流水渡澗秋泠泠，怒濤拍天風雨驚。", "鸞鏘鶴唳翻青冥，龍吟虎嘯愁太陰。", "連山遍野流空明，飄飄音樂張洞庭。", "彈璈鼓簧吹雪笙，拊石擊磬作天鈞。", "忽然昭文不鼓琴，幽幽又作吟風箏。", "問童何如睡不應，起視月落天河傾。", "乃知虛皇集萬靈，風伯起舞蒼穹伶。", "世間鄭衛聊足聽，久笑舞此蓬萊音。", "傳伯技癢不可禁，篝燈起誦離騷經。"]'),
('81a7b9bb-38d3-4e01-9f86-b86e4750c45d','贈王秀翁','黎廷瑞','宋','宋诗','song-poetry','','[]','君挾青囊枕中寶，別我去行千里道。',64,'全唐诗/poet.song.247000.json','["君挾青囊枕中寶，別我去行千里道。", "淮南小山訪松桂，湘江極浦尋芳草。", "侯王有種從何來，富貴在天非可禱。", "倘遊海上遇安期，歸來遺我如瓜棗。"]'),
('0aa8d906-f059-4004-9561-528016b52918','鐵笛行贈丁雲屋','黎廷瑞','宋','宋诗','song-poetry','','[]','斗牛之墟有伏龍，寶氣夜起天爲虹。',160,'全唐诗/poet.song.247000.json','["斗牛之墟有伏龍，寶氣夜起天爲虹。", "雷公往矣不再逢，潭底高卧吟秋風。", "忽羞珠宮薄且闕，返形化作紅爐雪。", "背負七星雷吐舌，五色石墮天驚裂。", "何人携此過武亭，真仙東遊弭節聽。", "知音千載空翠屏，猿啼鬼哭烟冥冥。", "華表雲深鶴一隻，渺渺孤吟空八極。", "左呼廬阜老仙客，右呼西風古禪伯。", "江上暮雲寒蕭蕭，梅花未動飄葉凋。", "紅尾鳳凰飛翠霄，好去瑶臺吹玉簫。"]'),
('e9f0224b-07b3-4ae0-86c5-e721f511f002','上奚宣慰冰壑','黎廷瑞','宋','宋诗','song-poetry','','[]','書生於世無所用，歲晚東陵瓜自種。',192,'全唐诗/poet.song.247000.json','["書生於世無所用，歲晚東陵瓜自種。", "幾度騎馿欲出門，青松繞舍雲扃洞。", "枕書高卧綠陰中，何許清風驚午夢。", "始知絳節下丹霄，左驂麒麟右鸞鳳。", "行行原隰廣咨詢，歷歷閭閻摩疾痛。", "懸崖絕壁冰照壑，白晝青山雷欲凍。", "神姦畏景那敢見，肯綮逢刀無不中。", "范滂太守使令懾，楊綰入相朝野頌。", "每繙圖史想斯人，常恨寥寥千載空。", "水見黄河山太華，不識歐陽當自訟。", "振衣扶策候轅門，秋意欣然云走送。", "願調梅鼎作商霖，老我荒園日抱甕。"]'),
('4008b282-3463-4b97-b44a-64767709f202','啄木辭','黎廷瑞','宋','宋诗','song-poetry','','[]','木鬰鬰兮有蠹生之，穴冥冥兮木窾以委。',67,'全唐诗/poet.song.247000.json','["木鬰鬰兮有蠹生之，穴冥冥兮木窾以委。", "皇賫于鴷兮厥服孔儀，往伺于木兮爾喙爾夷。", "朝于木癭兮莫于木枝，蠹宿于根兮而鴷不知，厦將墮兮其何以支。"]'),
('abd1bcf6-0899-4835-abcd-9f57ab9e1a2f','久旱得雨連陰彌旬農者云復宜得數日晴作二龍行','黎廷瑞','宋','宋诗','song-poetry','','[]','赤龍推車出暘谷，欲將燭光燒却珊瑚屋。',102,'全唐诗/poet.song.247000.json','["赤龍推車出暘谷，欲將燭光燒却珊瑚屋。", "黑龍奮怒起天池，欲倒海水浸却扶桑枝。", "黔黎代爲黑龍訴，帝命赤龍且回馭。", "已欣膏澤沃焦塵，復畏連陰起寒霧。", "地裂不補難望秋，天漏不補亦可憂。", "我願二龍行天各一日，水火停齊萬寶畢。"]'),
('c161d0d6-2021-4f73-ad81-e6ccedd9f155','送鶴神','黎廷瑞','宋','宋诗','song-poetry','','[]','玄裳兮縞衣，紛爾乘兮遄歸。',86,'全唐诗/poet.song.247000.json','["玄裳兮縞衣，紛爾乘兮遄歸。", "嗟我甿兮苦復苦，穀懸于天兮麥在土。", "爾之族兮類且多，蠶爾食兮如甿何。", "甿之憂兮來年眎爾天爾田。", "天崇崇兮有廩，皇之漿兮可飲。", "樂莫樂兮爾還，勿復來兮人間。"]'),
('0898e551-4c33-4e77-92d7-f624463399cd','飲酒樂','黎廷瑞','宋','宋诗','song-poetry','','[]','羊祜折臂爲三公，英布之相黥而王。',254,'全唐诗/poet.song.247000.json','["羊祜折臂爲三公，英布之相黥而王。", "富貴真可愛，體膚不敢傷。", "劉安升天守都厠，長房學道須食糞。", "神仙誠可慕，臭穢那可近。", "駟馬高蓋未易求，水銀黄金况難信。", "我亦不願承明廬，我亦不願蓬萊山。", "但願觳𧥆耕田間，種秫釀作九霞丹。", "秋風兩鬢不須綠，日飲時可朱吾顔。", "山花山鳥自歌舞，醉聽松風牢掩關。", "用世之士笑我拙，出世之士憐我頑。", "冕裳不著雖共蓑笠老，露霓易過安得歲月還。", "那知我復笑爾還爾憐，千秋之後高臺曲池在何處。", "六鰲之側岱嶼員嶠俱深淵，茲論猶日茫昧然。", "華亭鶴唳欲聽不可得，單豹遇虎所養安得全。", "唯有飲酒之樂不可言，所以達士不與醒者傳。"]'),
('026fa347-b9bf-4cc1-860d-f6dbccc577c1','鵬飛操','黎廷瑞','宋','宋诗','song-poetry','','[]','朝吾發兮海溟，夕吾抵兮天門。',163,'全唐诗/poet.song.247000.json','["朝吾發兮海溟，夕吾抵兮天門。", "鱗脫軀兮欲蛻，翮之起兮如雲。", "濤山湧兮雪浪，駕天風兮浩蕩。", "霓掩映兮霞蒸，倏橫飛兮徑上。", "龍膢余兮鳳來迎，帝下觀兮環珮鳴。", "逍遥遊兮既極，澹河漢兮無聲。", "河漢無聲兮有意，誰知之兮漆園吏。", "桐之孫兮吏之魂，吏不語兮孫能言。", "忘言兮且止，極吾思兮隠几。", "春風菲菲兮杏壇花，春服翩翩兮沂水涯。", "聊徜徉兮稅駕，奚必之兮南華。"]'),
('2393c7f2-31b3-44b4-b1f4-e73e926b5afc','精衛行','黎廷瑞','宋','宋诗','song-poetry','','[]','微禽負大耻，勁氣橫紫冥。',124,'全唐诗/poet.song.247000.json','["微禽負大耻，勁氣橫紫冥。", "口啣海山石，意欲無滄溟。", "滄溟茫茫雲正黑，濤山峨峨護龍國。", "假令借爾秦皇鞭，驅令石頭填不得。", "布囊盛土塞江流，孫郎覽表笑不休。", "勞形區區讎浩渺，志雖可尚難乎酬。", "蓬萊有人憐爾苦，勸爾休休早歸去。", "精衛精衛我亦勸汝歸，滄海自有變作桑田時。"]'),
('b9d72c07-dff3-41e4-be69-2845d00b88b5','泊淮岸夜聞鬼語','黎廷瑞','宋','宋诗','song-poetry','','[]','北風行平林，蘆葉響乾雨。',206,'全唐诗/poet.song.247000.json','["北風行平林，蘆葉響乾雨。", "青燐走平沙，獨夜鬼相語。", "沉吟乍幽咽，怨哭倍酸楚。", "遺臠烏鳶飽，滯魄狐兔伍。", "白骨委飛霜，零落從草莽。", "草死東風吹復生，骨枯東風吹不榮。", "汝悲信悲不足詰，吾欲詰爾爾試聽。", "君不見劉項割鴻溝，又不見孫曹戰赤壁。", "回頭萬事曉雲空，石馬荒荒土花碧。", "世間倘有長生藥，薊子白雲丁令鶴。", "霸城相見悲銅狄，華表歸來歎城郭。", "汝不見興與衰，又不憂寒與饑。", "濠上之叟不汝欺，汝有至樂爾不知。", "嗚呼人生何苦爾何樂，人生羨汝不可學。"]'),
('74192af3-24b4-4dc2-a3a8-79ac2a09265f','禽言四首  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','布穀布穀，十家九家逃亡屋。',65,'全唐诗/poet.song.247000.json','["布穀布穀，十家九家逃亡屋。", "去冬屯田買牛到黄犢，今春軍需剝皮共食肉。", "無牛可耕休論飯，秋糧要米從何辦。", "布穀布穀奈爾何，江南漸少淮南多。"]'),
('53c74ee6-a5c9-4a6e-9822-15f6d29aca39','禽言四首  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','不如歸去，歸去故鄉不是無耕處，爾獨胡爲在中路。',54,'全唐诗/poet.song.247000.json','["不如歸去，歸去故鄉不是無耕處，爾獨胡爲在中路。", "子規子規，爾不自勸何用勸我爲。", "我懷我室更欲歸，爾歸漂摇何所依。"]'),
('2f6fccb3-34bb-4f5f-a237-42d384009271','禽言四首  其三','黎廷瑞','宋','宋诗','song-poetry','','[]','麥飯熟快活，半年忍饑待此麥，問汝快活能幾時。',40,'全唐诗/poet.song.247000.json','["麥飯熟快活，半年忍饑待此麥，問汝快活能幾時。", "更有五月六月饑亦所不辭，且願休王師。"]'),
('51dded5c-1a1d-4fa8-8d37-8f8f54f7b177','禽言四首  其四','黎廷瑞','宋','宋诗','song-poetry','','[]','提壺盧，沽美酒，烹肥羜，剪新韭。',83,'全唐诗/poet.song.247000.json','["提壺盧，沽美酒，烹肥羜，剪新韭。", "琵琶胡姬玉纖手，清歌嫋嫋鶑囀柳，尊前勸我千萬壽。", "君不見東家逃亡西家走，惟我臺上集親友。", "明日得似今日否，酒盡無盡盡再沽。", "喚僕夫，提壺盧。"]'),
('5ab85ed5-1a5f-41cd-90df-b0e6b9655591','贈古泉相士','黎廷瑞','宋','宋诗','song-poetry','','[]','土階章韶風日美，巢父不聽却洗澗中水。',92,'全唐诗/poet.song.247000.json','["土階章韶風日美，巢父不聽却洗澗中水。", "象犀滿山珠塞淵，棄不之顧但酌嶺外泉。", "嗚呼千丈之渾泥數斗，一滴清泠空宇宙。", "古人今人同此耳與口，古泉眼中見有相似二君不。", "我亦有耳但願聽松風，有口只飲酒。"]'),
('ab9d833e-c717-4079-ab3d-f60201b7b2cc','禽言  其一','黎廷瑞','宋','宋诗','song-poetry','','[]','朝看花滿枝，暮見花辭樹。',36,'全唐诗/poet.song.247000.json','["朝看花滿枝，暮見花辭樹。", "東風翻覆手，驟開驟落無憑據。", "不如歸去，不如歸去。"]'),
('e362c1da-8b6e-4054-a57a-0fd015dcdf93','禽言  其二','黎廷瑞','宋','宋诗','song-poetry','','[]','萬疊青山，白雲何處。',69,'全唐诗/poet.song.247000.json','["萬疊青山，白雲何處。", "行不得，哥哥哥。", "冥冥高飛憂網羅，煢煢孤往虞干戈。", "江湖蛟鱷擾，山谷虎狼多。", "行不得，哥哥哥。", "不信時，哥但知去到前頭無去處。"]'),
('bbc1d637-0714-4853-a5be-026490b41bf9','題孫方叔石泉亭','黎廷瑞','宋','宋诗','song-poetry','','[]','君不見山上石，可以搘明堂而柱宣室。',152,'全唐诗/poet.song.247000.json','["君不見山上石，可以搘明堂而柱宣室。", "又不見石上泉，可以蘇大旱而致豐年。", "君隠非山隠於市，安有萬丈蒼崖千丈水。", "自言掇拾累巉巖，更復停潴引清泚。", "朝霏淡淡苔蘚生，暮雨瀟瀟蛙黽喜。", "餐松啖柏吾齒可以礪，譽堯非桀吾耳可以洗。", "君家鼻祖子荆子，千年家法應如此。", "一丘一壑真自足，坐守風烟終局促。", "欲友子駕兩黄鵠，香爐峰頭看飛瀑。"]'),
('1a74a1ee-e935-4abf-85c6-74d9a5d26ab5','贈堪輿家楊生','黎廷瑞','宋','宋诗','song-poetry','','[]','楊子逐貧不去，楊仙救貧便富。',94,'全唐诗/poet.song.247000.json','["楊子逐貧不去，楊仙救貧便富。", "始知方技可發身，不信儒冠真誤人。", "生出楊枝枝幾葉，青囊世世能傳業。", "祇今四海貧士多，我救無術可奈何。", "蒼梧雲去天亦老，會稽穴沒生秋草。", "但願沉冥了歲年，江南何地出酒泉。"]'),
('adc59cf7-61ce-4e5e-b452-e7059f31e86f','送方此山歸盤中','黎廷瑞','宋','宋诗','song-poetry','','[]','渴不飲盜泉水，熱不棲惡木陰。',118,'全唐诗/poet.song.247000.json','["渴不飲盜泉水，熱不棲惡木陰。", "飛蚊營營蚋漫漫，掇拾餘醖搜殘斟。", "祝融老子亦忘劇，于君大是相知音。", "娛娛炎埃場，遺以清風林。", "蒼藤老樹覆林磵，芸夫綸叟時相尋。", "太虛茫茫納宇宙，雲來雲去初何心。", "送君盤中居，且作盤中吟。", "雙溪渡頭一笑去，落日孤舟秋水深。"]'),
('d03013af-777c-4a8d-8690-e00b5d089f49','次徐松巢韻','黎廷瑞','宋','宋诗','song-poetry','','[]','欲寄音書碧宇空，幾回溪上佇秋風。',64,'全唐诗/poet.song.247000.json','["欲寄音書碧宇空，幾回溪上佇秋風。", "離愁自歎三千丈，飛夢長隨十八公。", "尚書蘭孫懷舊好，頗疑梨棗悶新功。", "寅君近况知何似，想見丹爐夜夜紅。"]'),
('7b04066e-2919-4633-8c33-42a9364059d4','又','黎廷瑞','宋','宋诗','song-poetry','','[]','結廬溪水上，日夕對郭璞。',60,'全唐诗/poet.song.247000.json','["結廬溪水上，日夕對郭璞。", "清曉林霏開，碧玉峭如削。", "幾欲乘興游，不見雲山鶴。", "青鞋動高興，安得踐斯約。", "尊酒不須携，巖泉清可酌。"]'),
('4aeb258c-c0f6-485c-b1d8-9a6579f13ba5','題鄭子實秋溪釣雨圖','陸文圭','宋','宋诗','song-poetry','','[]','水墨淡淡，烟雨濛濛。',40,'全唐诗/poet.song.247000.json','["水墨淡淡，烟雨濛濛。", "溪抱前山，人倚孤篷。", "我懷季鷹，感慨秋風。", "身羈洛下，興寄吳淞。"]'),
('56fc7a66-8f1b-473d-b36d-b3ca07ec8238','題猿石手卷二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','空山暮雨，枯木曉霜。',20,'全唐诗/poet.song.247000.json','["空山暮雨，枯木曉霜。", "此處聞聲，若爲斷腸。"]'),
('0c0ce7cc-8050-4686-a9e3-7d3c02733da5','題猿石手卷二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','楚山無人，群戲樹顛。',20,'全唐诗/poet.song.247000.json','["楚山無人，群戲樹顛。", "或據大石，如君長然。"]'),
('42dc69e6-a643-4835-99cb-b5e45155b0b4','讀史','陸文圭','宋','宋诗','song-poetry','','[]','魏延及楊儀，兩人蜀俊乂。',120,'全唐诗/poet.song.247000.json','["魏延及楊儀，兩人蜀俊乂。", "各懷專妬心，曲直竟誰在。", "孔明惜其才，未嘗輒偏廢。", "渭南反斾歸，師在千里外。", "朝臣意左右，魏爲楊所害。", "楊亦不得死，晚用姜維輩。", "蜀竟以是亡，束手付鄧艾。", "艾復矜其功，受制于鍾會。", "四人共一律，皆以專妬敗。", "家國莫不然，嗚呼可爲戒。"]'),
('54231d82-aee4-49f7-8f7a-f8963bec941a','李杜','陸文圭','宋','宋诗','song-poetry','','[]','子美坐同谷，太白走扶風。',108,'全唐诗/poet.song.247000.json','["子美坐同谷，太白走扶風。", "雖遭倉黄急，轉覺吟咏工。", "首亂者群憸，貽禍及二翁。", "因知漆室女，發論乃至公。", "觸事機難審，臨危計易窮。", "川原愁夕照，草木困西風。", "鬼馬如龍游，鬼妾如花紅。", "變滅不須臾，焉能保其終。", "擇禍莫若輕，老遁林谷中。"]'),
('408df3c1-88c4-4ebb-8e8f-d00b77ade06a','賦蕭仲堅所書汴梁節婦事','陸文圭','宋','宋诗','song-poetry','','[]','汴水流濁黄，美人如冰清。',108,'全唐诗/poet.song.247000.json','["汴水流濁黄，美人如冰清。", "案無伯鸞夫，袴無趙氏嬰。", "姑老扶上牀，夜寒機杼鳴。", "停梭獨太息，莫把鴛鴦織。", "織成孤飛雁，離群不再匹。", "河東柳家兒，抉眼去其夫。", "愚者生不諧，直者死不渝。", "太師漢復周，相國秦又楚。", "嗟哉二丈夫，愧此一嫠女。"]'),
('820f508c-8451-4524-9d73-4a104cd0a555','謝詹中美惠五典毓蒙書','陸文圭','宋','宋诗','song-poetry','','[]','山上有佳木，春風抽新萌。',144,'全唐诗/poet.song.247000.json','["山上有佳木，春風抽新萌。", "勿縱羊與斧，條葉隨敷榮。", "山下有流泉，涓涓滴深清。", "勿投泥與沙，支派任縱橫。", "物爾人亦然，習與性俱成。", "位可望賢聖，教乃始孩嬰。", "五典敘千古，一編粹群英。", "屬辭不厭巧，立義不厭精。", "金玉二三子，源委諸老生。", "寒燈讀未竟，眵眼開雙明。", "惜哉書晚出，會使世盛行。", "價知貴洛紙，報愧乏齊瓊。"]'),
('161be717-f53d-4fd1-b829-58e860238577','得己堂','陸文圭','宋','宋诗','song-poetry','','[]','爲己終成物，爲人適喪己。',72,'全唐诗/poet.song.247000.json','["爲己終成物，爲人適喪己。", "得之以爲重，喪者深可耻。", "與其乞墦生，不若蒙袂死。", "貧賤勿失色，富貴亦勿競。", "窮達本無心，安於義與命。", "人受命於天，顔孟獨能正。"]'),
('8bbc48cd-a92d-4b6c-8ca7-02e5be76d179','性齋二首爲分湖陸提舉作  其一','陸文圭','宋','宋诗','song-poetry','','[]','孔門性不聞，學者失其義。',108,'全唐诗/poet.song.247000.json','["孔門性不聞，學者失其義。", "上中下爲三，善與惡爲二。", "鄒洛異而同，韓揚同而異。", "不指理不明，不兼氣不備。", "理無智無愚，氣有駁有粹。", "本體在涵養，工夫由克治。", "立義以居敬，存誠以去僞。", "曾思兩卷書，學問千古事。", "性外無餘天，齋中有樂地。"]'),
('799463fd-d4cd-4cbf-be0d-86bae6810b25','性齋二首爲分湖陸提舉作  其二','陸文圭','宋','宋诗','song-poetry','','[]','吾宗家湖曲，虛齋納天光。',72,'全唐诗/poet.song.247000.json','["吾宗家湖曲，虛齋納天光。", "清源瀉活水，中有菡萏香。", "我欲袖兩圖，再拜升公堂。", "先天揭右序，太極列左方。", "見草憶舂陵，看花思洛陽。", "花草各有性，指圖試參詳。"]'),
('a346afb9-8156-41d8-82a8-5e98d46c7ee3','怡顔亭曹若晦子無易爲奉親作','陸文圭','宋','宋诗','song-poetry','','[]','冬青有何好，婆娑歲寒姿。',72,'全唐诗/poet.song.247000.json','["冬青有何好，婆娑歲寒姿。", "每愛淵明句，獨樹乃爲奇。", "朝陽紫翠交，夕月光陸離。", "幽懷聊所寄，宴生輒移時。", "陶寫得真性，絲竹亦何爲。", "歡趣不自覺，况令兒輩知。"]'),
('1c42bb82-f22f-4b3f-9b9e-74cd64d4ac65','雜詩五首  其一','陸文圭','宋','宋诗','song-poetry','','[]','田叟不知書，指望升平年。',48,'全唐诗/poet.song.247000.json','["田叟不知書，指望升平年。", "一生把鋤犁，忽聞鑄戈鋋。", "早晚征徭起，驚訛走相傳。", "腐儒寒窗下，風雨正齁眠。"]'),
('c2994d15-7e82-4199-a950-90d8a37c665e','雜詩五首  其二','陸文圭','宋','宋诗','song-poetry','','[]','夜半更相呼，巷南連巷北。',48,'全唐诗/poet.song.247000.json','["夜半更相呼，巷南連巷北。", "人語何喧喧，陰風何窣窣。", "猛虎下山來，挼尾逐不得。", "村中雞犬盡，行擇小兒食。"]'),
('38d66181-dc42-4890-ba69-f53636c3194f','雜詩五首  其三','陸文圭','宋','宋诗','song-poetry','','[]','何處人夜歸，一犬穿籬吠。',48,'全唐诗/poet.song.247000.json','["何處人夜歸，一犬穿籬吠。", "狺狺聲四起，似各應其類。", "月寒人影空，帖耳循牆去。", "家家防穿窬，披衣不得睡。"]'),
('c80dc4a4-635d-4f82-9930-bc87f5eebec7','雜詩五首  其四','陸文圭','宋','宋诗','song-poetry','','[]','秋聲何颼颼，乃在枯柳邊。',48,'全唐诗/poet.song.247000.json','["秋聲何颼颼，乃在枯柳邊。", "疇昔韻鸝鶊，歲晚棲窮蟬。", "張緒少年時，春風正可憐。", "流光不相待，白首淚潸然。"]'),
('03786ee4-d558-4d4f-aebd-f47f88647813','雜詩五首  其五','陸文圭','宋','宋诗','song-poetry','','[]','定遠未封侯，發憤投其筆。',48,'全唐诗/poet.song.247000.json','["定遠未封侯，發憤投其筆。", "老儒七十餘，毫禿手不釋。", "才器有長短，志器各自適。", "遥思玉關外，萬里風沙隔。"]'),
('c349f156-f90e-41f3-9005-63758c4d06b3','次善卿雜詩五首  其一','陸文圭','宋','宋诗','song-poetry','','[]','貞女不自媒，蛾眉爲誰掃。',72,'全唐诗/poet.song.247000.json','["貞女不自媒，蛾眉爲誰掃。", "春風吹年華，閉戶綠芳草。", "靈脩不我顧，覽鏡紅顔槁。", "焉得北堂萱，聊用寬憂抱。", "又懼青蠅讒，善使黑白倒。", "遂令親者疏，我欲俾有昊。"]'),
('cb7c8ea4-5ab7-415a-8acc-34f783e1b5bd','次善卿雜詩五首  其二','陸文圭','宋','宋诗','song-poetry','','[]','東坡譏舉子，有類候蟲鳴。',60,'全唐诗/poet.song.247000.json','["東坡譏舉子，有類候蟲鳴。", "退之譏詩人，謂作蒼蠅聲。", "制策直而核，聯句新且清。", "自作復自譏，持論終未平。", "無人解此意，起我懷古情。"]'),
('623796a3-fc19-4e4e-a7f1-af68e5c0042e','次善卿雜詩五首  其三','陸文圭','宋','宋诗','song-poetry','','[]','蛙從井底語，豹在管中見。',60,'全唐诗/poet.song.247000.json','["蛙從井底語，豹在管中見。", "若遇大方家，一笑真自獻。", "饋漿意已驚，抱甕力殊倦。", "因知巧若拙，頗覺狂次狷。", "玉以德保瑕，珉以多故賤。"]'),
('e10c1adf-f239-418e-b714-112c0f62fb70','次善卿雜詩五首  其四','陸文圭','宋','宋诗','song-poetry','','[]','火雲吐赤日，旱勢千里闊。',60,'全唐诗/poet.song.247000.json','["火雲吐赤日，旱勢千里闊。", "古人救荒術，貨食知本末。", "家家算口賦，殆類僧持鉢。", "激水活肆枯，植木蔭道暍。", "諸公善努力，赤子正饑渴。"]'),
('3dde6d38-be77-41d8-a923-3bb85da4bad1','次善卿雜詩五首  其五','陸文圭','宋','宋诗','song-poetry','','[]','棄兒啼草間，瘦妻卧路傍。',84,'全唐诗/poet.song.247000.json','["棄兒啼草間，瘦妻卧路傍。", "公廩已告匱，私戶猶多藏。", "嗟哉守錢奴，盜竊勢且昌。", "莫保千金軀，汝富安得長。", "鍊炭不及炊，寶玦空自將。", "獨有黄巾寇，不入鄭公鄉。", "高賢古所貴，薄俗今可傷。"]'),
('9a665765-5878-4a85-9f2b-6eaaa49ee219','婺州傅仁贄詩求見依韻和之','陸文圭','宋','宋诗','song-poetry','','[]','髪燥始出游，心期結明主。',156,'全唐诗/poet.song.247000.json','["髪燥始出游，心期結明主。", "天方窮畸人，世不喜生語。", "絕絃恨伯牙，抱璞泣和氏。", "獨憐身皓皓，不救俗靡靡。", "競趨聲利途，孰蹈仁義軌。", "寘之勿復道，作者敦竊比。", "婺女寶氣明，箕尾德星聚。", "雜遝貢棘闈，高明識芝宇。", "鑑衡付有司，尺度失奇士。", "少需知我者，一第溷子耳。", "瓠樗嗟無用，車斗可勝數。", "老矣何能爲，欿然徒自視。", "安得善及人，共勉學爲己。"]'),
('e0c265c8-ec0c-4cb2-ad15-55eddf83e2fc','和陸振之見贈韻','陸文圭','宋','宋诗','song-poetry','','[]','我懷陶元亮，早棄彭澤令。',240,'全唐诗/poet.song.247000.json','["我懷陶元亮，早棄彭澤令。", "寧甘柴桑餓，不受宋人聘。", "晚詩題甲子，繞著義熙正。", "得書晉徵士，千載論始定。", "吾宗佳公子，世祿讓千乘。", "高眠九思齋，清節故可敬。", "寄來停雲篇，詞與意俱勝。", "耿耿好賢心，頗似緇衣鄭。", "居家未得閒，歉歲講荒政。", "良苗困螟螣，兇暴過梟獍。", "閭里不聊生，一髪寄微命。", "閉閣憂攢眉，懷哉我同姓。", "惜無勳業志，不必頻看鏡。", "吾衰畏殘暑，一雨秋意盛。", "拏舟泝流歸，帆飽風力勁。", "田蕪且莫問，但恨荒菊徑。", "明月近中秋，雲掃天宇凈。", "素蛾惜皓髪，把酒呼不應。", "何當共携手，盡此南樓興。", "效顰輒捧心，拙句酬佳詠。"]'),
('b84cab8b-267f-4139-9de3-f1aa2e06576a','和丁師善韻','陸文圭','宋','宋诗','song-poetry','','[]','轍鮒活斗升，莫向肆中索。',192,'全唐诗/poet.song.247000.json','["轍鮒活斗升，莫向肆中索。", "已無秋成望，况復歲暮迫。", "蓉城一小縣，舞袖折旋窄。", "針芒萬畝青，席卷一川白。", "苦腸真食蓼，枵腹思啖柏。", "蒙袂嗟饑氓，胠篋畏暴客。", "將懷轉壑憂，誰任求芻責。", "爲政推仁心，匹婦無弗獲。", "登途祗王命，東西固不擇。", "漢網殊闊疏，掛一直漏百。", "但令大綱正，潜使宿弊革。", "斯民本同體，難以一膜隔。", "發奸雖有術，救急豈無策。", "不憚原隰驅，要知閭里阨。", "消平蛇龍居，安集鴻雁宅。", "庶免愁歎聲，謠誦沸廣陌。"]'),
('55c0c286-ba09-47cd-9aa0-87c428dcf058','辛卯二月記異','陸文圭','宋','宋诗','song-poetry','','[]','客子遊吳中，步上姑蘇臺。',60,'全唐诗/poet.song.247000.json','["客子遊吳中，步上姑蘇臺。", "是日天雨土，四面集坌埃。", "微明日漏出，半朗風吹開。", "癡兒戲團沙，智士疑劫灰。", "天意復如此，人事信悠哉。"]'),
('05046d8d-7eb2-4a71-b0ab-0a82cf3a6c78','有感','陸文圭','宋','宋诗','song-poetry','','[]','六月南風盛，秋意雖未多。',60,'全唐诗/poet.song.247000.json','["六月南風盛，秋意雖未多。", "長養會有極，摇落將如何。", "高槐鳴衰蟬，况乃蒲與荷。", "一老坐太息，群兒笑且歌。", "笑歌恐未終，歲月已蹉跎。"]'),
('c6c8ab99-21a6-4df0-96eb-a484cf33c878','春日不出','陸文圭','宋','宋诗','song-poetry','','[]','春風不著人，微寒带微和。',72,'全唐诗/poet.song.247000.json','["春風不著人，微寒带微和。", "落梅枝上稀，桃李園中多。", "桃李尚爲容，青草被陵阿。", "時至氣自應，美惡同一科。", "無聲花蝶拍，有韻山鳥歌。", "老人閉門坐，如此景物何。"]'),
('f1669c29-deef-4109-b3fc-ba4bea863556','清明日偕趙雲壁張仲實顧伯玉張見山游分韻得好字以百家衣補之趙故嘉禾宰今爲學官坐中多及學校事','陸文圭','宋','宋诗','song-poetry','','[]','清明花亂開，今日風日好。',96,'全唐诗/poet.song.247000.json','["清明花亂開，今日風日好。", "吾得及春游，相期拾瑶草。", "城市多囂塵，客衣日杲杲。", "何時一樽酒，且試開懷抱。", "王孫丈人行，生世何用早。", "爲樂當及時，蹉跎覺年老。", "虛名復何益，棄捐勿復道。", "但願崇明德，藏身以爲寶。"]'),
('d5e6fcac-5d20-4e9b-a486-6aed2b902543','三月旦日出遊','陸文圭','宋','宋诗','song-poetry','','[]','季春已一日，寒氣猶襲人。',108,'全唐诗/poet.song.247000.json','["季春已一日，寒氣猶襲人。", "齋中偷小暇，陌上追餘春。", "金華古精廬，幾劫化微塵。", "入門何所見，修竹出牆鄰。", "迤北過崇明，殿閣何嶙峋。", "山房閉不啟，俗客來輒嗔。", "徐歸偃藤牀，息我定力勻。", "殘書了一卷，古意含酸辛。", "山芽聊止渴，起瀹石泉新。"]'),
('c00c23eb-64f5-4be1-9292-8d9926434f55','三月一日偕善之無逸遊南山桃園分韻得源字','陸文圭','宋','宋诗','song-poetry','','[]','白雲起南山，隨我度溪園。',72,'全唐诗/poet.song.247000.json','["白雲起南山，隨我度溪園。", "園丁荷鋤去，季女出應門。", "汲泉供香茗，掃石開清樽。", "人靜禽聲樂，春深花事繁。", "蛾眉映修竹，掩袂嬌欲言。", "吾親白雲外，未敢訪桃源。"]'),
('a0a50b66-1ed6-4c14-b25a-380627b63fb3','癸卯二月仲實諸人游野外飲花下得家字','陸文圭','宋','宋诗','song-poetry','','[]','散步逐芳草，小酌慰殘花。',60,'全唐诗/poet.song.247000.json','["散步逐芳草，小酌慰殘花。", "土銼野人居，茜裙蠶婦家。", "汲流澗水渾，挽樹花梢斜。", "園童貢新蔬，復邀啜杯茶。", "我興偶然盡，汝意良可嘉。"]'),
('332e4109-c9c7-4c18-b8ff-b4ad3b40316c','申港道中','陸文圭','宋','宋诗','song-poetry','','[]','兀兀乘肩輿，西風掠老鬢。',60,'全唐诗/poet.song.247000.json','["兀兀乘肩輿，西風掠老鬢。", "雲凍山色暝，水寒江聲近。", "籬根盈尺雪，晴釋纔及寸。", "人事日相酬，客路歲將盡。", "急歸掩柴門，地爐撥餘燼。"]'),
('33df938e-8816-40e4-882f-324e9d054361','茅山道中','陸文圭','宋','宋诗','song-poetry','','[]','蜿蜒西北來，土阜餘百里。',132,'全唐诗/poet.song.247000.json','["蜿蜒西北來，土阜餘百里。", "怪石聳巉岩，勢距三峰止。", "大峰東南傾，中峰伏龍起。", "綿綿亙不斷，小峰平而峙。", "名雖漢代立，山自開闢始。", "我來春雨餘，峰色有如喜。", "綠鬟光可鑑，櫛沐初出水。", "縹緲三仙人，婆娑一老子。", "情知隔凡聖，頗亦達生死。", "埋金何必問，採藥聊復爾。", "洞乳滴丹泉，手掬𠻳吾齒。"]'),
('2f208d71-fd86-4e8b-a626-b3ff49fa42a0','游崇禧觀南塢真人置酒索詩','陸文圭','宋','宋诗','song-poetry','','[]','粉牆繚而曲，轉入寶珠林。',72,'全唐诗/poet.song.247000.json','["粉牆繚而曲，轉入寶珠林。", "卷簾爐香出，竹日凈沉沉。", "天人一代師，功行夙所欽。", "掀髯顧我笑，呼酒得細斟。", "雲厨薦黄獨，飽慰饑蟲吟。", "相携鑑正室，試聽玉泉琴。"]'),
('6fef3261-7881-413e-a80e-07c9ea31396f','京口訪郭義山出示陸丞相遺墨','陸文圭','宋','宋诗','song-poetry','','[]','寶祐丙辰榜，季世尚詞章。',96,'全唐诗/poet.song.247000.json','["寶祐丙辰榜，季世尚詞章。", "功業已衰謝，氣概猶堂堂。", "壯士死海島，尤勝死雒陽。", "遺翰落人間，姓字透紙香。", "甲子行一周，復見文運昌。", "遺黎存一二，往事空茫茫。", "寒燈客窗夢，飛墮碙山洋。", "留眼看中原，且勿悲故鄉。"]'),
('e403ab4b-492a-4b5d-8bc7-8d38b255c868','渡黄河舟子作難久之乃渡','陸文圭','宋','宋诗','song-poetry','','[]','四瀆水中大，尋源河最長。',96,'全唐诗/poet.song.247000.json','["四瀆水中大，尋源河最長。", "未必通漢津，支機事荒唐。", "導流始積石，以西入要荒。", "龍門久東狹，橫潰走徐梁。", "奔流俟其定，勢可一葦航。", "我來桃源渡，渾渾流濁黄。", "艤舟不肯濟，奈此黄帽郎。", "石瀨投千金，貞女可憐傷。"]'),
('7ff4e202-7527-4c86-a8f2-a2703ddbef28','宿遷道中遇雪','陸文圭','宋','宋诗','song-poetry','','["\u5199\u96ea", "\u96ea"]','登車宿遷北，萬頃鋪瓊田。',60,'全唐诗/poet.song.247000.json','["登車宿遷北，萬頃鋪瓊田。", "黑雲湛水光，上下玻璃天。", "六花時時飄，集我車上氈。", "左右拍手笑，翁似白鶴仙。", "失却翁白髯，頓覺翁少年。"]'),
('99a69621-5491-4e7f-8e5d-06fe0a9f5428','入杭苦雪二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','雪天無晨昏，尤難辨西東。',60,'全唐诗/poet.song.247000.json','["雪天無晨昏，尤難辨西東。", "高低賦萬象，偶爾一色同。", "會臯日與月，終愁雨兼風。", "居人掩關卧，况乃逆旅中。", "買薪呼斗酒，黧頰生微紅。"]'),
('23cc8044-e654-4e3c-9da1-69227fcad39a','入杭苦雪二首  其二','陸文圭','宋','宋诗','song-poetry','','["\u897f\u6e56"]','年年西湖上，梅柳得春多。',60,'全唐诗/poet.song.247000.json','["年年西湖上，梅柳得春多。", "新正十日雪，重陰壓微和。", "皓潔混泥途，輕盈赴寒波。", "危橋馿失脚，不如坐吟哦。", "推窗無傑句，奈此玉峰何。"]'),
('03e0cee0-10f9-440d-a43a-91ec8757add0','至元重光單閼之歲春正月隴西郡太夫人介壽八十子侍郎帥其昆弟子姪內外姻族寮友賓客奉觴上壽如儀州人士相與嘉歎爭爲歌詩詠其事而繡使紫山胡公爲之序云','陸文圭','宋','宋诗','song-poetry','','[]','斷機碎錦纈，短髻剪青絲。',180,'全唐诗/poet.song.247000.json','["斷機碎錦纈，短髻剪青絲。", "殷勤謝師友，老婦得佳兒。", "長宦客四方，鶴髪在高堂。", "安得凌風翼，高飛至母傍。", "春暉不可報，萱草日日長。", "今夕知何夕，門有車馬跡。", "堂下羅鐘鼓，堂上合賓客。", "春風吹綠酒，起舞兒獻壽。", "客問年幾何，舊歲七十九。", "此去三千年，蟠桃始開花。", "花開又結實，瑶池度歲華。", "客起再拜言，遺核幸分甘。", "小人亦有母，八十又加三。", "核中有瓊漿，飲之勝啜菽。", "懷歸滿袖香，仙霞燭幽谷。"]'),
('63ba7039-4623-4569-8766-8d0148f2b024','壽理伯雍同知','陸文圭','宋','宋诗','song-poetry','','[]','理侯人之父，亦復兼母慈。',120,'全唐诗/poet.song.247000.json','["理侯人之父，亦復兼母慈。", "束吏如頑奴，煦民猶嬰兒。", "闖門無雜賓，鈴下生蛛絲。", "內聞讀書聲，日晏忘晨炊。", "上馬出署事，坐看棠陰移。", "人靜報休衙，閉閣方退思。", "廷中相戒言，慎勿干以私。", "但祝公百歲，長爲良吏師。", "公言撫字勞，良吏安可爲。", "方當上印綬，自與赤松期。"]'),
('dcd9ea19-eb56-4088-9640-647da4f0b1ce','壽李仲明同知','陸文圭','宋','宋诗','song-poetry','','[]','新息父賈彪，南陽母杜詩。',132,'全唐诗/poet.song.247000.json','["新息父賈彪，南陽母杜詩。", "束吏如官奴，護民如嬰兒。", "李侯妙政術，千古同襟期。", "高寒月半弓，清粹玉一規。", "掘菜朝爲虀，脫粟暮作糜。", "但聞讀書聲，不聞兒啼饑。", "褚衣敝再浣，櫪馬瘦莫騎。", "今朝侯生辰，父老持酒巵。", "厨傳寂如水，不知侯所之。", "介壽古有言，此意亦復辭。", "獨立古梅下，遥赴天仙期。"]'),
('518d6110-c800-42b0-9a9c-62e9c6f97ca5','庚寅臘月二十九日餞孫晉卿宿清孝里晨起呈岩隠','陸文圭','宋','宋诗','song-poetry','','[]','驅馬四十里，悵然臨別情。',72,'全唐诗/poet.song.247000.json','["驅馬四十里，悵然臨別情。", "舉酒坐太息，歲月空崢嶸。", "河流日浩浩，此地幾送迎。", "老我白板扉，卿等致太平。", "窗風吹酒醒，起視天未明。", "小星爭餘光，殘月西南傾。"]'),
('77204133-26a9-4205-a8b2-ab44c71ab597','皆山樓分韻得坐字','陸文圭','宋','宋诗','song-poetry','','[]','無詩山不喜，無樓猶自可。',72,'全唐诗/poet.song.247000.json','["無詩山不喜，無樓猶自可。", "樓上著詩人，青山皆屬我。", "得句山禽鳴，落筆山花墮。", "翠屏招我隠，欲往輒不果。", "推窗呼與飲，醉吸雲一朵。", "須臾成五采，吐出驚滿坐。"]'),
('21d7db7c-1ee4-4904-80c4-1059284de193','爲劉君符賦樂山詩','陸文圭','宋','宋诗','song-poetry','','[]','山體本至靜，仁體亦如之。',132,'全唐诗/poet.song.247000.json','["山體本至靜，仁體亦如之。", "樂者有深味，魯論無費辭。", "目玩唯自得，心契若有期。", "逝川同一旨，妙理無容窺。", "劉公本好古，雅志非好奇。", "諸君爲著語，殆類愛山詩。", "泉石涵清思，松柏媚幽姿。", "古來山中人，此道未必知。", "蠟屐毋乃癖，拄笏殆成癡。", "獨有首陽高，薇苦甘如飴。", "得仁即無怨，千載真吾師。"]'),
('daa9e440-64e2-4836-844c-345e30d10a13','壬辰端陽後一日會潜齋以竹深留客處荷凈納凉時分韻得凈字','陸文圭','宋','宋诗','song-poetry','','[]','日透朱櫻明，雨拭白蓮凈。',48,'全唐诗/poet.song.247000.json','["日透朱櫻明，雨拭白蓮凈。", "布席開清樽，授簡遞新詠。", "謀樂須及時，養拙聊適性。", "傳聞度遼師，鎧甲冒暑盛。"]'),
('6e495b70-29a7-42c0-99e3-e1d1cfd64514','贈劉宗道自金陵來遊茅峰','陸文圭','宋','宋诗','song-poetry','','[]','君家汴水陽，弔古游秣陵。',108,'全唐诗/poet.song.247000.json','["君家汴水陽，弔古游秣陵。", "秦淮映江月，歷代幾廢興。", "古人所樹立，今人愧未能。", "嗟我搔白髪，空齋對書燈。", "邂逅接餘論，談笑得良朋。", "我如蜩與鳩，睨鯤化爲鵬。", "歲晏落蓬蒿，安得齊飛騰。", "東望積金峰，春遊記吾曾。", "鶴仙遲子來，丹井𠻳寒冰。"]'),
('3df53e35-fbb2-435c-a4c4-d57b079bfa40','贈翟良甫洛人南遊','陸文圭','宋','宋诗','song-poetry','','[]','溫洛天地中，父老升平年。',132,'全唐诗/poet.song.247000.json','["溫洛天地中，父老升平年。", "清游盤石坐，醒酒落花眠。", "勝地已陳迹，故事空遺編。", "銅駝泣秋雨，禍機始杜鵑。", "耆英日凋謝，嵩少無人烟。", "懷古笑我迂，慕學嗟子賢。", "購書或千金，卧榻餘一氈。", "低頭肯揖吏，閉口不言錢。", "情已寄丘壑，足猶履山川。", "駕言遠尋師，胡爲近捨旃。", "煌煌邵程業，百世誰能傳。"]'),
('133bb40f-31be-4832-bc08-36e7eb924d4a','贈柯山夏梅月','陸文圭','宋','宋诗','song-poetry','','[]','五星配五行，占法具春秋。',288,'全唐诗/poet.song.247000.json','["五星配五行，占法具春秋。", "參以四暗耀，不知始所由。", "經緯十二辰，一國係一州。", "三河即豫地，係宋復係周。", "晉自居太原，衛本都帝丘。", "借問益與并，古有二國不。", "三晉俱屬冀，韓衛不見收。", "嘗以扣日者，不語輒掉頭。", "渠未通古今，敢問儒者流。", "氣化互生尅，躔度有遲留。", "因之別貴賤，庶人與王侯。", "既云命在天，何以身不修。", "經籍古格言，較此殊不侔。", "殃慶有所積，禍福皆自求。", "理數各一家，二家果孰優。", "論數每多驗，言理或不售。", "忠信人爵從，孟軻老於鄒。", "仁者必有壽，牖下死伯牛。", "殺人取印綬，嬖主乘軒輶。", "將貂續狗尾，以冠加沐猴。", "市朝日洶洶，乾坤意悠悠。", "璇穹列高真，星月侍宸游。", "朝裾曳明霞，從珮鳴蒼璆。", "居然視世濁，不肯分天憂。"]'),
('5693bf81-f375-4bb2-ba40-1a8e5f034bf7','贈季清隠道人','陸文圭','宋','宋诗','song-poetry','','[]','虞山摴西城，尚湖繞其趾。',204,'全唐诗/poet.song.247000.json','["虞山摴西城，尚湖繞其趾。", "青屏照玉鏡，屈摺十八里。", "傳聞漢真人，丹成飛入水。", "到今水不腥，魚鱉長而美。", "往年山中人，夜半忽驚起。", "神鋒閃烈電，爍爍光不已。", "平明斸山骨，石函半鑱毀。", "土花蝕蒼龍，歲月不可紀。", "玄靈啟幽秘，結構此經始。", "雲香染衣佩，嵐翠襲巾履。", "道人方晏坐，秋葉打窗紙。", "西風送詩句，吹入千岩裏。", "收拾費工夫，遠來將舉似。", "見叟却忘言，爐烟生棐几。", "徐云乘興出，興盡行當止。", "山中有緣事，比欲相料理。", "白鶴數日饑，吾今且歸耳。"]'),
('ed1bc2fe-86a8-4624-a78c-74d947a1d7ca','贈筆生楊日新','陸文圭','宋','宋诗','song-poetry','','[]','雪屋夜明寒，引紙一長吁。',108,'全唐诗/poet.song.247000.json','["雪屋夜明寒，引紙一長吁。", "貧無食肉相，頗悔身業儒。", "晨出生謁入，被褐而長鬚。", "穎脫殊可喜，文翰定自娛。", "自言中山徒，常與陳玄俱。", "醉曾揮草聖，閒或寫桃符。", "最愛王逸少，勉隨劉寄奴。", "嗟生不自惜，貌澤神亦枯。", "世多宏肇輩，幸我非二蘇。"]'),
('297be037-e75c-447e-a190-874e31015cf8','贈筆生林君實','陸文圭','宋','宋诗','song-poetry','','[]','我愛古人巧，創物揜前聞。',120,'全唐诗/poet.song.247000.json','["我愛古人巧，創物揜前聞。", "遐哉蒼頡氏，頼此蒙將軍。", "將軍絕地脈，乃解開人文。", "模寫不得力，制作空云云。", "祇今千載下，藝圃專策勳。", "貶黜毛錐子，褒進中書君。", "工拙無定在，好惡有殊分。", "老我翻墨瀋，落紙無煙雲。", "有生來被褐，倩客試書裙。", "雙金慚報贈，隻字寄殷勤。"]'),
('756b42db-b13f-4b81-9dd1-8c60dfddcba6','題宋學古九天玄女數自云其師鍾堯臣得之襄城柳下老翁所授','陸文圭','宋','宋诗','song-poetry','','[]','天九積陽數，玄女夫何爲。',108,'全唐诗/poet.song.247000.json','["天九積陽數，玄女夫何爲。", "廣陵亦健將，乃惑一用之。", "彼術信誕謾，此遇尤希奇。", "珍重柳下翁，仙隠未可知。", "言天以人證，言數以理推。", "守正死不避，居貞凶可移。", "堯富與堯壽，此理始無私。", "顔貧與顔夭，此性終無虧。", "姑慎君子術，勿與老人期。"]'),
('39d4d04e-eda4-46d6-9b5e-47cd9bb209d4','別李宰','陸文圭','宋','宋诗','song-poetry','','[]','句曲一山縣，東西俱百里。',192,'全唐诗/poet.song.247000.json','["句曲一山縣，東西俱百里。", "三茅地有靈，出宰多才美。", "前有趙與謝，今有程與李。", "李爲山東望，聲價高莫比。", "清明一古鏡，冷浸玉泉裏。", "敏哉製錦手，洗却鳴琴耳。", "仁心非邀譽，直道不容毀。", "慈姁牧細民，謙撝揖多士。", "學館盛文風，講席究經旨。", "有客東北來，空齋兀書几。", "彈鋏笑馮驩，下榻慚孺子。", "樂雖足一瓢，飽不望四簋。", "既爲邑之氓，是亦吾所耻。", "饑餓欲賙之，餽蒱斯受已。", "將歸重回首，决去負知己。", "冉冉楚山雲，悠悠斷江水。"]'),
('aed73693-4892-493e-babd-d801b6b20cdf','留別義塾諸公','陸文圭','宋','宋诗','song-poetry','','[]','婆娑七十翁，已矣將焉求。',132,'全唐诗/poet.song.247000.json','["婆娑七十翁，已矣將焉求。", "麋鹿違本性，一朝出林丘。", "故園在何許，駕言東南游。", "人才盛吳會，講貫多儒流。", "內顧衰朽質，汙渠映清溝。", "坐有歌驪駒，將貽識者羞。", "溽暑困朱夏，偃息時歸休。", "南窗小容膝，卧對紅葵榴。", "年華不我待，青鏡照白頭。", "祇今已後死，巨海吹浮漚。", "諸君幸少壯，勗學追前修。"]'),
('9dd46aa2-db35-4f52-aab0-645e599c331f','寄申屠御史','陸文圭','宋','宋诗','song-poetry','','[]','御史帝耳目，監察沿隋唐。',228,'全唐诗/poet.song.247000.json','["御史帝耳目，監察沿隋唐。", "臺閣迥清風，筆簡凌秋霜。", "澄清一攬轡，驅狸走豺狼。", "賢哉故安侯，廉介尤剛方。", "閉門杜私謁，上殿肅朝綱。", "今侯有祖風，學術尤章章。", "出擁簿書塵，入薰書傳香。", "胸襟漢石渠，人物魯靈光。", "終然百鷙鶚，不及一鸞凰。", "奉國信孜孜，問塗何皇皇。", "往歲金陵轍，前年古浙航。", "鳴犢有餘哀，河水空洋洋。", "行役山川苦，歸興桑麻長。", "廣陵挹雄勝，平山弔凄凉。", "瘦馬乏芻櫪，寒妾無帛囊。", "家瘠道愈肥，躬瘁名逾芳。", "昔在東都季，憸佞沉忠良。", "知幾獨子龍，絕迹棲梁碭。", "瞻烏止誰屋，亦復可憐傷。"]'),
('e09868eb-632a-4721-967e-328490082cfd','寄錄事王君玉','陸文圭','宋','宋诗','song-poetry','','[]','風沙瞇行人，日脚黄無光。',156,'全唐诗/poet.song.247000.json','["風沙瞇行人，日脚黄無光。", "愁鴟蹲古木，凍雁拾餘糧。", "荒城雞犬寂，古堠荆蒿長。", "瘦馬兀冰塗，龍塞天一方。", "今晨發申浦，何日抵漁陽。", "道傍轉徙氓，啼哭勢倉黄。", "惰游散不歸，信美非吾鄉。", "錦衣雖云樂，無褐可憐傷。", "南泝江悠悠，北視天茫茫。", "遠煩公護視，雨雪上河梁。", "從事豈獨賢，簡書詎能忘。", "嗟爾居者逸，擁氈坐高堂。", "且置勿復道，擊筑飲離觴。"]'),
('a713c1b0-3937-4903-b822-0c61267a17ca','送周宣差除陝西廉訪僉事','陸文圭','宋','宋诗','song-poetry','','[]','昔人比貴宦，綉錦以爲衣。',96,'全唐诗/poet.song.247000.json','["昔人比貴宦，綉錦以爲衣。", "當晝與夜行，故鄉歸不歸。", "每評會稽章，不及相州記。", "公今往三秦，身是綉衣使。", "玉衡直而平，寶瑟和而清。", "當知九州外，生此千人英。", "南人去勿悲，西人來勿喜。", "明年當入覲，垂紳佐天子。"]'),
('59eda576-4d74-4248-80c1-d3ae0b02d66f','送陸同知北上二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','浙尾带荒江，土與材俱薄。',288,'全唐诗/poet.song.247000.json','["浙尾带荒江，土與材俱薄。", "吳季獨終隠，楚黄亦晚錯。", "餘子不足數，眼明見卓落。", "騄駬初歷塊，青萍新淬鍔。", "齒少逾老心，事邇存遠略。", "百金重氣義，千里赴言諾。", "可期功名會，兼受生死託。", "宦途入幽薊，詩句留殿閣。", "出佐紫陽城，一麾真小却。", "炳燭照吏奸，良劑痊民瘼。", "一庭秋水凈，萬戶春風樂。", "河內泣留恂，并州永思郭。", "歸裝乍林丘，趣騎已沙漠。", "梅花古驛寒，別酒故人酌。", "徑北道邳徐，迂西趨汴洛。", "宮闕臯盛麗，山川想寥廓。", "成臯歎楚戰，砥柱窺禹鑿。", "舊邦弔二虢，古邑辨三亳。", "望諸墓猶存，戲馬臺如昨。", "燕趙誇蛾眉，雲代珍狐貉。", "壯士多屠沽，逸人或岩壑。", "訪古記宜勒，登高賦須作。", "訂訛青簡在，得句錦囊著。", "明年衣繡歸，頗願聞其略。"]'),
('9f0a9a6a-e081-4894-85d9-a6173feb9ede','送陸同知北上二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','淳風日已薄，恩義不相維。',120,'全唐诗/poet.song.247000.json','["淳風日已薄，恩義不相維。", "吏無得於民，民顧吏有辭。", "政化本不立，刀筆事愈卑。", "李侯今之人，而行古所爲。", "外有屠嘉直，內無五倫私。", "鋤奸如惡草，護民猶嬰兒。", "瀹河甦彼旱，勸粟哺爾饑。", "從容方報政，代者俄及期。", "庸吏推不去，良吏去復思。", "誰歟觀民風，入境採吾詩。"]'),
('f6625189-1847-44d4-9714-8ce1ede988b2','送郝仲明代歸','陸文圭','宋','宋诗','song-poetry','','[]','古之州縣吏，久任各稱職。',120,'全唐诗/poet.song.247000.json','["古之州縣吏，久任各稱職。", "任久則化行，吏與民相得。", "民或不安業，咎在吏數易。", "代者如傳舍，吏民不相識。", "王嘉朱浮疏，每讀三太息。", "暨城有賢佐，溫良而端直。", "爲政知大體，人方飲其德。", "瓜猶未及期，旌已催行色。", "中州固多士，此士去可惜。", "老稚候城隅，相邀卧車側。"]'),
('7e81dcc7-46a9-49f9-bc76-d3672371f2e9','送葉仲實赴鹽官州判','陸文圭','宋','宋诗','song-poetry','','[]','我舟餘杭遊，君馬薊北驟。',60,'全唐诗/poet.song.247000.json','["我舟餘杭遊，君馬薊北驟。", "我衣素染塵，君衣錦炫晝。", "江湖著閒散，郡國需雋茂。", "才高真小試，儒腐乃大繆。", "鞭讓祖生先，策甘之反後。"]'),
('35d292f0-0c33-4dc4-aec8-4a75656832b7','送王安之無錫州判','陸文圭','宋','宋诗','song-poetry','','[]','龍峰鄰吾州，赤子久失乳。',108,'全唐诗/poet.song.247000.json','["龍峰鄰吾州，赤子久失乳。", "或加手斵削，誰肯頂摩拊。", "有客來嘉禾，談我讀書塢。", "口稱王侯賢，可配循吏古。", "廉不受私謁，公不畏强禦。", "素秋下嚴霜，陽春沃膏雨。", "澤國鱸正肥，山泉茗尤苦。", "州縣徒勞人，揚歷安足數。", "莫思金带橫，長學彩衣舞。"]'),
('59571495-7e60-4931-8d3f-4858c0daf11c','送宋春卿之官湘陰','陸文圭','宋','宋诗','song-poetry','','[]','乾霜落丹楓，潮水清且淺。',60,'全唐诗/poet.song.247000.json','["乾霜落丹楓，潮水清且淺。", "雅志君山高，離思湘江晚。", "利名登津要，孤介分疏遠。", "來暮彼雖嗟，去思此難挽。", "何當升臺端，繡斧煩臨遣。"]'),
('5089d06c-b6f8-4e8b-8e77-53822e2a4c92','送顧伯玉麻陽簿','陸文圭','宋','宋诗','song-poetry','','[]','放州清江閘，及此新雨凉。',72,'全唐诗/poet.song.247000.json','["放州清江閘，及此新雨凉。", "故人得邂逅，好語傾肺腸。", "惜哉廊廟器，漂泊落湖湘。", "前途阻勳業，末技呈詞章。", "營營百年短，浩浩萬古長。", "共惜天下寶，得志無相忘。"]'),
('758930e6-1106-452b-9bed-93ff33afb57e','送陳茂卿赴興國教授','陸文圭','宋','宋诗','song-poetry','','[]','彭城陳師道，三州一學官。',180,'全唐诗/poet.song.247000.json','["彭城陳師道，三州一學官。", "高文曾蘇敬，偉節章趙歎。", "百世有斯人，嫡孫承後山。", "君材中梓漆，壤錯榛與菅。", "藻芹味苦淡，輒當粱肉餐。", "莫終三釜養，竟墮一氈寒。", "榮枯數前定，出處身兩難。", "腐鼠或青冥，枳棘棲孔鸞。", "升高足易蹶，恬處寢亦安。", "逆君散花洲，西上捲雪灘。", "臯比第一義，子佩正聚觀。", "士方從北學，音已變南冠。", "俎豆器疑朴，詩書味轉酸。", "何人力不變，此道獨追還。", "金溪有陸叟，昔仕乾淳間。"]'),
('24e7f83b-a25d-448d-b834-86f11860a180','送焦君實之采石學官','陸文圭','宋','宋诗','song-poetry','','[]','江水日以遠，山花日又新。',120,'全唐诗/poet.song.247000.json','["江水日以遠，山花日又新。", "先吾不復少，後我皆成人。", "之子如良金，出礦以精純。", "又如山中木，始遇雪發春。", "送子啟長途，跋子升華津。", "青雲題柱客，白髪倚閭親。", "有志皆騰逸，非才獨隠淪。", "山林雙鬢古，井臼一生貧。", "宇宙無窮事，行藏各自身。", "因風傳短句，望月弔詞臣。"]'),
('cc34e288-1e2d-4f66-bb13-1db3f6c58938','送王行可赴宣城學官','陸文圭','宋','宋诗','song-poetry','','[]','閉關坐十年，扣門得一士。',108,'全唐诗/poet.song.247000.json','["閉關坐十年，扣門得一士。", "自言貧爲養，非謂學優仕。", "執手問何之，贈言聊復爾。", "清溪生芹藻，流入泮宮水。", "先令我清心，次令人潔己。", "鑄金師範巧，琢玉士習美。", "六經懸日月，顔孟元不死。", "君欲從之遊，青燈茅屋底。", "相逢莫相問，擾擾鼓篋子。"]'),
('0d428190-c8b0-49b3-9228-242b27eb826e','送嚴陵邵叔忠學錄歸侍二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','薄官如秋菰，冷淡不堪食。',72,'全唐诗/poet.song.247000.json','["薄官如秋菰，冷淡不堪食。", "學宮如傳舍，敝漏棲不得。", "訪君橋水東，一榻可容膝。", "中吳多佳士，三載誰與適。", "可憐泮林鴞，止醉桑葚黑。", "束書歸去來，釣臺秋風夕。"]'),
('ffac728f-91a4-4386-bfb9-71516be911b3','送嚴陵邵叔忠學錄歸侍二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','黄甲舊書生，明廷推一鶚。',60,'全唐诗/poet.song.247000.json','["黄甲舊書生，明廷推一鶚。", "歲莫戢羽翰，靜聽華亭鶴。", "盛衰今昔異，出處老少各。", "乃翁信奇士，之子亦不惡。", "斥鷃伏卑枝，寄聲謝寥廓。"]'),
('f63c1d5a-48ac-44ce-b235-6bc609409e92','送華仲實譯史入京','陸文圭','宋','宋诗','song-poetry','','[]','蒼頡何代人，後乃有冰斯。',96,'全唐诗/poet.song.247000.json','["蒼頡何代人，後乃有冰斯。", "智者能創物，此理不復疑。", "國朝重文字，設官如經師。", "君才實楚産，北學尤恢奇。", "冥鴻登翰音，威鳳呈羽儀。", "青雲睨子貴，皓首笑吾衰。", "尚白玄空守，飛黄勢莫追。", "祖行遲出郭，東畎正耘耔。"]'),
('15092d40-65b6-4aaf-aa27-df70b00e533d','送吳仲寶入京','陸文圭','宋','宋诗','song-poetry','','[]','余年長汝父，汝季復余從。',96,'全唐诗/poet.song.247000.json','["余年長汝父，汝季復余從。", "季也難爲兄，文史日從容。", "兄也實競爽，立身期亢宗。", "可念玉雪子，五月上盧龍。", "棗榆曝西日，塵土吹炎風。", "爾欲副爾志，安得寧爾躬。", "有方遊可遠，揚名孝乃終。", "歸來拜嘉慶，我酌壽汝翁。"]'),
('42698930-c138-49cf-81fb-ce7689060899','送趙季舒之燕','陸文圭','宋','宋诗','song-poetry','','[]','有客東南來，白馬嘶北風。',48,'全唐诗/poet.song.247000.json','["有客東南來，白馬嘶北風。", "問客將何之，舉鞭指盧龍。", "云是漢家子，出入明光宮。", "古宮今焉在，廢堵生秋蓬。"]'),
('68c3e5f4-5af9-4f32-9d9a-c197072ab1fc','送道成北遊','陸文圭','宋','宋诗','song-poetry','','[]','從游十載前，總角君尚少。',84,'全唐诗/poet.song.247000.json','["從游十載前，總角君尚少。", "相逢十載後，我鬢雪爭曜。", "修鱗縱巨壑，倦羽落荒嶠。", "盛衰各自異，巧拙更相誚。", "義理浩無涯，經綸孰知要。", "立身如處女，被服善窈窕。", "止令公子慕，莫博千金笑。"]'),
('d96fa027-b2e5-481a-b197-9c14825e7e2c','送錢君瑜歸嘉禾','陸文圭','宋','宋诗','song-poetry','','[]','海東有孤鶴，玉羽青冥間。',108,'全唐诗/poet.song.247000.json','["海東有孤鶴，玉羽青冥間。", "衝風揚黄塵，吹落蓉城山。", "蓉城何寥廓，山木多高寒。", "石泉翳荒蘚，飲啄常苦艱。", "矯首復南飛，凉秋生羽翰。", "願隨鴻鵠游，不共雞鶩餐。", "嗟爾不群志，全身良獨難。", "遠避鷹與鸇，近防弋與彈。", "仙機縱不誤，雲路終漫漫。"]'),
('078cda33-1231-4f6e-bb74-9df41115d387','送輔若晦南遊','陸文圭','宋','宋诗','song-poetry','','[]','天令中和春，錦花柳絲織。',96,'全唐诗/poet.song.247000.json','["天令中和春，錦花柳絲織。", "江山回淑氣，車馬有行色。", "問君今何之，白髪在高堂。", "韔弓箙兩矢，出門志四方。", "丈夫信有志，遊近不堪遠。", "錫穴綆冷泉，館娃弔荒畹。", "青青三吳道，急雨飄客衣。", "縱無譏小草，恐有遺當歸。"]'),
('3ceb88a1-7dce-4a21-b70e-0978de193595','送袁仲野赴毘陵','陸文圭','宋','宋诗','song-poetry','','[]','儒吏不相得，異器如薰蕕。',168,'全唐诗/poet.song.247000.json','["儒吏不相得，異器如薰蕕。", "儒視吏不屑，吏嫉儒爲仇。", "俗儒不知變，譊譊孔與周。", "事叢委不理，言大怍不酬。", "嗟乎鉛槧生，謝此刀筆流。", "安得經濟手，一洗吾儕羞。", "當路有達官，鄰境逢仁侯。", "留情案牘間，舉人拔其尤。", "君抱汲古學，才識推兼優。", "肯隨雞鶩爭，會偕鸞鵠游。", "高風動寥廓，茲土豈淹留。", "獨憐老知己，青燈守荒丘。", "不堪明時用，空懷當世憂。", "斯文付後死，已矣復焉求。"]'),
('831e9a7f-b001-4799-ae09-17060bcb32de','送黄雲心游松江','陸文圭','宋','宋诗','song-poetry','','[]','吾宗兩才子，世亂身不免。',48,'全唐诗/poet.song.247000.json','["吾宗兩才子，世亂身不免。", "絕憐華亭鶴，竟類東門犬。", "客行因弔古，寒日下荒坂。", "井邑今豪雄，往事海濤遠。"]'),
('486a66cf-e39f-4a5a-90f8-e71cb78218e7','送陳公南之松江并柬山齋','陸文圭','宋','宋诗','song-poetry','','[]','我衰惜別離，數日輒作惡。',96,'全唐诗/poet.song.247000.json','["我衰惜別離，數日輒作惡。", "老懷自當爾，嘗恐兒輩覺。", "君器如璠璵，似可寘臺閣。", "莫辭簿書苦，亦有宦游樂。", "久厭黄田魚，去聽華亭鶴。", "亭下有高士，滴露草玄學。", "持詩道甫訊，進拜復前却。", "問我今何如，癡頑勝如昨。"]'),
('4cfebc05-fa8c-4831-92f8-5989c7bd840d','古意二首送朱鶴皋  其一','陸文圭','宋','宋诗','song-poetry','','[]','雁蕩英英雲，孤鳳雲中吟。',60,'全唐诗/poet.song.247000.json','["雁蕩英英雲，孤鳳雲中吟。", "風吹五色羽，墮此半水林。", "桐花作秋枯，野桑空綠沉。", "苦葚不致醉，鴞食予何心。", "鳳兮歸去來，岐山有高岑。"]'),
('e545c9b8-8af0-4c72-8a2c-5b5b701cda7c','古意二首送朱鶴皋  其二','陸文圭','宋','宋诗','song-poetry','','[]','蓬首寒機女，枉顧生光輝。',84,'全唐诗/poet.song.247000.json','["蓬首寒機女，枉顧生光輝。", "一登君子堂，松蘿相因依。", "茂陵喜新聘，中路忽有違。", "願垂堂上鏡，照妾心中微。", "生死要有託，悠悠空是非。", "出門念遠道，歲晏將安歸。", "膏沐更誰容，爲君疊羅衣。"]'),
('fb3d81f7-9576-4ba4-9863-a3e8dcd49b7c','送陳子高','陸文圭','宋','宋诗','song-poetry','','[]','稜稜玉壺冰，瑩潔絕纖罅。',48,'全唐诗/poet.song.247000.json','["稜稜玉壺冰，瑩潔絕纖罅。", "無人手自將，寘之霜臺下。", "海東聞鶴唳，清思方在野。", "遲明有公事，匆匆催上馬。"]'),
('7353a900-3019-40ab-86bb-5504b7524393','送吳寬齋併謝惠詩','陸文圭','宋','宋诗','song-poetry','','[]','衰年八十一，草露骨垂朽。',120,'全唐诗/poet.song.247000.json','["衰年八十一，草露骨垂朽。", "有客款荆扉，甘言許吾壽。", "假如活百歲，祇欠十有九。", "辛勤拋書冊，散誕耽棋酒。", "時時課小詩，不自覺妍醜。", "袖中出新句，見客驚欲走。", "反顧仍疾讀，佳處輒肯首。", "呼兒急傳觴，晚喜得此友。", "久之來告別，秋懷掛衰柳。", "百金無所贈，五言聊藉手。"]'),
('60159a9d-26a9-45a1-96b3-b8665a484ff7','送天台陳審中','陸文圭','宋','宋诗','song-poetry','','[]','陳爲台望族，不數謝與錢。',144,'全唐诗/poet.song.247000.json','["陳爲台望族，不數謝與錢。", "此以科甲貴，彼以婚姻連。", "吾猶及乃祖，執鞭慕先賢。", "亂後識嚴君，握手吾同年。", "事功竟落落，世慮日日煎。", "衣冠一不振，抱恨埋重泉。", "君如丹鳳雛，五采何翩翩。", "久客滄江上，窮秋思浩然。", "文運今再明，六甲一周天。", "老我終白屋，看子收青氈。", "浙水東西流，北風送南船。", "赤城幾日到，雁影夕陽邊。"]'),
('5b0d6c2b-6ce7-48e6-bfa3-b6ea5705629e','送楊伯可','陸文圭','宋','宋诗','song-poetry','','[]','齊魯多平原，江浙田高下。',228,'全唐诗/poet.song.247000.json','["齊魯多平原，江浙田高下。", "戢戢如魚鱗，土籍誰主者。", "富人擅其利，失業憫孤寡。", "方今用周禮，天官出經野。", "古法雖可行，必得奉行者。", "楊君古循良，暨陽小民社。", "原隰遍咨詢，辭色每寬假。", "經營始不擾，期集乃多暇。", "實惠甦困窮，先聲走豪霸。", "隴牛閒卧晝，邑犬不驚夜。", "當年經行處，愛此憩棠舍。", "鳩功首上計，列郡居其下。", "傾城出送君，饑童控羸馬。", "坐中有狂生，出位獨難咤。", "均爲受廛氓，關市不親稼。", "鄉胥上下手，輕重意取捨。", "仁公力救弊，立法宜少借。", "聖朝天廣大，焉用究纖罅。", "議政罪甘誅，矧避官長駡。"]'),
('3bfceb72-a26d-4bf3-9335-2025f757c9e2','送張仲實','陸文圭','宋','宋诗','song-poetry','','[]','持斧上東山，伐木鳥群呼。',108,'全唐诗/poet.song.247000.json','["持斧上東山，伐木鳥群呼。", "道義不相敦，朋友良可無。", "嗟我聚糠粃，從君味膏腴。", "方轡蹈先軌，聯綬趨正塗。", "事功期遠致，詩翰亦小娛。", "但令交久長，不恨別須臾。", "歲律陰崢嶸，客程路盤紆。", "人事况寡歡，月異時復殊。", "疏梅憶孤嶼，新柳懷清湖。"]'),
('f7147ec6-9945-4411-9691-978fa4b9aeb3','送師本竹','陸文圭','宋','宋诗','song-poetry','','[]','魯國幾男子，陋巷稱顔淵。',156,'全唐诗/poet.song.247000.json','["魯國幾男子，陋巷稱顔淵。", "簞食何從出，頼有負郭田。", "養志本無求，求人志可憐。", "蜀翁古奇士，束書裹寒氈。", "客來擁氈坐，客去挾書眠。", "索供廣文飯，催送司業錢。", "玉瓶何處酒，翠釜誰家烟。", "我乃遭數奇，彼胡鍾美偏。", "厄窮不自憫，靜退猶爲賢。", "揖士撤講席，呼兒買歸船。", "後游記何日，今別已高年。", "感翁出處跡，撫几心茫然。", "握手出門去，梅雨暗江天。"]'),
('efa90f4b-b4e3-48ec-a9a0-994e1d14f7d2','送徐允伯','陸文圭','宋','宋诗','song-poetry','','[]','古有淳寂鄉，君與陶阮到。',228,'全唐诗/poet.song.247000.json','["古有淳寂鄉，君與陶阮到。", "每評伯倫頌，謂勝周公誥。", "山間童負鍤，臺下人拾帽。", "短鞭跨遼碣，破毯眠雪窖。", "歸來四壁立，挾冊坐鄉校。", "悠悠泮宮水，羹有芹可芼。", "案上方醉吟，室中已饑告。", "長缾卧虛簷，破釜架空竈。", "翠眉方與齊，赬頰忽自悼。", "愁踏布衾裂，羞拆海圖倒。", "先生樂陶然，美睡呼不覺。", "達士多迂拙，庸兒競嘲噪。", "豈知海上鯤，姑隠霧中豹。", "歲晚空齋人，杖屨辱相好。", "百錢呼兒沽，一榻爲君掃。", "浩興忽長歌，衰意亦旁譟。", "銜杯孤月落，椎壁四鄰閙。", "明當遠行役，寒雨映客棹。", "秋江蒲稗深，佇子平安報。"]'),
('e97bd95c-067e-4e87-b80b-eb0abffa98c5','徐觀伯遠將徙海陵介吾姪來索詩徐故家兵後流落三十年長子依許監倉客淮南因贅于海陵迎二親就養坡公謂此事今無古或聞者也感歎之餘爲賦二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','甲與吾同生，君子行一周。',84,'全唐诗/poet.song.247000.json','["甲與吾同生，君子行一周。", "少年各豐裕，歲晚懷百憂。", "菜地古城下，我今手鋤耰。", "君當往海陵，絕江汎漁舟。", "駕言彼就養，逝將老菟裘。", "哀哉隨陽雁，止爲稻粱謀。", "君看橫江隼，萬里凌高秋。"]'),
('699486b4-217b-4d9f-b2ec-e9c56c122039','徐觀伯遠將徙海陵介吾姪來索詩徐故家兵後流落三十年長子依許監倉客淮南因贅于海陵迎二親就養坡公謂此事今無古或聞者也感歎之餘爲賦二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','慈烏昔哺雛，日夜望雛長。',84,'全唐诗/poet.song.247000.json','["慈烏昔哺雛，日夜望雛長。", "安知風雨橫，故巢墮草莽。", "烏羽日摧頹，雛饑竟何往。", "其一止海隅，雌飛鳴相向。", "反哺若天性，迎烏致其養。", "我衰髪盡白，兒長忽先喪。", "贈君慈烏篇，老淚滴紙上。"]'),
('6a868c6a-4ef5-418b-b4d6-51edfd021728','竹友以其季子將有遠行丐余一言余與翁游視其季猶姪也爲之言以勵其志','陸文圭','宋','宋诗','song-poetry','','[]','我生髪未燥，汝父以詩鳴。',156,'全唐诗/poet.song.247000.json','["我生髪未燥，汝父以詩鳴。", "憂患涉世老，襟義猶崢嶸。", "晚乃得二雛，美不減徐卿。", "季也纔弱冠，詩壇將父兵。", "愈湜氣如虹，候門識奇英。", "下馬呼小友，相顧各自驚。", "騄駬不受羈，歷塊千里行。", "分臺柏森森，霜氣壓百城。", "汝游何所挾，兩字直而清。", "銳進年倍壯，靜退事飽更。", "欲令從雅操，端肯迂修程。", "遠游重垂戒，顯親須揚名。", "但酬化茝志，足慰舐犢情。"]'),
('e24face8-0d8b-4fa2-bdba-9995fb74a0b6','送信講師','陸文圭','宋','宋诗','song-poetry','','[]','達士脫名檢，高人落林丘。',108,'全唐诗/poet.song.247000.json','["達士脫名檢，高人落林丘。", "體性未應殊，作用終不侔。", "講師得三昧，宗學貫九流。", "曾對樹說法，解使石點頭。", "劫火焚地水，慈雲護松楸。", "報恩心種種，閲古事悠悠。", "香火三生願，因緣再世游。", "文辭重柳請，衣服許韓留。", "殷勤翻短褐，博雅愧前修。"]'),
('4c989f05-9c77-4b5b-a150-69329db3c6c1','題質夫竹居','陸文圭','宋','宋诗','song-poetry','','[]','西園一叢竹，歲久枝幹繁。',72,'全唐诗/poet.song.247000.json','["西園一叢竹，歲久枝幹繁。", "會見鸞鳳棲，莫厭鳥雀喧。", "玉聲寒雨碎，翠色朝烟昏。", "蕭蕭黄素葉，風吹擁籬根。", "主人避俗客，青苔坐柴門。", "勁節諒無比，幽懷不可言。"]'),
('d9684aaf-f76b-4efb-912a-992d75cf8547','跋徐知事所藏禊帖','陸文圭','宋','宋诗','song-poetry','','[]','辨才將九十，及見開皇初。',84,'全唐诗/poet.song.247000.json','["辨才將九十，及見開皇初。", "不知虞褚輩，得似老僧書。", "尤物世希有，昭陵劫灰餘。", "玉函人不見，繭紙乃蠹魚。", "梅花一片石，猶自寶璠璵。", "定武久荆棘，長安復丘墟。", "茂林有陳迹，今誰山陰居。"]'),
('bd167045-eaa5-4fc2-bdcf-fb4505ad2e38','題沈華父送行詩卷','陸文圭','宋','宋诗','song-poetry','','[]','孟陽索吾錦，景純奪吾筆。',120,'全唐诗/poet.song.247000.json','["孟陽索吾錦，景純奪吾筆。", "老我嘆才盡，秀句吐不出。", "東陽有行卷，展玩已盈帙。", "乘雁豈爲多，買菜復求益。", "嗟君乃佳吏，家世本經術。", "一從冠惠文，不肯事佔𠌫。", "貞廉嚙苦蘗，和勁調玉瑟。", "簿書謝囂塵，車馬動行色。", "君如擊水茝，我似退風鷁。", "出處兩忘言，黄花秋淅瀝。"]'),
('b7414b4d-4e91-41b3-84cf-9dcecd837c39','題月心詩卷併記遇仙事云','陸文圭','宋','宋诗','song-poetry','','[]','東軒記待月，縱筆說性命。',132,'全唐诗/poet.song.247000.json','["東軒記待月，縱筆說性命。", "豈惟不知月，實亦不知性。", "文雖歐蘇工，理至關洛定。", "人心如明月，塵垢失清凈。", "霧收海氣澄，天逈風力勁。", "持我光明珠，照此大圓鏡。", "鏡中雙綵鸞，翔立請驂乘。", "御宴影娥池，神飈忽吹醒。", "鸞飛曉鏡空，龍睡淵珠靜。", "依舊碧潭心，無復瓊樓興。", "韓郎固有言，仙人未賢聖。"]'),
('7eb90083-df98-4f66-861c-92217a0a77e3','題百雁圖','陸文圭','宋','宋诗','song-poetry','','[]','青天一張紙，群雁飛來遠。',36,'全唐诗/poet.song.247000.json','["青天一張紙，群雁飛來遠。", "秋渚蘆瀟瀟，徘徊下清淺。", "若烹不能鳴，一一俱不免。"]'),
('b24f749a-1d49-432b-8858-998a06fdb7f8','詠風','陸文圭','宋','宋诗','song-poetry','','[]','好風何處來，天籟出衆竅。',60,'全唐诗/poet.song.247000.json','["好風何處來，天籟出衆竅。", "披襟懷楚臺，擊筑思高廟。", "扶摇九萬里，自謂一息到。", "安知大鵬運，不滿斥鷃笑。", "終當謝蓬蒿，振翼絕海嶠。"]'),
('46b675f7-6862-4248-90b1-a06e48ddee55','夏雨','陸文圭','宋','宋诗','song-poetry','','[]','仲夏井泉溢，雨聲集虛堂。',132,'全唐诗/poet.song.247000.json','["仲夏井泉溢，雨聲集虛堂。", "銀竹瀉高簷，靜聽何浪浪。", "蓮葉不受水，盤珠走低昂。", "溽潤逼衣篝，縫我新葛裳。", "媿彼作田人，蓑笠排青秧。", "出戶懶著屐，掃地燒木香。", "白晝生睡思，徐徐到羲皇。", "夢覺聞鼓吹，草蛙怒方塘。", "竹尾起寒烟，濕螢度微光。", "鄰翁閉門卧，中夕啼蒼黄。", "三日絕薪賣，積潦勢頹牆。"]'),
('b40a93a7-69c2-43c1-b0aa-c6e243ae1f14','秋感','陸文圭','宋','宋诗','song-poetry','','[]','遥夜百感集，白露下空庭。',72,'全唐诗/poet.song.247000.json','["遥夜百感集，白露下空庭。", "秋風入草木，衆葉會飄零。", "甘液始潤物，履霜漸陰凝。", "哀哉石榴樹，讖語成添丁。", "蘭艾既同焚，孰別臭與馨。", "皇天默不語，今古常青青。"]'),
('f8de58b2-53ab-486b-852f-73ffe59e5e7e','月','陸文圭','宋','宋诗','song-poetry','','[]','青天一片玉，上有衆星列。',72,'全唐诗/poet.song.247000.json','["青天一片玉，上有衆星列。", "夜中光漸小，讓此玻璃月。", "白兔卯時生，桂子秋後結。", "天上有山河，兩界隔吳越。", "何當御嫦娥，萬里駕飛轍。", "太白爲前驅，綵鸞相繼發。"]'),
('fd7b1c87-6be5-4975-bb9b-badc0ee81a30','徐德文索雪岡詩云已得而復失余尋舊稿亦無見想滕六遣六丁取之去矣再賦','陸文圭','宋','宋诗','song-poetry','','[]','雪飛不擇地，因高勢易積。',48,'全唐诗/poet.song.247000.json','["雪飛不擇地，因高勢易積。", "玉龍二百丈，橫卧前山脊。", "隨香去尋梅，路白無行跡。", "鐵笛吹一聲，驚裂蒼崖石。"]'),
('3427aac3-1f1c-4fe7-8f39-64d5471fa13d','新移瑞香不得雨有嘆','陸文圭','宋','宋诗','song-poetry','','[]','瑞香兒女花，艷潔而芳妍。',144,'全唐诗/poet.song.247000.json','["瑞香兒女花，艷潔而芳妍。", "得之古精廬，移置列檻前。", "易地費人力，不出花自然。", "深慮本先撥，枝葉隨之顛。", "是時夏久旱，不雨龜坼田。", "林木且憂枯，弱植豈自全。", "既已厄於人，況復遭此天。", "天與人仇之，命也花自憐。", "井筒灌朝夕，小潤培芳年。", "封植豈無心，榮枯自有緣。", "何時回春風，笑挽司花仙。", "携手共樽酒，醉卧雲錦邊。"]'),
('580ac38a-d9aa-41e2-aa7d-353770a8a91b','生意堂賦玉簪花得相字','陸文圭','宋','宋诗','song-poetry','','[]','娟娟秋蘭花，綠葉何披猖。',84,'全唐诗/poet.song.247000.json','["娟娟秋蘭花，綠葉何披猖。", "沙鷺明玉羽，冰蠶吐絲腸。", "倩盼宜素絢，追琢少金相。", "居然鐵石心，愛此風露香。", "何當競春華，亦復委朝霜。", "折花三太息，援筆臨清觴。", "明年花好在，坐客忘瀟湘。"]'),
('88e1f991-dbc6-4bb6-8945-6f040717dd6d','老桂古字韻','陸文圭','宋','宋诗','song-poetry','','[]','人受氣之精，百歲驚風雨。',96,'全唐诗/poet.song.247000.json','["人受氣之精，百歲驚風雨。", "少壯會有衰，神散無復聚。", "木受氣之偏，生旺寄於土。", "枝榦老更奇，花葉落仍吐。", "君看山中桂，秋露滴金乳。", "種者是何人，賞者經幾主。", "天香入酒冽，吸月空懷古。", "素娥笑白髪，對影獨起舞。"]'),
('fb9fa3eb-8b15-4740-b941-00313ae3a7a7','詠松','陸文圭','宋','宋诗','song-poetry','','[]','老松如枯骸，短松覆兒髪。',48,'全唐诗/poet.song.247000.json','["老松如枯骸，短松覆兒髪。", "城中薪價高，斤斧不時伐。", "難長虬龍姿，免藏虎豹穴。", "樵童出山暮，步擔挑新月。"]'),
('916fc9f9-ce1d-4b33-8503-3694466942c9','泗濱石','陸文圭','宋','宋诗','song-poetry','','[]','荆山石有玉，楚國無人知。',288,'全唐诗/poet.song.247000.json','["荆山石有玉，楚國無人知。", "再獻猶弗售，抱璞空自悲。", "他日遇良工，乃始稱其奇。", "寶傳數百載，邯鄲又得之。", "秦人請城易，趙氏以爲疑。", "不予寧負曲，予之恐見欺。", "相如奉使往，持璧指瑕疵。", "衝冠遽如許，睨柱欲何爲。", "衣褐已歸趙，湯鑊安足辭。", "奇哉古若人，掩卷空嗟咨。", "是非定百世，成敗止一時。", "天生此尤物，前後成禍基。", "有美當韞匵，衒鬻誠非宜。", "和氏不待價，刖足將尤誰。", "人才國輕重，璧豈係安危。", "相如真暴虎，雖死悔莫追。", "二子有遺憾，仲尼真吾師。", "泗濱一片石，不染自成緇。", "上有華林字，疑是故物遺。", "春官雅好古，傳載煩文移。", "主人不敢惜，持貢白玉墀。", "埋光經幾年，不與賞音期。", "無意博連城，得失輕毫釐。", "二事擬非倫，聊以資吾詩。"]'),
('32bf7ae0-8cd4-4c4d-8760-eeea2396fa87','車','陸文圭','宋','宋诗','song-poetry','','[]','舟止奔牛堰，始識丹陽車。',156,'全唐诗/poet.song.247000.json','["舟止奔牛堰，始識丹陽車。", "規製殊草草，力不任馳驅。", "淮安距宿遷，代之牛與馿。", "軒蓋乃差大，雙輪夾一輿。", "軝衡輗軏軫，名物與古殊。", "梓人不知經，多以方言拘。", "輸載亦稍豐，日行百里餘。", "御者非王良，隉杌不安車。", "蒲輪召申公，養老宜徐徐。", "干祿以爲榮，愧我非純儒。", "小兒問金根，其制復焉如。", "輿服漢最詳，具載班范書。", "慎勿似韓昶，問學當勤渠。"]'),
('bef18c14-aa15-4e03-ae26-467d1bee6d82','挽趙益之','陸文圭','宋','宋诗','song-poetry','','[]','汝父昔吾友，汝翁昔我師。',132,'全唐诗/poet.song.248000.json','["汝父昔吾友，汝翁昔我師。", "汝時侍親側，楚楚玉雪兒。", "稍長從吾游，學問乃大奇。", "風木不待養，垣室空遺基。", "成立汝有望，修短吾莫推。", "四世積善心，一門無龐眉。", "俯仰三十載，三喪路人悲。", "受氣各有終，勞生嗟奚爲。", "牆東荷鋤叟，夙受汝翁知。", "老懷念疇昔，不覺哀涕垂。", "欲誌殿中墓，健筆慚退之。"]'),
('7a197def-5302-4dd0-8f31-ecd59cdfa838','挽鄧友梅','陸文圭','宋','宋诗','song-poetry','','[]','簫鼓何闐闐，西風弔客船。',48,'全唐诗/poet.song.248000.json','["簫鼓何闐闐，西風弔客船。", "主人辭華屋，輤車落荒阡。", "芙蓉一片石，千古懷人賢。", "喚醒梅花魂，薦之秋菊泉。"]'),
('04dcbfe8-c618-44d6-a26a-8693ef9c9ae0','北入穆陵關皆山石崩沙北風塵起行人良苦因作','陸文圭','宋','宋诗','song-poetry','','[]','大風北來沙觸面，行人咫尺不相見。',240,'全唐诗/poet.song.248000.json','["大風北來沙觸面，行人咫尺不相見。", "寒日無光天地晦，一似項劉睢水戰。", "四山确犖路摧車，磵壑涓流長一線。", "土簷烟突兩三家，鬼貌鵠形何物變。", "葛盧牛語誰能別，公冶禽言難復辨。", "古磁濁酒時招飲，破甕酸虀聊自薦。", "吾聞臨菑稱鉅麗，十二山河據形便。", "姑尤聊攝舊提封，夷吾小白初營建。", "三歸反坫侈國中，九合衣裳出幽鄄。", "孟姜洵美共翱翔，稷下群遊逞雄辯。", "盛衰氣脈不可測，往來今古更相禪。", "干戈流徙人物換，水火崩騰陵谷轉。", "會使雍門重感慨，無復蘇秦昔誇羨。", "山東負海猶如此，六合茫茫難臯遍。", "安得長劍倚白雲，手抉狂飈清九縣。"]'),
('5236ff21-cea7-4dd7-ae5e-874ea6a83014','出鎮口止見小峰','陸文圭','宋','宋诗','song-poetry','','[]','鎮東小峰獨無侶，中峰徐來顧其弟。',48,'全唐诗/poet.song.248000.json','["鎮東小峰獨無侶，中峰徐來顧其弟。", "大峰偃蹇背面去，似嫌俗客不與語。", "無奈我行節節高，山欲藏身恐無所。"]'),
('43e03b36-a215-424f-917d-e747d6a1b79b','訪何庵觀水陸功德','陸文圭','宋','宋诗','song-poetry','','[]','山收雨脚雲氣濕，葛藤刺屨穿徑入。',64,'全唐诗/poet.song.248000.json','["山收雨脚雲氣濕，葛藤刺屨穿徑入。", "精廬桃李花漫山，磬鐘聲繞落花間。", "野僧凈設伊蒲供，譯說西方如說夢。", "我方談笑耳不聞，寒窗暮對西山雲。"]'),
('a78cdd91-a505-4001-9dd3-4ad9c16264fd','即事','陸文圭','宋','宋诗','song-poetry','','[]','南窗陰陰日色薄，北窗烈烈風聲惡。',64,'全唐诗/poet.song.248000.json','["南窗陰陰日色薄，北窗烈烈風聲惡。", "破衲蒙頭睡正濃，地爐煮餠鐺折脚。", "小奴驚叫老婢嗔，我愧口腹煩他人。", "豪家香閣暖生春，人乳蒸豚蠟代薪。"]'),
('256aef65-5090-46eb-bec8-36a7614ca579','壬辰六月旦日記異','陸文圭','宋','宋诗','song-poetry','','[]','六月朔旦昧爽天，我夢蝴蝶飛翻翻。',192,'全唐诗/poet.song.248000.json','["六月朔旦昧爽天，我夢蝴蝶飛翻翻。", "一聲驚覺不可執，鏗然有物墮我前。", "陰風蕭蕭榻震動，褰帷一咤聲寂然。", "向空抹漆無所臯，堂上呼燈人自眠。", "一生學道心勿動，養氣未敢輕先賢。", "元忠昔日鬼移牀，廳廡之下凡三遷。", "稚圭卧內見匕首，金带忽置城頭邊。", "二公名德余不及，鬼賊揶揄空自憐。", "神姦無復照金鼎，偷兒何暇哀青氈。", "二端是否吁莫辨，一夕倉卒嗟何緣。", "吟哦未斷紙窗白，山寺風雨鳴鐘懸。", "起來搔首空四壁，濕薪竈婢愁炊烟。"]'),
('9186f79a-cd8d-4693-8594-8fd24d2e6a93','庚子七月書事','陸文圭','宋','宋诗','song-poetry','','[]','今年低漥水生魚，去年高亢旱坼龜。',64,'全唐诗/poet.song.248000.json','["今年低漥水生魚，去年高亢旱坼龜。", "陰陽似屬天公事，廟堂可是無臯夔。", "勸分納粟令如火，老稚依然鵠形餓。", "嗟汝命薄獨可憐，穹官巨室無凶年。"]'),
('83f8178f-044f-417a-85f0-36605dd23f29','臘月二十九日作','陸文圭','宋','宋诗','song-poetry','','[]','夜漫漫，塵冥冥。',56,'全唐诗/poet.song.248000.json','["夜漫漫，塵冥冥。", "大車道上檻檻聲，三十餘里天未明。", "一軒一輊不得寧，倚坐兀兀摇心旌。", "天寒歲暮霜雪零，嗟哉客子誰汝令。"]'),
('16302e99-78d4-4c7e-bbc9-ecbd5b0a7bb6','和曹士開侍御見寄韵','陸文圭','宋','宋诗','song-poetry','','[]','南臺御史忠貫日，當晝妖狐屏無跡。',96,'全唐诗/poet.song.248000.json','["南臺御史忠貫日，當晝妖狐屏無跡。", "端方自是廊廟器，錯落天球間宏璧。", "記曾緩带理江城，猶憶尊前坐談客。", "春樹相思白日晚，月梁入夢青燈夕。", "乘車戴笠高與下，倚樓看鏡今非昔。", "壯心無復夜聞雞，莫比司空鬚恨赤。"]'),
('855775ee-f9e5-4c22-ba01-817d09d6ea1e','壽王君明','陸文圭','宋','宋诗','song-poetry','','[]','去年中秋月色高，吳山痛飲推文豪。',144,'全唐诗/poet.song.248000.json','["去年中秋月色高，吳山痛飲推文豪。", "今年依舊故鄉月，紛紛青紫誇兒曹。", "世間兒曹何足數，芙蓉仙人在江浦。", "握荃懷瑾遺世紛，黄卷日與聖賢伍。", "曾攀月桂臼邊枝，素娥夜半睡不知。", "覺來薄怒赬自持，與仙重約三秋期。", "一朝功成九霄去，小黠肯顧偷桃兒。", "城東白髪龍鍾叟，瓣香來祝仙人壽。", "長生辟穀未要學，千載與君期不朽。"]'),
('3eb9af0d-6b1f-4e46-9187-3595ae30ad95','察罕布哈忠翊父歿王事母表門閭本官棄職侍養守制三年一門節孝人所難能作詩美之','陸文圭','宋','宋诗','song-poetry','','[]','王氣初不限中華，至性未嘗根六籍。',160,'全唐诗/poet.song.248000.json','["王氣初不限中華，至性未嘗根六籍。", "門閭節行世所欽，父子忠孝天應惜。", "連環解玉理堅緻，老蚌剖珠光的皪。", "伯也執殳萬人敵，血染征衣歸不得。", "空留明鏡照孤鸞，妾顔如花心如石。", "鬒雲漸變蠶絲白，蓬首何曾御脂澤。", "北堂手植忘憂草，幸有斑衣可娛老。", "不須遣使寄當歸，兒無遠志歸來早。", "事親日短當愛日，祇今三年已素鞸。", "宰予衣錦殊未安，溫嶠絕裾非小失。"]'),
('daa9e3a1-17ca-45e4-aee1-a0d3b2745790','雅宜山在城西五十里有德慶庵在其下穹窿山福順寺長老紹堯翁作詩取以雅宜爲號求詩','陸文圭','宋','宋诗','song-poetry','','[]','雅宜山低一拳石，氣壓華嵩千丈碧。',128,'全唐诗/poet.song.248000.json','["雅宜山低一拳石，氣壓華嵩千丈碧。", "不論城市與林丘，愛山例是詩人癖。", "寒泉修竹蒼崖底，青山解與高人語。", "花落猿吟總是機，舉似山僧盡成句。", "山僧來獻詩人號，百種不如山色好。", "德慶禪牀明月夜，館娃人海紅塵曉。", "我知山心雅好靜，犖确不容車馬造。", "草堂宜雨又宜晴，藜杖芒鞋時一到。"]'),
('a9d66354-167c-449b-9ee4-48adbb45dcf3','贈道人周大方','陸文圭','宋','宋诗','song-poetry','','[]','道家者流雙鳳仙，迂訪牆東老田叟。',128,'全唐诗/poet.song.248000.json','["道家者流雙鳳仙，迂訪牆東老田叟。", "叟讀儒書五十年，一事不成今白首。", "道人過門何所求，期將汗漫東北游。", "青蛇三尺風雷吼，玄鶴一聲天地秋。", "吏商奔走日百里，區區嗜利與名耳。", "道眼視之海中漚，炎夏長途何必爾。", "吾師之師柱下史，紫氣曾驚關尹喜。", "當時剩却五千言，焉用老人詩一紙。"]'),
('73607b08-fd54-4a1c-8abe-4a3abb9b8b66','贈潘道士祈雨','陸文圭','宋','宋诗','song-poetry','','[]','人天相距尺有咫，雷電六丁繞吾指。',64,'全唐诗/poet.song.248000.json','["人天相距尺有咫，雷電六丁繞吾指。", "藥師馬上寄小瓢，夜半一滴灑千里。", "古湫源竭老蛟泣，新秧秀濯田畯喜。", "匣收寶劍捲陰符，師歸宴坐茅峰裏。"]'),
('28b45b23-f2e9-4dac-aa7f-73e31a53e849','贈鄭元明術士自言安晚之孫故詩及之','陸文圭','宋','宋诗','song-poetry','','[]','梁灝八十有二歲，自從天福逮雍熙。',200,'全唐诗/poet.song.248000.json','["梁灝八十有二歲，自從天福逮雍熙。", "中更乾德五星聚，晚賜龍頭拜玉墀。", "吾今之年灝相若，布衣落拓何能爲。", "吟詩獨與熊兒和，作賦那求狗監知。", "龍鍾久納少年侮，耿介尤爲諂子嗤。", "吾聞長沙趙彥仁，豫知鄭相秉化鈞。", "從容杯酒託二子，端嘉之際俱名臣。", "是時宋德已衰謝，扶顛江左尚有人。", "安晚之孫今爲庶，嗟我與子俱邅迍。", "不須諛我有許壽，且道何時脫子貧。", "清和四月天氣新，共買一醉拋青春。", "窮通壽夭俱莫問，蓋世英雄一窖塵，草間惟有石麒麟。"]'),
('c3a67cfe-e7f5-422a-836d-e26cc7c6db79','贈張明德星士','陸文圭','宋','宋诗','song-poetry','','[]','二曜五緯萬古懸，甘石之學今不傳。',224,'全唐诗/poet.song.248000.json','["二曜五緯萬古懸，甘石之學今不傳。", "術家能以天占人，聖人乃以人占天。", "仁義禮智性所具，吉凶禍福命使然。", "命天俵賦定不易，性我受用修則全。", "經文二百有五字，明德乃在新民先。", "君從何處講此學，直遡建洛窺先賢。", "工夫潜深秋日靜，本真瑩靜霜月圓。", "市聲初散簾欲下，龜筴未收客下馬。", "一人妄計秩崇庳，一人猥算資高下。", "縱橫二位布逆順，錯落五行分制化。", "先生拊掌笑且答，二客相看面如赭。", "徐言至善同一初，非愚不足智有餘。", "萬物不齊氣雜揉，是心本明如太虛。", "不須詹尹就决疑，客如不信問子輿。"]'),
('d7410906-a578-4925-a147-032cdce1b46f','壬申冬晦叔譯史歸別小詩奉餞','陸文圭','宋','宋诗','song-poetry','','[]','蒼頡製字傳羲皇，鬼神夜哭殊倉黄。',96,'全唐诗/poet.song.248000.json','["蒼頡製字傳羲皇，鬼神夜哭殊倉黄。", "語言聲律未易下，嗟君楚産學北方。", "又能經術飾吏事，筆墨豈足盡所長。", "郵亭一夕飲離觴，他年富貴勿相忘。", "天無烈風海波靜，白雉九譯貢越裳。", "盛時努力早出仕，成誦姬旦坐明堂。"]'),
('a3f0cba9-3d37-4b9a-9641-ee6d417d5852','從聖國寶二茂才敘別','陸文圭','宋','宋诗','song-poetry','','[]','龍門世家史學祖，足涉淮湘到鄒魯。',96,'全唐诗/poet.song.248000.json','["龍門世家史學祖，足涉淮湘到鄒魯。", "兒生墮地弧在左，婦閉車中爲誰苦。", "二君雁蕩游虎林，逆旅一笑論古心。", "地爐畫灰事未竟，推窗看天雪意深。", "山寒約共梅花語，江水東流予北去。", "明年春風上石渠，道傍爲我弔望諸。"]'),
('543cb06a-cb6e-403e-8930-5ca03bb08b34','留別山村樂閑菊存愛山梅村并寄景初慎與國華','陸文圭','宋','宋诗','song-poetry','','[]','南來飛雪如柳花，北歸柳花如飛雪。',64,'全唐诗/poet.song.248000.json','["南來飛雪如柳花，北歸柳花如飛雪。", "乾坤偪仄困羈旅，江山蒼莽驚歲月。", "白雲冉冉千里外，滴盡春林子規血。", "故人回首亂峰青，古堠斜陽照離別。"]'),
('433c5e43-30f3-4c60-a3eb-5e3e1839eba7','送馬伯亨西省郎中','陸文圭','宋','宋诗','song-poetry','','[]','驚吾學問非少年，羨君功業當壯年。',96,'全唐诗/poet.song.248000.json','["驚吾學問非少年，羨君功業當壯年。", "曾聞雞聲共起舞，老我輸君獨著鞭。", "臘寒枯柳不堪折，欲別未別心茫然。", "關塞黑風虎方嘯，江湖白浪龍正眠。", "洪都西統數千里，俊乂如林足驅使。", "好將舊榻拂塵埃，佳客可能無孺子。"]'),
('5c0272f2-a67a-4af7-a65f-d623c15f7fd6','送干壽道同知北上','陸文圭','宋','宋诗','song-poetry','','[]','甲寅詔下興賢才，吳中多士轟春雷。',176,'全唐诗/poet.song.248000.json','["甲寅詔下興賢才，吳中多士轟春雷。", "門外鵠袍那可數，一人獨上黄金臺。", "宦途詰曲容不得，直向東海窺蓬萊。", "蓬萊水闊雲氣浮，眼看健翮摩天游。", "故鄉六載不歸去，老盡西風菊徑秋。", "歸來四壁亦不惡，人羨錦衣君不覺。", "館娃茂苑正凄凉，古汴黄河復漂泊。", "問鄉安在遲一見，承恩內直金華殿。", "從容薇閣演絲綸，花間應隔同年面。", "自恨山中老樗櫟，擁腫不堪逢匠石。", "枯梢無復起春風，一生空負吹噓力。"]'),
('42320fe8-ac43-4a64-9328-50b40a4687de','送祝君晟之官昌化','陸文圭','宋','宋诗','song-poetry','','[]','九里河梁昔携手，酒酣共折城南柳。',112,'全唐诗/poet.song.248000.json','["九里河梁昔携手，酒酣共折城南柳。", "春風六載忽吹過，浮雲萬事無不有。", "餘生閉戶忍寒餓，薄宦隨方困奔走。", "徑從蓮幕換青衫，猶勝兔園嘲白首。", "我床昨夜破却甕，君印何時大如斗。", "肯將車服耀故人，未覺來往煩佳友。", "從今出處可忘言，柳邊重飲城南酒。"]'),
('0acc5d90-f2a0-480d-a413-ecd9f963ff19','送經之偕義齋兩舍人入燕併呈善之待制','陸文圭','宋','宋诗','song-poetry','','[]','君馬三渡白溝河，溝水東流青草多。',128,'全唐诗/poet.song.248000.json','["君馬三渡白溝河，溝水東流青草多。", "踞鞍顧盼聊試耳，伏櫪悲歌奈老何。", "古人千金重然諾，把臂况受生死託。", "肯先申白獨辭楚，且伴機雲雙入洛。", "道遠始知離別苦，地僻應思宦游樂。", "榮名日久當日厭，浮生花開又花落。", "平世應無戰國材，選賢何日到金臺。", "寄聲玉堂老仙伯，桂樹秋風歸去來。"]'),
('4cb7cc36-03aa-4552-90af-fb716a18d1e6','送節之衡之兩舍人入燕','陸文圭','宋','宋诗','song-poetry','','[]','龍駒鳳雛兩陸子，並駕秋風鞭騄駬。',144,'全唐诗/poet.song.248000.json','["龍駒鳳雛兩陸子，並駕秋風鞭騄駬。", "老眼一見失驚喜，定知乃翁元不死。", "生子真足慰人心，景升諸兒豚犬耳。", "滿朝譽翁不容口，世祿固應傳不朽。", "爲官豈計多得錢，取印終須大如斗。", "我是韓家十八郎，里中曾拜北平王。", "碧梧停鵠已飛去，玉雪娟娟今在傍。", "往事傷懷淚如水，矻矻窮年吾老矣。", "欲追霞佩小頡頏，手倦束書携不起。"]'),
('f05ccc1c-6880-4be5-9a3d-0a24be6bcd70','送楊起之安豐錄判','陸文圭','宋','宋诗','song-poetry','','[]','芍陂茫茫古邊城，雞犬相聞今樂土。',112,'全唐诗/poet.song.248000.json','["芍陂茫茫古邊城，雞犬相聞今樂土。", "交兵往事空流水，避亂居民尚遺堵。", "似聞此地歲豐穰，要得清官手摩拊。", "君才天馬足神駿，老大去年參選部。", "閩中實歷禆風憲，淮右先聲動官府。", "爭看祖道車騎衆，力疾登途霜月苦。", "牆東故人懶出門，濁酒黄花對誰舞。"]'),
('48d2d32a-bba9-4509-ae62-9c5b5b9bd66f','送黄子高常熟教授','陸文圭','宋','宋诗','song-poetry','','[]','儒科一廢四十年，甲寅詔下初興賢。',160,'全唐诗/poet.song.248000.json','["儒科一廢四十年，甲寅詔下初興賢。", "雞窗夜半同起舞，竟讓祖生先著鞭。", "去乘騄駬首燕路，歸騎赤鯉游琴川。", "川中疑有古文學，子游故里今依然。", "采芹思樂絃且歌，官况雖清奈冷何。", "省臺衮衮豈足羨，燕雀喧啾入網羅。", "殘春積雨困花柳，天氣昏昏如中酒。", "怕逢北客問新事，更恨東人奪佳友。", "暮年離別意鮮歡，追思得失空長歎。", "詩成寫寄掩關卧，夢逐飛絮黏征鞍。"]'),
('af65f550-820f-45a4-9704-52dda1cd4bb6','奉餞子華教授北上時癸酉三月','陸文圭','宋','宋诗','song-poetry','','[]','清明上巳三月中，一春天氣少沖融。',120,'全唐诗/poet.song.248000.json','["清明上巳三月中，一春天氣少沖融。", "曈曈初日翳復吐，黄塵漲起西北風。", "有客束書挾兩童，南來兩馬一馬驄。", "舉鞭蕭蕭易水東，博徒劍客時相逢。", "怪君體弱心甚雄，聲名壯健驚老翁。", "元英磨室渺無蹤，黄金誰爲隗築宮。", "茫茫宇宙今古同，天時人事安有終，江柳自綠山花紅。"]'),
('6b4a75b2-319a-461d-a997-3079449f4af7','送吏員遷調松江','陸文圭','宋','宋诗','song-poetry','','[]','吏員務選才具良，不問他邦與吾鄉。',144,'全唐诗/poet.song.248000.json','["吏員務選才具良，不問他邦與吾鄉。", "珠金出産已足貴，蘭桂移根亦自香。", "諸君此行良不惡，居家何如宦游樂。", "季鷹曾憶松江鱸，士龍空歎華亭鶴。", "昔人還鄉苦不早，今人離鄉涉遠道。", "漁舟泛澤青茫茫，客衣吹霜白皜皜。", "朱甍結構井邑富，畫戟清閑官府好。", "紛紛刀筆心自厭，落落功名身未老。", "要看入海運大鵬，不恨出山成小草。"]'),
('ba9d1a81-43c1-47e4-a9a9-4727d7575e38','送吳子長入京','陸文圭','宋','宋诗','song-poetry','','[]','乙亥江城守宵遁，連營錦帳排鋒刃。',192,'全唐诗/poet.song.248000.json','["乙亥江城守宵遁，連營錦帳排鋒刃。", "丁男釋耒兒女啼，朱門一夕黄金盡。", "我時擁卒護鄉井，紵袍白馬君來省。", "石牀試劍人血腥，地爐傳酒牛炙冷。", "手揮談麈看落月，平明索飯出門別。", "虎林山頭却寄書，一字不問家何如。", "乾坤風雨旦復旦，家家昇平喫飽飯。", "君才筦庫久繁劇，我老詩書更憂患。", "肯將出處問猿鶴，自覺高低笑鵬鷃。", "浩蕩炎風扇區野，斜日征鞍古榆下。", "功名不復念遠道，富貴自覺顔色好。", "俯仰疇昔予何言，梅雨敲窗濕詩草。"]'),
('aa4af61c-14f0-46c3-ab5b-93178910f91a','送羅秋崖','陸文圭','宋','宋诗','song-poetry','','["\u897f\u6e56"]','宰相昔起富春山，門生四海皆達官。',224,'全唐诗/poet.song.248000.json','["宰相昔起富春山，門生四海皆達官。", "牋書爭寶朵雲樣，題詩便隔紗籠看。", "知君相與有瓜葛，絕口不道人所難。", "何不跨鼇上金鑾，胡爲采芹坐江干。", "群鴞飛來爭野葚，三鱣不足供朝餐。", "人生榮悴何足歎，海水會使桑田乾。", "當軒下馬昔日盛，閉門羅雀今朝閒。", "群兒瑟縮手不熱，先生落魄氈猶寒。", "范陽城南丹旐歸，何人送者車班班。", "羊曇獨灑西州淚，孟嘗空感雍門彈。", "老樹春殘蝴蝶去，滄江歲晚白鷗還。", "北風吹雪被長巒，詩囊酒榼隨征鞍。", "請君讀詩飲美酒，歸日謝客牢閉關。", "世間萬事不須問，西湖柳色差可觀。"]'),
('af480558-eb6c-4756-93c1-82e9acb1497b','送吳君遠','陸文圭','宋','宋诗','song-poetry','','[]','暨陽幕職無他奇，置薤一本水一盂。',144,'全唐诗/poet.song.248000.json','["暨陽幕職無他奇，置薤一本水一盂。", "鐘鳴張燭起署事，坐看日落庭西隅。", "雁行鉗紙走却立，高懸明鏡分絲銖。", "長官堂上口嘯諾，時時隔舍聞歌呼。", "荒村人閒花自落，圜扉晝靜草欲蕪。", "褰帷使者上治狀，爲出清冰置玉壺。", "小兒踉蹡老翁怒，細問代者如君無。", "楚苔漬雨古驛寒，酒酣寫出陽關圖。", "君行上馬慎勿驅，梅水綠漲南興湖。"]'),
('9b81f161-d0c7-49c4-8749-9f4ac946d9dc','送黄子高如泰州謁朱南伯','陸文圭','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','采采江蘺步石磵，東望海堤青不斷。',96,'全唐诗/poet.song.248000.json','["采采江蘺步石磵，東望海堤青不斷。", "故人泮上誰飲酒，尺素不來魚尾短。", "黄子卓犖文更奇，命駕千里赴相思。", "長江鳬雁不足數，曠野虎兕將何之。", "景德寺前讀書閣，彥國九原不可作。", "寄聲故人加餐食，昨夜秋風淮水惡。"]'),
('ffc3daf4-6d64-4c32-988c-51954d6a7c42','送張子野','陸文圭','宋','宋诗','song-poetry','','[]','江淮落南俯閩嶠，山水相背風馬牛。',96,'全唐诗/poet.song.248000.json','["江淮落南俯閩嶠，山水相背風馬牛。", "間關草就北征賦，日暮彈鋏君何求。", "袖中漫刺通姓名，猶及慶曆思中州。", "子京永叔老交友，白首鶑燕陪風流。", "今無花月聽水調，但見滿目森戈矛。", "長歌送君萬里游，天荒地老令人愁。"]'),
('28f51d15-31de-4e0a-a652-c7c2da1c4635','送徐舜輯','陸文圭','宋','宋诗','song-poetry','','[]','彥霖父子魏公客，持國之兄招不得。',160,'全唐诗/poet.song.248000.json','["彥霖父子魏公客，持國之兄招不得。", "豪華落盡漳水流，主人眠石扃醉白。", "天傾地坼古今愁，浣花窮殺老參謀。", "窗寒雪壓燈昏夜，門靜蟲吟葉落秋。", "平生故人渺江浦，誰往省之遣宗武。", "惜哉赤白兩洪崖，敢道交情棄如土。", "回舟蘋浦思依依，空憶桃花鱭鱠肥。", "竹西騎鶴不可去，西州萬里將安歸。", "南山之陽木已老，南山之陰木尤槁。", "不信春風吹不蘇，珍重歲寒宜自保。"]'),
('f578c78c-f2c6-4641-a2f7-5155310a6673','送仲華葛兄','陸文圭','宋','宋诗','song-poetry','','[]','蓉城諸葛何綿綿，一門青紫三百年。',144,'全唐诗/poet.song.248000.json','["蓉城諸葛何綿綿，一門青紫三百年。", "聞孫流落湘江上，手握美瑾懷香荃。", "夜行衣綉豈足榮，歸夢皛皛經山川。", "君家元有紫荆樹，一枝兩枝枯或妍。", "當暑歸來憩其下，俯仰陳迹心茫然。", "牆東野人頭雪白，乃翁坐上琴書客。", "鳳毛一見眼雙明，豚犬吾兒空自責。", "追思老少各時異，坐閲興衰疑世隔。", "江湖來往慎風波，他年重會銅駝陌。"]'),
('755b3d45-b2fa-43fc-b7f2-b26e847f5caf','送北禪釋天泉長老入燕','陸文圭','宋','宋诗','song-poetry','','["\u8861\u5c71"]','金身夢覺白馬東，西來禪教各一宗。',203,'全唐诗/poet.song.248000.json','["金身夢覺白馬東，西來禪教各一宗。", "講師高據獅子座，緇素群集驚盲聾。", "天華咫尺飛墜地，夜燭神光滿室紅。", "遠師道林嗣宗風，專談義學離禪鋒。", "三葉五性總超詣，一枝擘與天泉翁。", "不泥筌蹄求解脫，不執文字迷本空。", "黄梅四月上盧龍，騎馿不下莫相逢。", "徐州麥飯足可飽，青州布衫誰與縫。", "盧溝橋邊石頭滑，飛錫徑入明光宮。", "手揮玉麈天顔喜，身被紅綃帝渥濃。", "回頭却笑虎丘石，夜半不憶寒山鐘。", "君不見懶殘昔住衡山峰，使者召之終不從，天寒垂涕石窟中。"]'),
('b86d684b-8828-40d4-9b25-72cd513e0d35','己卯題吳江長橋二首','陸文圭','宋','宋诗','song-poetry','','[]','瓜步投鞭濕馬尾，吳江猶是衣带水。',288,'全唐诗/poet.song.248000.json','["瓜步投鞭濕馬尾，吳江猶是衣带水。", "陽侯不敢駕風濤，神劍自斷長虹死。", "木罌夜半飛渡軍，縛筏驅丁命如蟻。", "波心兩龍忽跳出，一聲金鼓波神泣。", "興廢相望五六載，斜陽獨倚欄干立。", "酒酹波神叫不應，劍鋩冷浸秋蒲碧。", "江頭朱欄四千尺，一望初疑幾十里。", "左約江流右截湖，橋東出日橋西雨。", "漁歌答響遠相失，群雁旅泊迷葭葦。", "荒村獨木橫野渡，深厲纔能濕衣履。", "乘輿足受兩三人，猶當杠梁涉溱洧。", "書生眼力小如甕，一臯巨麗心驚喜。", "吁嗟人力不可到，毋乃神功役山鬼。", "憶昔燕兵下江浙，馬逸風騣卷灘尾。", "長驅水陸一時進，錢塘破竹從風靡。", "川流衰竭王氣盡，成敗反復固其理。", "汴師平南將彬美，南人死恨樊若水。", "采石浮橋一夕成，曉出降幡人姓李。"]'),
('d790bea8-a1f5-4f5d-b4b2-4de9143a5751','寧晉李照磨築室奉親名曰芝室索客賦之','陸文圭','宋','宋诗','song-poetry','','[]','口誦嚴君口授書，手提慈姥手縫衣。',128,'全唐诗/poet.song.248000.json','["口誦嚴君口授書，手提慈姥手縫衣。", "寸草安能報春暉，遠志不敢回當歸。", "嗟兒客宦游有方，舅姑晨興婦在旁。", "手供鮭菜晡下堂，几席代汝親扶將。", "白雲英英趙州山，玉琴石榻窗戶閒。", "上池飲罷燕坐間，生香滿室光照顔。", "鍾英毓秀自乃翁，草木臭味將毋同。", "借鋤取箒面發紅，偕飲甘露薰祥風。"]'),
('8daf64de-66db-462b-92a7-7fea05e33342','寄題俞氏草堂','陸文圭','宋','宋诗','song-poetry','','[]','浣花老人溪上住，野梅官柳橋西路。',144,'全唐诗/poet.song.248000.json','["浣花老人溪上住，野梅官柳橋西路。", "碧雞坊外少人行，曉带春星自來去。", "荒基蘚合無尋處，峽川萬古流詩句。", "紫芝之孫居澄江，瓊茅結宇青竹窗。", "南牆夜深塔鈴語，古寺白鶴飛來雙。", "索我新吟寫君趣，開卷悠然起幽思。", "我嘗十年卜山居，經營未有瀼西地。", "風流縱似老參謀，資給應無賢錄事。", "願君分借半間雲，勝日當携茶具至。"]'),
('6fdb8532-ef1a-4b66-a49d-8916d474f52b','題南夫四時佳致園亭','陸文圭','宋','宋诗','song-poetry','','[]','桐川博士老文學，出處乃在可否間。',160,'全唐诗/poet.song.248000.json','["桐川博士老文學，出處乃在可否間。", "舍東支徑劣百步，牆北危亭俯兩山。", "風花辭枝黏草碧，雨竹卸籜連苔斑。", "林臯紅葉白雁早，江國瓊英翠羽寒。", "一年天與四時景，百歲人無半日閒。", "擾擾鳴鐘戒晨起，昏昏秉燭愁夜闌。", "蜉蝣生死寄黄壤，烏兔飛走凋朱顔。", "主人自得靜中趣，物理常於動處觀。", "從容琴書寓真樂，邂逅樽前追清歡。", "良時佳友不易得，惡客未至門先關。"]'),
('c3f3a84e-ae56-4bff-82a5-260cee03456c','題立齋不礙雲山亭','陸文圭','宋','宋诗','song-poetry','','[]','英英山中雲，蒼蒼雲外山。',156,'全唐诗/poet.song.248000.json','["英英山中雲，蒼蒼雲外山。", "雲山偃蹇若高士，不傍貴人門戶間。", "藕堂老人家四壁，詩句曾參浣花客。", "一亭半落平疇外，拾盡乾坤眼猶窄。", "樵歌斷處起寒青，鳥影明邊際空碧。", "玉鸞不入巫陽夢，滿榻凝塵室生白。", "昨宵礎潤卜雨來，岸巾欄角小徘徊。", "忽然一片黑模糊，失却萬丈青崔嵬。", "有風颯然起林薄，如覺天日徐徐開。", "推窗看山色如故，斷雲飄零不知處。"]'),
('116c61d8-8f14-42a5-942e-2056abf09d6e','書范石湖白髭行後','陸文圭','宋','宋诗','song-poetry','','[]','渡江莫盛乾淳間，虞范諸賢鬢未斑。',80,'全唐诗/poet.song.248000.json','["渡江莫盛乾淳間，虞范諸賢鬢未斑。", "功名草草負遺恨，老死不見鞏洛山。", "我近經行石湖路，范家水名王家墓。", "風流一代竟澌盡，手澤何人爲珍護。", "直當慷慨論興亡，奚暇悲歌嘆衰暮。"]'),
('8a2529e9-1d99-4ff8-9b1d-7649915edc15','題程子充少監家藏二詩遺墨','陸文圭','宋','宋诗','song-poetry','','[]','教子惟欲諂，嫁女惟欲官。',188,'全唐诗/poet.song.248000.json','["教子惟欲諂，嫁女惟欲官。", "床屏觸頭乃翁怒，文書銜袖媒姥謾。", "癡人一笑可絕倒，古訓相傳良獨難。", "大夫有愧程監察，上谷敢望元遺山。", "易簀微言尚典刑，出門別語重丁寧。", "子無橐裝與寶劍，女無綉褥與金屏。", "各贈驪珠五十六，藏在肺腑爲深銘。", "梓喬俯仰俱莫及，冰玉清潤尤相形。", "水衡使者直而溫，遺山宅相監察孫。", "禔身務學承先志，範世傳家示格言。", "正大去今八十年，流風遺俗猶有存。", "誰能題詩墓柏下，使兩仙翁起九原。"]'),
('eb956cd9-5300-4baf-b094-52cd7cb08f92','甲申春張菊存遊洞霄諸公餞詩盈軸越明年余過故都補行卷之末','陸文圭','宋','宋诗','song-poetry','','[]','春申下邑荒江濱，有眼不識錢塘春。',176,'全唐诗/poet.song.248000.json','["春申下邑荒江濱，有眼不識錢塘春。", "朅來南北兩高峰，乍見西施真美人。", "曉妝濃淡看不足，誓結鶉衣老湖曲。", "安知湖曲有高人，如此仙姿尚嫌俗。", "別尋大滌登天柱，氣壓群峰三十六。", "歸來書窗風雨夕，潜聽三竺山靈哭。", "睠言玉局老飛仙，摩挲銅狄今幾年。", "神蛟飛鼠亦何有，金堂玉室空茫然。", "天風吹醒丹泉酒，碧桃津遠人回首。", "石上禽餘搗药聲，絕憐無訣授長生。", "今年却被山靈笑，依舊湖堤拾芳草。"]'),
('9ad29eab-b73d-4958-a130-85e0eeaeaefd','題金陵海月潮卷','陸文圭','宋','宋诗','song-poetry','','[]','太陰朔望有盈虧，海外隨之互消長。',48,'全唐诗/poet.song.248000.json','["太陰朔望有盈虧，海外隨之互消長。", "夜半秦淮湧月來，一輪却掛鍾山上。", "山中那得有潮音，尊師鼻息如雷響。"]'),
('923255d3-c1d9-4eed-96e8-c31ac9f4ee73','題尹存庵行卷','陸文圭','宋','宋诗','song-poetry','','[]','錢塘築塢高於郿，黄金鑄成九鼎移。',96,'全唐诗/poet.song.248000.json','["錢塘築塢高於郿，黄金鑄成九鼎移。", "木棉羈魂招不得，方士入海從安期。", "廬陵二老當時在，翰墨光芒透紙背。", "爾後空聞化鶴歸，我今欲見啼鵑拜。", "長安市上重經過，逢人問是伯休那。", "勸君且尋遂初賦，人家國事竟如何。"]'),
('2a75ed6a-e125-431d-9fc7-a85e4bb09764','題分宜謝草廬行卷','陸文圭','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','袁曹官渡爭雌雄，荆州僑寄大耳翁。',208,'全唐诗/poet.song.248000.json','["袁曹官渡爭雌雄，荆州僑寄大耳翁。", "涕流髀肉消不盡，試與元直游隆中。", "隆中自有躬耕者，布衣抱膝茅簷下。", "從容一曲梁甫吟，不覺將軍三枉駕。", "室中屏人纔數語，跨荆包益成鼎峙。", "南陽陌上龍出雲，永安宮中魚得水。", "古今成敗真郵傳，英傑千年不一見。", "識拔端由品藻公，位置無嫌草茅賤。", "山中謝客江烟昏，誰携行卷到柴門。", "手披康樂草廬賦，知是蘭庭佳子孫。", "春塘柳禽成昨夢，炎興相業更誰論。", "洞庭三江風浪奔，鯨魚出沒相吐吞。", "何爲四方歸來些，山堂鶴怨能移文。"]'),
('da0328f7-21ac-4118-bc91-0cffacf1359e','題張南山慶九十詩卷','陸文圭','宋','宋诗','song-poetry','','[]','翁今百歲少十年，我少公年二十五。',112,'全唐诗/poet.song.248000.json','["翁今百歲少十年，我少公年二十五。", "天與翁齡百二十，我已化作原頭土。", "延年賸得飲食樂，損壽多應作詩苦。", "梅開儻獲登公堂，一醉猶能戴花舞。", "兒孫拍手向我語，公漆點鬚貝齊齒。", "降原陟巘步如飛，飽飯何曾飲人乳。", "夢中猶記前朝事，二老相逢必歡喜。"]'),
('3726b8e6-a2f7-4115-a428-a70c3b7af5b0','題王復初所藏子昂臨禊帖','陸文圭','宋','宋诗','song-poetry','','[]','昭陵玉函出人間，開平經今四百年。',128,'全唐诗/poet.song.248000.json','["昭陵玉函出人間，開平經今四百年。", "永和遠距貞觀先，俯仰陳跡俱可憐。", "古人學書如學仙，筆鋒誰入玄之玄。", "水晶宮裏佳公子，風流翰墨皆天然。", "我評逸少非真逸，史載深謀并絕識。", "獨留繭紙博千金，似是藝成能掩德。", "名士由來贋逼真，書空咄咄彼何人。", "遺才流落稽山下，修竹娟娟萬古春。"]'),
('119fd554-fac0-42fc-8006-9e4fcf955c59','題登瀛圖','陸文圭','宋','宋诗','song-poetry','','[]','世傳閻公學士圖，意象曠雅難形模。',224,'全唐诗/poet.song.248000.json','["世傳閻公學士圖，意象曠雅難形模。", "山僧臨本持索句，展卷復掩空長吁。", "秦王功高塞宇宙，搜攬豪雋供馳驅。", "內懷矛甲伺同氣，外示閒暇耽文儒。", "臨城開館構傑閣，坐見瀛海移西都。", "分番夕宿無厭倦，珍膳日給何豐腴。", "天光下照天策府，煌煌星象經天衢。", "房喬夜半進危計，平明一矢驚臨湖。", "群賢崛起輔貞觀，亦有淹滯如顔蘇。", "惜哉燕翼謀未善，祥麟接武容妖狐。", "殿階置笏怒未解，田舍收麥言何諛。", "策名書府真有靦，空與老姥扶天樞。", "貴人一代骨已朽，史筆千載心猶誅。", "閻公絕藝今亦無，長安落日明榛蕪。"]'),
('595d6953-8b20-437a-b4d1-c5f1ce8b1abe','跋明皇貴妃並馬圖','陸文圭','宋','宋诗','song-poetry','','[]','聲殘玉笛梨花月，笑指驪泉浴香雪。',144,'全唐诗/poet.song.248000.json','["聲殘玉笛梨花月，笑指驪泉浴香雪。", "宣來天駟玉花驄，醉僛金勒摇東風。", "阿環並轡微相顧，一點芳心倩鶑訴。", "五溪老奴侍鞍側，招摇先入華清路。", "行幸東西春復秋，那知憂樂兩相酬。", "朝元警蹕猶清道，胡馬長嘶出薊幽。", "猿聲霜冷巴山曉，錦襪遺香清渺渺。", "南內凄凉稀進御，海雲空闊蓬萊小。", "淚濕花容春雨餘，縱有丹青畫不如。"]'),
('cc17fc02-0264-441f-97d7-6bddd1ffc759','跋趙太祖與韓王蹴踘太宗石守信楚昭輔党進環而觀之','陸文圭','宋','宋诗','song-poetry','','[]','紫微垣近一小星，作戲敢與太陽敵。',64,'全唐诗/poet.song.248000.json','["紫微垣近一小星，作戲敢與太陽敵。", "諸將旁觀信雄武，不逃書記收兵策。", "開封府尹真天人，受譖朱崖疑老臣。", "幸自宮中啟金匱，忍使涪陵竟隕身。"]'),
('e6262010-db61-44c8-bf38-35e2326da118','題萬戶府瑞麥圖','陸文圭','宋','宋诗','song-poetry','','[]','河中之野木連理，文人作頌何所美。',160,'全唐诗/poet.song.248000.json','["河中之野木連理，文人作頌何所美。", "鯉湖之水蓮雙葩，史臣紀異不足誇。", "木葉饑來豈堪食，蓮花遠觀空有色。", "由來上瑞是豐年，芙蓉池外麥連天。", "一莖三穗攢秀穎，好事軍中萬口傳。", "閲武堂成政多暇，刀劍不如牛犢價。", "老農噉飯看昇平，奇祥異産從天下。", "香餌先收夏隴雲，雪匙可卜秋田稼。", "絕憐西蜀杜參謀，困饑空懷當世憂。", "崆峒麥熟無人穫，且問王師休未休。"]'),
('7ea656bf-3040-47c8-be23-271f433741ea','題劉晦卿月樓圖并餞秋闈之行仍不犯月樓字','陸文圭','宋','宋诗','song-poetry','','[]','君不見劉越石，晉陽鐵騎圍城急。',190,'全唐诗/poet.song.248000.json','["君不見劉越石，晉陽鐵騎圍城急。", "一聲長嘯震山谷，拋弓散走群兒泣。", "又不見庾元規，武昌僚佐相追隨。", "坐據胡牀夜笑語，不知賓主竟爲誰。", "枕戈待旦成何事，終讓著鞭先士稚。", "況復西風塵污人，茂宏舉扇思還第。", "嗟嗟二子逢世亂，誤長清談空致患。", "爭如今夕倚闌人，一生飽喫升平飯。", "百城桴鼓夜不鳴，萬里山川秋愈明。", "黄鶴孤飛白鷗睡，捲簾露氣下三更。", "初聽笛聲何激烈，再聽書聲更清越。", "素娥密約無人知，今秋丹桂來先折。"]'),
('bd181c9f-a86a-4f80-b164-ec23c5da59df','題金君澤家山飛雲圖','陸文圭','宋','宋诗','song-poetry','','[]','吳姿楚態誰使然，白石齒齒山娟娟。',88,'全唐诗/poet.song.248000.json','["吳姿楚態誰使然，白石齒齒山娟娟。", "孤雲欲斷不斷處，中有萬斛瀟湘烟。", "黄榆日晚長洲路，木葉山頭幾風雨。", "一聲寒雁江南書，萱草靈椿解相語。", "解相語，君應知。", "山風獵獵遊子衣，畢逋有待何當歸。"]'),
('f179a612-951a-4f90-990a-5a06575bd43d','應昌路驛傍有古松一榦生十八枝爲斧所傷江西胡生圖以示州長官命余作詩','陸文圭','宋','宋诗','song-poetry','','[]','盧龍迤北道應昌，八月飛雪六月霜。',160,'全唐诗/poet.song.248000.json','["盧龍迤北道應昌，八月飛雪六月霜。", "陰風蕭颯百草僵，牛羊隴坂狐兔岡。", "破郵古廟人鬼靜，傍植巨木百尺强。", "孤根綿綿蟄幽土，枝榦直上凌穹蒼。", "何年堂堂十八公，會朝侍立冠劍長。", "中有二公能死節，張許崛强存睢陽。", "餘生幸或逃斤斧，遠地何由選棟梁。", "西江行客苦好事，一見携之袖裏藏。", "摩挲老眼識奇怪，興作萬里神蒼茫。", "寒齋無復丁生夢，腹內惟聞葵藿香。"]'),
('6b042c25-785b-4e64-b1d1-099939fbd33c','唐人洗馬圖','陸文圭','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君不見雀鼠谷抵介休壁，馬甲不解王不食。',134,'全唐诗/poet.song.248000.json','["君不見雀鼠谷抵介休壁，馬甲不解王不食。", "又不見泰山馬色別爲群，東封望之如錦雲。", "英雄角力多相值，嬖倖承恩思自媚。", "不辭汗血千里勞，驅死塵沙那得避。", "何如落日清水灣，驊騮獨步春草閒。", "圉人袒肩沒兩踝，控轡欲上未上間。", "靜觀物理坐歎息，玉花慘淡何人筆。", "少陵野老最善評，弟子曾入將軍室。"]'),
('ef089ef6-88f7-4362-9d05-926177a057b0','跋牧馬圖','陸文圭','宋','宋诗','song-poetry','','[]','平原淺陂，水草甘美。',180,'全唐诗/poet.song.248000.json','["平原淺陂，水草甘美。", "枯梢吹風，日落塵起。", "物色祁連山前路，又似踰關渡隴水。", "一人解鞍枕欲睡，一人褶袴手仰指。", "一人持轡却回頭，萬馬攢蹄行復止。", "飲者嚙者各自然，馳者忽在立者前。", "駒而幼者隨壯者，浴者出沒晴波川。", "風騣雪尾不受鞭，並驅逐者如爭先。", "須臾兩騎獨殿後，戎笠持兵相格鬬。", "老羝挾乳自成群，牧羝人遠傍無救。", "何人丹青手摸寫，崿礴胸中有全馬。", "陸子作詩配駉野，千古傳流好事者。"]'),
('62cf04d9-5aeb-4783-ac3f-233dbacd0a77','栽桑','陸文圭','宋','宋诗','song-poetry','','[]','細聽鄰婦低眉說，年年育蠶苦無葉。',144,'全唐诗/poet.song.248000.json','["細聽鄰婦低眉說，年年育蠶苦無葉。", "山童執筐入市賣，一稱百錢猶未愜。", "更兼春雨土窗寒，忍見蠶饑頭戢戢。", "買絲織絹輸官外，空借鄰機閒一月。", "阿姑卒歲無繻袴，小兒露骭風吹裂。", "今時縣官清且明，課民務本令必行。", "擔桑赬肩荷鋤去，青青布種環郊城。", "明年家養一百箔，巷響繰車楝花落。", "滿籠新絲白雪香，聽賽蠶官鼓聲樂。"]'),
('6ab8dd49-1764-4b87-93c1-492db8eaf71b','賦燒筍竹字韻','陸文圭','宋','宋诗','song-poetry','','[]','先生朝槃厭苜蓿，筍味得全差勝肉。',160,'全唐诗/poet.song.248000.json','["先生朝槃厭苜蓿，筍味得全差勝肉。", "蒼頭掃地犀角出，赤燄騰烟龍尾禿。", "土膏漸竭外欲枯，火候微溫酒已熟。", "撥灰可惜衣殘錦，解籜猶憐膚躍玉。", "青青無日長兒孫，草草爲人供口腹。", "盧家丞相蒸葫蘆，石家無人煮豆粥。", "去毛留頂有何好，擣韭作虀空自速。", "不如野人工食淡，自辦行厨入修竹。", "句裏曾參玉版禪，胸中會著篔簹谷。", "主人不問不須嗔，昨夜西風響林屋。"]'),
('867b208a-ce09-4259-9198-aedd77898aaa','竹鶴窺棋雪字韻','陸文圭','宋','宋诗','song-poetry','','[]','秦馬投鞭江可竭，別墅從容謀已决。',128,'全唐诗/poet.song.248000.json','["秦馬投鞭江可竭，別墅從容謀已决。", "蘭階小兒呼與棋，敵手不覺平時劣。", "青岡鶴唳走先聲，捷書上牀屐齒折。", "局中勝負俄今古，身後功名謾豪傑。", "何如山中靜相對，風度幽篁韻清絕。", "林深有客遇神機，柯爛無人傳妙訣。", "白頭老姥獨解事，化作仙禽欲饒舌。", "石枰落子忽驚飛，五月驪山啄殘雪。"]'),
('757f5987-14ba-4a93-bdfa-f278aafad49b','四月八日偕張菊村鄧匪石洪樂閑遊城西諸寺以山高水長分韻得長字','陸文圭','宋','宋诗','song-poetry','','[]','門外青山寺，西行半里强。',48,'全唐诗/poet.song.248000.json','["門外青山寺，西行半里强。", "童分泉茗潔，僧供飯蔬香。", "地僻紅塵靜，心閑白日長。", "少年餘氣習，棋酒愧疏狂。"]'),
('290b89b8-7774-465d-8241-ab32978155fd','春雨歎','陸文圭','宋','宋诗','song-poetry','','[]','山城春强半，雨脚亂如麻。',48,'全唐诗/poet.song.248000.json','["山城春强半，雨脚亂如麻。", "潤麥還傷麥，催花又落花。", "閑來憂歲事，老去惜年華。", "卧聽空簷滴，應無夢到家。"]'),
('500a679a-8e08-4c8b-8ed2-9fb317dfb6b7','驟雨','陸文圭','宋','宋诗','song-poetry','','[]','絳帳虛堂設，簷牙雨驟傾。',48,'全唐诗/poet.song.248000.json','["絳帳虛堂設，簷牙雨驟傾。", "已過驚蟄日，未聽候蟲聲。", "向晚飛蚊出，偏工傍耳鳴。", "山靈戲窮士，邀喝夜相迎。"]'),
('e9745a95-337a-40cc-a141-9719ae13307c','立冬','陸文圭','宋','宋诗','song-poetry','','[]','早久何當雨，秋深漸入冬。',48,'全唐诗/poet.song.248000.json','["早久何當雨，秋深漸入冬。", "黄花猶带露，紅葉已隨風。", "邊思吹寒角，村歌相晚舂。", "籬門日高卧，衰懶愧無功。"]'),
('01d71b19-8425-47a0-bf06-2cfa50161c4a','夏港道中','陸文圭','宋','宋诗','song-poetry','','[]','微暖背曝日，輕寒面受風。',48,'全唐诗/poet.song.248000.json','["微暖背曝日，輕寒面受風。", "人行官路側，鵲起野田中。", "細草陳根綠，疏林病葉紅。", "故人雲水隔，來往愧衰翁。"]'),
('a8968d06-5d15-4c0f-a016-f5015d3284aa','高郵寶應道中','陸文圭','宋','宋诗','song-poetry','','[]','長淮昔戰爭，廢地少人耕。',48,'全唐诗/poet.song.248000.json','["長淮昔戰爭，廢地少人耕。", "野壁三家市，官亭十里程。", "田夫時識字，水鳥不知名。", "薄暮宿何處，孤雲又一城。"]'),
('e4225f32-cd0e-4b81-9fc2-abc3cdb78e96','客中度歲','陸文圭','宋','宋诗','song-poetry','','[]','歷遍青徐路，東風送入京。',48,'全唐诗/poet.song.248000.json','["歷遍青徐路，東風送入京。", "車中守殘歲，道上拜新正。", "椒酒今誰獻，桃符舊未更。", "故園梅正發，不見玉崢嶸。"]'),
('0d12c49d-14fb-4bff-9fc3-26406b9c38b6','喜雨上理同知','陸文圭','宋','宋诗','song-poetry','','[]','蒼蒼雖莫測，誠意儘能回。',48,'全唐诗/poet.song.248000.json','["蒼蒼雖莫測，誠意儘能回。", "履草穿雲去，爐香带雨來。", "神龍如有喜，旱魃不成災。", "四野車聲歇，歡聲却似雷。"]'),
('af615914-5d13-4f28-82b5-b0f335e4df1e','贄王容溪','陸文圭','宋','宋诗','song-poetry','','[]','勁竹持高節，餘花表晚香。',48,'全唐诗/poet.song.248000.json','["勁竹持高節，餘花表晚香。", "一瓢顔子巷，六籍鄭公鄉。", "後學師珪行，先天發寶藏。", "空携經世具，獨立暮山蒼。"]'),
('66ab2be4-ba68-4fe5-a195-74efe38810fa','和宋春卿寄詩韻二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','練江詩酒社，聚散十年春。',48,'全唐诗/poet.song.248000.json','["練江詩酒社，聚散十年春。", "君作并州客，身爲絳縣人。", "一牛甘送老，五馬未全貧。", "出處嗟殊異，相思意却真。"]'),
('5c3827cc-aaf6-42a6-a12f-44deff24eeff','和宋春卿寄詩韻二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','壯游不知倦，老境怕逢春。',48,'全唐诗/poet.song.248000.json','["壯游不知倦，老境怕逢春。", "自分無知己，何堪從避人。", "飛花空有恨，巢燕不嫌貧。", "獨憶延陵客，風流似季真。"]'),
('4aae367d-324d-4937-ab8d-e38c610c9704','和誼齋惠詩','陸文圭','宋','宋诗','song-poetry','','[]','鴞室徒勞甚，鳩居奈拙何。',48,'全唐诗/poet.song.248000.json','["鴞室徒勞甚，鳩居奈拙何。", "田園空歲晚，梅柳得春多。", "徑合思除蔓，墉高許附蘿。", "呼兒凈掃地，恐有故人過。"]'),
('559cbd1c-81c6-4d0e-8c24-22b79125791e','和心淵雷雨地震詩','陸文圭','宋','宋诗','song-poetry','','[]','天公惡作劇，翻手變炎凉。',48,'全唐诗/poet.song.248000.json','["天公惡作劇，翻手變炎凉。", "海運三山動，江高數尺彊。", "震雷驚失匕，漏雨苦移牀。", "不慮填溝壑，真成老更狂。"]'),
('4385774f-d1de-4d3d-92fa-1580a573ac69','奉和子華秋懷四首  其一','陸文圭','宋','宋诗','song-poetry','','[]','九日秋懷惡，那禁暑氣隆。',48,'全唐诗/poet.song.248000.json','["九日秋懷惡，那禁暑氣隆。", "苦吟愁作祟，多病藥無功。", "有客來相訪，扃門弗爲通。", "怕談當世事，遺患及孩童。"]'),
('f9bc8d3f-193d-41fb-8026-7a46d7087c57','奉和子華秋懷四首  其二','陸文圭','宋','宋诗','song-poetry','','[]','况值艱難日，那當老病身。',48,'全唐诗/poet.song.248000.json','["况值艱難日，那當老病身。", "後生欺舊輩，俗吏笑高人。", "易掃張超霧，難清庾亮塵。", "鹽梅正相得，鼎鼐盍調新。"]'),
('885e5ca4-a345-45cf-84df-8db74c0f2207','奉和子華秋懷四首  其三','陸文圭','宋','宋诗','song-poetry','','[]','痛飲消愁酒，愁城未肯降。',48,'全唐诗/poet.song.248000.json','["痛飲消愁酒，愁城未肯降。", "陰風吹北戶，斜日上西窗。", "艱食懸禾畝，苛征及葦江。", "何曾入官府，深愧鹿門龐。"]'),
('45bf50b2-056f-4cd2-a0e1-59b3867e86e0','奉和子華秋懷四首  其四','陸文圭','宋','宋诗','song-poetry','','[]','得志瘳民瘼，何期與願違。',48,'全唐诗/poet.song.248000.json','["得志瘳民瘼，何期與願違。", "青燈疏簡冊，黄土污征衣。", "道路嗟于役，山川賦式微。", "秋風動鱸興，應不踐危機。"]'),
('2d73abfb-9a29-4dfc-99c1-5996227f9baf','和唐人閑字韻詩卷','陸文圭','宋','宋诗','song-poetry','','[]','鼎鼎百年內，何由一日閑。',48,'全唐诗/poet.song.248000.json','["鼎鼎百年內，何由一日閑。", "衝冠無怒髪，攬鏡已蒼顔。", "未易桴浮海，應難屐上山。", "春逢甲子雨，愁聽溜潺潺。"]'),
('d76ae81e-9dc9-41e8-b59d-e1c9bc3fed86','贈游士艾介翁','陸文圭','宋','宋诗','song-poetry','','[]','三江懷故國，七澤弔孤臣。',48,'全唐诗/poet.song.248000.json','["三江懷故國，七澤弔孤臣。", "有客詩招隠，何心賦問鈞。", "明時無棄士，晚節少全人。", "游子歸何日，農工已及春。"]'),
('e38974e5-53e1-4ec5-a108-1701e1f157c7','丁酉春識慶上人于錢塘鄧君善之索余同賦孝僧詩余請以二十字盡記其實既成善之喜而書之不知何人持去後二年上人訪余江上復書以遺之','陸文圭','宋','宋诗','song-poetry','','[]','襁褓已離乳，干戈復異居。',48,'全唐诗/poet.song.248000.json','["襁褓已離乳，干戈復異居。", "關河行欲盡，母子遂如初。", "卓行先賢傳，前緣釋氏書。", "悲歡知已極，讚詠欲何如。"]'),
('b2f6a600-ebe6-4afc-b1d6-d2d3433d9f91','贈潘道士祈雨','陸文圭','宋','宋诗','song-poetry','','[]','日者旱太甚，天乎禱有諸。',48,'全唐诗/poet.song.248000.json','["日者旱太甚，天乎禱有諸。", "震雷驚破柱，驟雨喜隨車。", "精意通無間，神功斂不居。", "魯侯明德頌，好接有年書。"]'),
('cd64cbf3-c872-42a9-a708-5acae33776eb','送劉青璧湖北道按察','陸文圭','宋','宋诗','song-poetry','','[]','飄然南去客，使者趣揚舲。',48,'全唐诗/poet.song.248000.json','["飄然南去客，使者趣揚舲。", "白帝秋雲滑，黄牛暮雨腥。", "尋詩行楚甸，問酒宿巴汀。", "北道人多朴，無詞到訟庭。"]'),
('2efdf5c9-0c75-46e3-af0d-b67aef934d6e','送班同知','陸文圭','宋','宋诗','song-poetry','','[]','專城鎮西土，世祿食南方。',48,'全唐诗/poet.song.248000.json','["專城鎮西土，世祿食南方。", "紈袴洗餘習，簪纓襲舊芳。", "高風仰喬木，遺愛指甘棠。", "他日循良傳，應留姓字香。"]'),
('8991a94c-8dc8-40db-beab-c8390aa8843f','送楊伯可赴省','陸文圭','宋','宋诗','song-poetry','','[]','秋水芙蓉幕，時聞嘯諾歌。',48,'全唐诗/poet.song.248000.json','["秋水芙蓉幕，時聞嘯諾歌。", "簿書精力盡，臺省故人多。", "別酒禁愁得，交情奈久何。", "懷君四德備，廉正復謙和。"]'),
('fde2d964-ba08-44ec-9283-14b3cace66c7','丙申歲侯仲達之官洪澤','陸文圭','宋','宋诗','song-poetry','','[]','淮楚俗輕揚，蕭蕭古戰場。',48,'全唐诗/poet.song.248000.json','["淮楚俗輕揚，蕭蕭古戰場。", "殘兵空壁壘，曠野失農桑。", "魚蟹西風市，菰蒲淺水塘。", "君山足詩景，何事訪漁郎。"]'),
('399a0b3f-fa8f-48b7-981b-1e7025986604','送王縣尹之官湘潭','陸文圭','宋','宋诗','song-poetry','','[]','江亭重執手，雪壓暮潮平。',48,'全唐诗/poet.song.248000.json','["江亭重執手，雪壓暮潮平。", "臺閣踰三載，絃歌又一城。", "遺鄉因楚俗，令尹似湘清。", "別駕余知己，分廷託寄聲。"]'),
('e3ae4bf6-f478-4bcd-acf8-dc4fcbe3dfa6','送郭仁卿之官三衢','陸文圭','宋','宋诗','song-poetry','','[]','憲府自清要，胡爲墮冗曹。',48,'全唐诗/poet.song.248000.json','["憲府自清要，胡爲墮冗曹。", "平反猶用恕，糾錄肯辭勞。", "才富家何瘠，官卑志愈高。", "青雲遲得路，勝我落蓬蒿。"]'),
('f358c7a6-87f4-462e-ad2c-d5ba1cd63a79','送吳次尹惠州巡檢','陸文圭','宋','宋诗','song-poetry','','[]','萬古羅浮洞，江樓著老坡。',48,'全唐诗/poet.song.248000.json','["萬古羅浮洞，江樓著老坡。", "子西相繼出，廷秀晚經過。", "欲訪先賢去，其如遠道何。", "天寒與君別，莫聽扊扅歌。"]'),
('667fd853-a6ef-4e52-ba58-0bb0b830ae7d','察罕布哈教授滿別','陸文圭','宋','宋诗','song-poetry','','[]','小却官雖晚，先登藝最優。',48,'全唐诗/poet.song.248000.json','["小却官雖晚，先登藝最優。", "文章九州外，科目萬人頭。", "桂折金天月，芹空泮水秋。", "澄清頼君輩，憲府正旁搜。"]'),
('e39a1750-4e27-4a7c-a3bd-fcd260020c5e','送廣平孫教授','陸文圭','宋','宋诗','song-poetry','','[]','廣平河水北，古暨浙江南。',48,'全唐诗/poet.song.248000.json','["廣平河水北，古暨浙江南。", "兩地音郵闊，三年官况諳。", "采芹聊共樂，食蘗豈能甘。", "別酒黄梅浦，情懷老不堪。"]'),
('5e09a564-1166-4215-959b-dfad8ca5f63d','送句景范教授之官澧浦','陸文圭','宋','宋诗','song-poetry','','[]','南楚離騷國，清風澧有蘭。',48,'全唐诗/poet.song.248000.json','["南楚離騷國，清風澧有蘭。", "相從泮水樂，獨棹一江寒。", "遠地重逢少，新知欲別難。", "高平讀書室，好爲掃荒殘。"]'),
('4da5f302-2903-4f46-9762-efef4bedbe3c','送張慎與歸海陵侍養二首  其一','陸文圭','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','湖風吹柳絮，記別一年餘。',48,'全唐诗/poet.song.248000.json','["湖風吹柳絮，記別一年餘。", "君出當歸養，吾窮久索居。", "乍逢論繾綣，欲別又躊躇。", "一葦長江隔，時時卜鯉魚。"]'),
('4de135c9-9159-41ad-bbda-7bfd366e1555','送張慎與歸海陵侍養二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','英才銷落盡，世事一凭欄。',48,'全唐诗/poet.song.248000.json','["英才銷落盡，世事一凭欄。", "以我相思切，知君欲別難。", "暮雲南國暝，早雁北江寒。", "獨羨萊衣樂，春風鬢未皤。"]'),
('812bc138-93b8-46dd-a572-49aa17e8bb26','送周子華南歸二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','江城少公事，幕府得詩人。',48,'全唐诗/poet.song.248000.json','["江城少公事，幕府得詩人。", "乍見顔如舊，相思意轉親。", "不堪時事改，贏得鬢毛新。", "後夜孤舟別，西風漾月輪。"]'),
('4f5331d5-cb73-4768-af5e-69c316264cde','送周子華南歸二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','此日與君別，重逢未有期。',48,'全唐诗/poet.song.248000.json','["此日與君別，重逢未有期。", "衰年行欲盡，近事或難知。", "浩蕩風雲會，蕭條草木悲。", "三吳多俊傑，試與問安危。"]'),
('760fe57c-49be-4cb8-8392-ab21bd600864','送魏叔華歸越','陸文圭','宋','宋诗','song-poetry','','[]','閲世滄江上，柴門幾送迎。',48,'全唐诗/poet.song.248000.json','["閲世滄江上，柴門幾送迎。", "雲泥雖異路，車笠見交情。", "春雨西興渡，梅花古粵城。", "寄聲賣樵叟，莫羨錦衣榮。"]'),
('0fb816d8-e838-4e2c-96f2-c4a0227de7a9','送長蘆穆生歸鄉來別','陸文圭','宋','宋诗','song-poetry','','[]','聞君返桑梓，老我屏丘樊。',48,'全唐诗/poet.song.248000.json','["聞君返桑梓，老我屏丘樊。", "命駕輕千里，臨岐贈一言。", "爲山方進簣，有水必觀瀾。", "顔孟千年在，遺經得盡繙。"]'),
('01d0a2da-7505-4f57-ab72-931d62507c35','送張仁卿二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','四海張公子，騰書盛贊賢。',48,'全唐诗/poet.song.248000.json','["四海張公子，騰書盛贊賢。", "論心纔幾日，屈指遂經年。", "鶩案翻新牘，雞窗理舊編。", "遲君得小暇，已索贈遊篇。"]'),
('44e85f5c-0d92-4685-865e-c2d17708ed22','送張仁卿二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','作縣徒勞爾，飛黄服短轅。',48,'全唐诗/poet.song.248000.json','["作縣徒勞爾，飛黄服短轅。", "棄官真不惡，惜別却無言。", "再試知何地，孤生老是村。", "去逢南國友，梅嶺正花繁。"]'),
('b3a67347-ee82-411e-86cd-5c45629257de','送李正齋','陸文圭','宋','宋诗','song-poetry','','[]','龔黄吁已遠，循吏捨公誰。',48,'全唐诗/poet.song.248000.json','["龔黄吁已遠，循吏捨公誰。", "卧轍留行色，歸裝減到時。", "朝爭馳薦剡，郡議立生祠。", "寂寂燕臺客，難酬國士知。"]'),
('3567862f-2dcd-4b62-8d99-ef65bf5e18ad','送唐子華','陸文圭','宋','宋诗','song-poetry','','[]','海內多英俊，交情得似君。',48,'全唐诗/poet.song.248000.json','["海內多英俊，交情得似君。", "慇懃別後語，嗚咽病中聞。", "吟棹秋溪月，歸帆晚浦雲。", "可憐江樹隔，何日更論文。"]'),
('8f09dbc4-e9ae-40da-bee2-f2bf0e1c388b','送龐西山','陸文圭','宋','宋诗','song-poetry','','[]','行李不盈車，西風兩鬢華。',48,'全唐诗/poet.song.248000.json','["行李不盈車，西風兩鬢華。", "歷官多在考，歸蜀已無家。", "人去空芹水，舟行及藕花。", "飛騰君有日，吾計老桑麻。"]'),
('a7f8303f-207d-4d04-a42b-aebdf6ee6ab4','送汪太無道人','陸文圭','宋','宋诗','song-poetry','','[]','面带青山色，道人何處來。',48,'全唐诗/poet.song.248000.json','["面带青山色，道人何處來。", "一壺懸日月，兩袖裹風雷。", "鉛鼎養活火，寒爐撥死灰。", "出尋方外友，不語又空回。"]'),
('1e996653-1989-4ba9-850b-b90b233bf4dc','送麻姑山道人','陸文圭','宋','宋诗','song-poetry','','[]','麻姑一女子，處處有仙壇。',48,'全唐诗/poet.song.248000.json','["麻姑一女子，處處有仙壇。", "地古留遺跡，君今住此山。", "流泉清澗底，落日亂峰間。", "聞有蔡經者，時時得往還。"]'),
('ff8a76a5-12cc-4708-8d9d-ed837b6c43c3','病中寄諸友','陸文圭','宋','宋诗','song-poetry','','[]','五福人間有，吾兼疾與貧。',48,'全唐诗/poet.song.248000.json','["五福人間有，吾兼疾與貧。", "死寧遭疫鬼，生不媚錢神。", "採藥思方士，貽書荷故人。", "城東有別墅，風雨失殘春。"]'),
('682ee32b-a6bc-4fc2-ad9e-f75b19faca4c','病枕','陸文圭','宋','宋诗','song-poetry','','[]','瀟瀟風雨夜，病枕厭長更。',48,'全唐诗/poet.song.248000.json','["瀟瀟風雨夜，病枕厭長更。", "輾轉終無寐，呻吟不絕聲。", "鼠牙乘壁暗，雞翼報窗明。", "辛苦牀前婢，頻呼睡不驚。"]'),
('3d84fc42-d978-46d9-a46e-b083ff0ebfe8','病枕不寐','陸文圭','宋','宋诗','song-poetry','','[]','大率憂兼病，尤非老所宜。',48,'全唐诗/poet.song.248000.json','["大率憂兼病，尤非老所宜。", "吟愁枯兩鬢，時事鎖雙眉。", "瘦削嫌衾薄，醒眠覺漏遲。", "拒霜三五朵，應愛北風吹。"]'),
('20113628-c82b-47d4-8a9d-43f35628de14','病足','陸文圭','宋','宋诗','song-poetry','','[]','筋寒苦蹠盭，尊足詎能勝。',48,'全唐诗/poet.song.248000.json','["筋寒苦蹠盭，尊足詎能勝。", "誰謂行多露，全如履薄冰。", "城非靴可踢，階豈襪堪登。", "設有蒲輪召，安車未易乘。"]'),
('fcfad2eb-625f-4058-88fd-ec5032bf4e0a','許正卿傷臂','陸文圭','宋','宋诗','song-poetry','','[]','危機在平地，險不是丘陵。',48,'全唐诗/poet.song.248000.json','["危機在平地，險不是丘陵。", "偶爾一投足，幾乎三折肱。", "鞠躬難盡力，攘臂必須繩。", "他日三公貴，軺車好穩乘。"]'),
('4af92630-08f8-4bfb-887c-7076e292cff1','題張招討墓碑','陸文圭','宋','宋诗','song-poetry','','[]','輕兵戒深入，險寇勿窮追。',48,'全唐诗/poet.song.248000.json','["輕兵戒深入，險寇勿窮追。", "失勢因魚服，留名有豹皮。", "空歸先軫面，竟裹伏波尸。", "廟食真無愧，嵯峨死節碑。"]'),
('116b7f25-d510-4c46-96f2-81b96d103b55','題孔平山墓銘','陸文圭','宋','宋诗','song-poetry','','[]','東魯家猶在，尼山道最尊。',48,'全唐诗/poet.song.248000.json','["東魯家猶在，尼山道最尊。", "教能行萬世，福不庇諸孫。", "薄宦三千里，遺銘數百言。", "不埋防墓側，空弔雨花魂。"]'),
('f3b28a71-15e2-4e74-85b1-7b7d836771a9','挽閑閑真人父司徒','陸文圭','宋','宋诗','song-poetry','','[]','堂堂遺一老，五福壽而康。',48,'全唐诗/poet.song.248000.json','["堂堂遺一老，五福壽而康。", "系出安仁譜，身居榮祿鄉。", "春山樵獨隠，晚圃菊尤香。", "有子知何憾，騎龍下大荒。"]'),
('62b6e354-7dd8-442e-bc52-4799839c167f','挽朱自齋總管','陸文圭','宋','宋诗','song-poetry','','[]','郡紱雖重綰，齋銘祇自修。',48,'全唐诗/poet.song.248000.json','["郡紱雖重綰，齋銘祇自修。", "陰功淮海積，遺愛浙江留。", "世事桑田水，人生薤露秋。", "蓋棺奚復憾，簫鼓咽原頭。"]'),
('f74df67d-09fa-452d-b80b-d2591c5c7d3f','挽貢仲章學士','陸文圭','宋','宋诗','song-poetry','','[]','才優如貢禹，經行復精純。',48,'全唐诗/poet.song.248000.json','["才優如貢禹，經行復精純。", "海內多知己，江東尚有人。", "林泉隠君子，臺閣古名臣。", "九轉丹成去，青山宰木春。"]'),
('901f0729-83e6-4bab-9123-f0c18f9e0a88','挽吳朝奉','陸文圭','宋','宋诗','song-poetry','','[]','幼時桑梓敬，耆舊惜凋殘。',48,'全唐诗/poet.song.248000.json','["幼時桑梓敬，耆舊惜凋殘。", "蕭誡師吾儉，龐言遺以安。", "天乎非不壽，命也亦何歎。", "誰筆延陵墓，嗚呼永不刊。"]'),
('1fe8e02b-fa55-40ed-9ea9-8560abc5bf6c','挽許士元州判','陸文圭','宋','宋诗','song-poetry','','[]','有數應前定，浮生難豫期。',48,'全唐诗/poet.song.248000.json','["有數應前定，浮生難豫期。", "爲親嘗藥去，俄自載喪歸。", "循吏堪爲傳，遺民議立祠。", "靈輀無路送，老淚不勝揮。"]'),
('7df44b1f-e61f-4c59-a1c4-7a610a868fdf','李君美夫婦挽詩二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','君家全盛日，父子佩金魚。',48,'全唐诗/poet.song.248000.json','["君家全盛日，父子佩金魚。", "太母嘗甘旨，曾孫列起居。", "榮華既消歇，憂患却乘除。", "執紼門生老，何堪數輓車。"]'),
('17a94151-49ab-44e3-86ae-57ad64f37318','李君美夫婦挽詩二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','一死人誰免，如君獨可哀。',48,'全唐诗/poet.song.248000.json','["一死人誰免，如君獨可哀。", "離鸞不忍訣，止鵩併成災。", "從吏聯翩去，喪車寂寞回。", "淵明本無疾，早歲賦歸來。"]'),
('00030740-9c73-4a6a-af66-e9a172a3f272','挽孔東岡','陸文圭','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','此老典刑在，粹然瞻德容。',48,'全唐诗/poet.song.248000.json','["此老典刑在，粹然瞻德容。", "百年守經學，一邑號儒宗。", "泗水乾別派，泰山摧小峰。", "孝哉廬墓子，滴淚死青松。"]'),
('e8a61275-31b6-4e3f-a8e5-2d06f44d8260','挽沈梅溪','陸文圭','宋','宋诗','song-poetry','','[]','未游通德里，曾識謝家兒。',48,'全唐诗/poet.song.248000.json','["未游通德里，曾識謝家兒。", "鄉邑推先輩，山林養令姿。", "梅花記開落，江水閲興衰。", "耆舊凋零盡，西風老淚垂。"]'),
('06d7a050-bbd0-4cb2-b969-f57fd64b3ec9','挽趙石居','陸文圭','宋','宋诗','song-poetry','','[]','地望掄魁重，冰銜博士清。',48,'全唐诗/poet.song.248000.json','["地望掄魁重，冰銜博士清。", "棄官爲隠計，因謗得詩名。", "水竹方成趣，松楸忽愴情。", "鄉中耆舊盡，老淚灑銘旌。"]'),
('4a936afe-dc28-458d-9490-f0e359377c72','挽李德夫','陸文圭','宋','宋诗','song-poetry','','[]','一種金籯業，相傳五世餘。',48,'全唐诗/poet.song.248000.json','["一種金籯業，相傳五世餘。", "貧同司馬壁，富有善和書。", "四子供甘旨，諸生問起居。", "典刑無復在，丹旐泣隨車。"]'),
('9e77494b-f8e1-478c-bfdd-eb6f7ede6376','挽柴青山','陸文圭','宋','宋诗','song-poetry','','[]','衣冠百世祀，齒德一時尊。',48,'全唐诗/poet.song.248000.json','["衣冠百世祀，齒德一時尊。", "白馬朝京客，青山負郭門。", "廢興疑有數，生死復何言。", "空有懷賢淚，西風滴古原。"]'),
('58832cc5-2d6b-4693-8d49-4df4f97cc6b1','挽何漢卿','陸文圭','宋','宋诗','song-poetry','','[]','被服安儒素，行藏任性真。',48,'全唐诗/poet.song.248000.json','["被服安儒素，行藏任性真。", "終于太平世，奪我老成人。", "喬木蒼蒼古，孫枝奕奕新。", "西鄰聞夜笛，衰淚一霑巾。"]'),
('f6bfc8de-f4a5-419b-b14e-e8349477f0f5','挽朱南伯','陸文圭','宋','宋诗','song-poetry','','[]','爵齒不踰德，天乎奪此君。',48,'全唐诗/poet.song.248000.json','["爵齒不踰德，天乎奪此君。", "官纔稱主簿，郎已轉修文。", "玉質埋黄壤，葩辭散彩雲。", "從今書带草，不獨鄭公墳。"]'),
('5adf29ab-43ff-4099-b3ed-5fe0c0c8ed03','挽謝竹所','陸文圭','宋','宋诗','song-poetry','','[]','江左稱群謝，青山幾夕陽。',48,'全唐诗/poet.song.248000.json','["江左稱群謝，青山幾夕陽。", "田園遺一老，詩禮訓諸郎。", "勝日携樽樂，清風隠几忘。", "靈輀無路送，東望涕霑裳。"]'),
('77925e52-044c-4d5d-bd58-9b72a8660868','挽杜華父','陸文圭','宋','宋诗','song-poetry','','[]','鄉里多遺老，朝廷少用儒。',48,'全唐诗/poet.song.248000.json','["鄉里多遺老，朝廷少用儒。", "公初升國學，官止教生徒。", "衛道心猶壯，憂時骨已臞。", "遥知埋玉處，風雨暗山隅。"]'),
('3dd3693e-9c33-4e15-bd86-efc1317fc94f','挽趙鼎之','陸文圭','宋','宋诗','song-poetry','','[]','太息佳公子，樽中了此生。',48,'全唐诗/poet.song.248000.json','["太息佳公子，樽中了此生。", "吐茵人不怒，駡坐客皆驚。", "北闕名垂就，南柯夢已成。", "老親併弱子，此恨若爲平。"]'),
('a117519b-84fa-484c-8255-1ebac6ca66fa','挽榕山陳同年','陸文圭','宋','宋诗','song-poetry','','[]','勞勞百年內，人物老滄洲。',48,'全唐诗/poet.song.248000.json','["勞勞百年內，人物老滄洲。", "大志生難測，微官病即休。", "江花自終古，榕樹不禁秋。", "雌甲嗟猶在，哀詞淚不收。"]'),
('47e4e126-41f3-47bb-b79e-d0267cead317','挽邱景游二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','粹德如金玉，鄉人稱善人。',48,'全唐诗/poet.song.248000.json','["粹德如金玉，鄉人稱善人。", "百年蔭喬木，五子拱靈椿。", "桂管經行路，蒲龕宴坐身。", "今歸兜率去，弔客謾霑巾。"]'),
('49172c24-d9ef-4ec9-91e9-f0b161c996dc','挽邱景游二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','游公門下久，公亦眷吾深。',48,'全唐诗/poet.song.248000.json','["游公門下久，公亦眷吾深。", "疾病煩憂卜，詩詞辱賞音。", "衰年空滴淚，舊事獨傷心。", "秉筆書潜德，空疏力不任。"]'),
('e27adfc3-a4f3-4b81-a70c-ff136e4d2b49','挽俞時齋','陸文圭','宋','宋诗','song-poetry','','[]','襄陽耆舊傳，一覽涕無從。',48,'全唐诗/poet.song.248000.json','["襄陽耆舊傳，一覽涕無從。", "入社深衣叟，齋居糲食翁。", "市朝終不到，林澗或相逢。", "有子能傳業，棺衾得慎終。"]'),
('4a2bd3bf-b14d-446b-b965-687ed87607ca','立齋挽詩','陸文圭','宋','宋诗','song-poetry','','[]','少日增庭秀，暮年山澤臞。',48,'全唐诗/poet.song.248000.json','["少日增庭秀，暮年山澤臞。", "吟魂繞花竹，客淚灑江湖。", "莫唱貞元曲，空遺洛社圖。", "絕憐埋片玉，幸喜産雙珠。"]'),
('cef966dd-7c44-466a-9b84-fb52bb4f2814','挽陳葵心','陸文圭','宋','宋诗','song-poetry','','[]','遺才今已老，生計晚方宜。',48,'全唐诗/poet.song.248000.json','["遺才今已老，生計晚方宜。", "卧病經旬月，孤墳寄一隅。", "逢原惟有女，伯道竟無兒。", "執紼嗟何及，哀詞與淚俱。"]'),
('a53c2934-169d-4404-8d4d-1b7b8e86e2cc','挽何有開','陸文圭','宋','宋诗','song-poetry','','[]','捧檄垂三考，還家甫一旬。',48,'全唐诗/poet.song.248000.json','["捧檄垂三考，還家甫一旬。", "風雲千里志，露電百年身。", "講席辭多士，帷堂泣老親。", "三生有遺恨，五福少全人。"]'),
('f4ab09ef-db38-4186-86e0-7aad720c253f','代挽奉政陳公','陸文圭','宋','宋诗','song-poetry','','[]','江淮離舊隠，遼碣著新功。',48,'全唐诗/poet.song.248000.json','["江淮離舊隠，遼碣著新功。", "騄耳非凡馬，蒼髯獨老龍。", "韓銘空紀實，曾簀遂長終。", "先世盟猶在，寒山淚滴松。"]'),
('dd2e7ea6-8de9-4acf-90f7-706e26ac36f7','故夫人陳氏挽章四首  其一','陸文圭','宋','宋诗','song-poetry','','[]','誓節携孤幼，塵奩不復妝。',48,'全唐诗/poet.song.248000.json','["誓節携孤幼，塵奩不復妝。", "夜機同婦織，曉隴課僮秧。", "甘旨期終養，哀榮畢後喪。", "前岡指陶墓，弔鶴重凄凉。"]'),
('f0fd4f36-ac7a-4d7c-aa49-3f3ba52285fe','故夫人陳氏挽章四首  其二','陸文圭','宋','宋诗','song-poetry','','[]','白首萱堂上，兒孫卓有成。',48,'全唐诗/poet.song.248000.json','["白首萱堂上，兒孫卓有成。", "膝前分栗果，枕上聽書聲。", "鳳誥將金闕，鸞驂遽玉京。", "舍西蘿月夜，嗚咽隴泉鳴。"]'),
('7e4f411c-33ed-4d39-ad13-1debfad9e759','故夫人陳氏挽章四首  其三','陸文圭','宋','宋诗','song-poetry','','[]','憶昨升堂拜，通家指舊盟。',48,'全唐诗/poet.song.248000.json','["憶昨升堂拜，通家指舊盟。", "爲言兒有立，多頼友相成。", "喜檄方形色，哀銘忽愴情。", "生芻一掬淚，端爲玉人傾。"]'),
('09e3c118-9bc3-436f-82c5-5f27b7cabb23','故夫人陳氏挽章四首  其四','陸文圭','宋','宋诗','song-poetry','','[]','萱草北堂深，霜風一夕侵。',48,'全唐诗/poet.song.248000.json','["萱草北堂深，霜風一夕侵。", "斷機思往訓，捧檄負初心。", "仙府雲軿遠，佳城月魄陰。", "平生五鼎養，空復美衣衾。"]'),
('e33d692f-5fee-4b71-86f5-13429204f5f4','送衛月山歸鄉','陸文圭','宋','宋诗','song-poetry','','[]','臚傳居第一，科目艷當年。',144,'全唐诗/poet.song.248000.json','["臚傳居第一，科目艷當年。", "慷慨誅奸佞，從容秉政權。", "諸孫今白屋，舊物止青氈。", "幾見黄粱熟，何當鐵硯穿。", "書聲月廡下，燈影雨窗前。", "學者師王式，時人老伏虔。", "不令官濟濟，空負腹便便。", "桑葚鴞偏惡，桐花鳳可憐。", "縱無當食祿，猶有可耕田。", "卒卒纔傾蓋，依依願執鞭。", "二翁俱耄矣，一別重凄然。", "握手出門去，桂花香滿船。"]'),
('6ba1bc21-009e-4158-a262-b567ae58139d','挽張宗師','陸文圭','宋','宋诗','song-poetry','','[]','鳳歷歸明主，龍韜識老臣。',192,'全唐诗/poet.song.248000.json','["鳳歷歸明主，龍韜識老臣。", "衣冠朝日月，劍履步星辰。", "極品躋黄閣，齋居入紫宸。", "存心妙經緯，贊化極彌綸。", "道教崇簪笏，詞林壓搢紳。", "儉慈爲世寶，安樂是天民。", "夢卜親如見，祈禳立有神。", "穀城黄石老，衡岳白衣人。", "密勿天心契，便蕃帝渥新。", "壽尊來玉醴，法樂宴崇真。", "重錦頒衣襲，精糜享膳珍。", "青溪合瑶草，玄圃植靈椿。", "化鶴聲逾遠，飛鳬跡已陳。", "松青凋晚歲，林縞失殘春。", "世事柯山局，人生桑海塵。", "十齡傳正印，一德鏤堅珉。"]'),
('9d2dc3e4-4ee6-4f15-8419-e10156d6da0a','挽吳野堂','陸文圭','宋','宋诗','song-poetry','','[]','保護兵衝日，焦勞歲歉時。',84,'全唐诗/poet.song.248000.json','["保護兵衝日，焦勞歲歉時。", "江湖一老重，州里百年思。", "家尚玄元學，人遵義役規。", "陰功宜有後，隠德固應祠。", "擬作榮鄉記，誰鎸有道碑。", "碧梧雖未識，宿草尚堪悲。", "偶泊梅江堰，空吟薤露詩。"]'),
('bc9f5370-3a80-48c0-aced-dbda3bc277c9','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其一','陸文圭','宋','宋诗','song-poetry','','[]','外直中通異衆芳，嗅來葉氣勝花香。',64,'全唐诗/poet.song.248000.json','["外直中通異衆芳，嗅來葉氣勝花香。", "一杯先吸鑑湖月，滿口潜消玉井霜。", "尤勝朱櫻煎作蜜，何須紫蔗壓爲漿。", "細看象鼻彎彎曲，刺手猶嫌綠柄長。"]'),
('40b58208-5782-467b-8b55-fe1a6eac2463','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其二','陸文圭','宋','宋诗','song-poetry','','[]','昔宴賓僚避暑林，傳杯故事到如今。',64,'全唐诗/poet.song.248000.json','["昔宴賓僚避暑林，傳杯故事到如今。", "屈莖聊當黄金杓，刺葉先抽碧玉簪。", "聞得鼻端香馥馥，流從舌底味森森。", "坡仙愛釀柑爲酒，却道清蓮带苦心。"]'),
('41240d57-0a27-46fd-8f38-f394fade0338','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其三','陸文圭','宋','宋诗','song-poetry','','[]','有客相傳避暑方，採蓮不用採花房。',64,'全唐诗/poet.song.248000.json','["有客相傳避暑方，採蓮不用採花房。", "綠盤擎重盛珠露，碧管虛中溜玉漿。", "象鼻捲風隨手曲，麝臍入水透肌香。", "醒來忽憶涪翁句，摘實分甘共母嘗。"]'),
('f3abb074-f45b-431f-bf86-6adc305ebf55','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其四','陸文圭','宋','宋诗','song-poetry','','[]','碧雲影裏倚欄干，鯨吸詩人酒量寬。',64,'全唐诗/poet.song.248000.json','["碧雲影裏倚欄干，鯨吸詩人酒量寬。", "惟有鑑湖堪避暑，遥知玉井正生寒。", "簪開翡翠微通竅，滴下真珠滿走盤。", "一葉偶因風颭破，帕羅香沁幾時乾。"]'),
('0a803df0-9aa0-4b86-9f4c-874d918a8c1d','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其五','陸文圭','宋','宋诗','song-poetry','','[]','荷亭避暑約傳杯，醉引清風入手來。',64,'全唐诗/poet.song.248000.json','["荷亭避暑約傳杯，醉引清風入手來。", "象鼻形彎通曲柄，鴨頭色重潑新醅。", "中擎玉液休傾滿，半捲青心莫展開。", "春酒一江能吸盡，始知李白是仙才。"]'),
('4957e943-c868-48c0-95cd-4e304952d97e','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其六','陸文圭','宋','宋诗','song-poetry','','[]','當年避暑使君林，暇日諸賢肯過臨。',64,'全唐诗/poet.song.248000.json','["當年避暑使君林，暇日諸賢肯過臨。", "荷带露香須緩折，酒無風韻莫輕斟。", "玉簪先透玲瓏玉，金注徐傾瀲灧金。", "葉底可能甘勝蜜，却憐小苦是蓮心。"]'),
('88faa9ae-f924-42af-811f-c2aef5ca6f2e','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其七','陸文圭','宋','宋诗','song-poetry','','[]','不須酒盞吸雲紅，刺葉潜令與柄通。',64,'全唐诗/poet.song.248000.json','["不須酒盞吸雲紅，刺葉潜令與柄通。", "碧色輪囷彎到底，黄流瀲灧注當中。", "醉來欲捉波心月，醒後因吹水面風。", "却笑求仙求不得，金莖半折露盤空。"]'),
('02dbb37d-263e-469c-80bd-06360772f91f','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其八','陸文圭','宋','宋诗','song-poetry','','["\u897f\u6e56"]','露盤凈植水中央，好借詩人引玉觴。',64,'全唐诗/poet.song.248000.json','["露盤凈植水中央，好借詩人引玉觴。", "象鼻巧能通葉柄，馬蹄更與摘蓮房。", "吸川不覺西湖闊，漱石尤便玉井凉。", "醉裏興來休折遍，也留數葉覆鴛鴦。"]'),
('aea9cee0-018d-46e6-9d4d-f103c393e33e','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其九','陸文圭','宋','宋诗','song-poetry','','[]','越溪女子翠紅裳，來與群仙侑一觴。',64,'全唐诗/poet.song.248000.json','["越溪女子翠紅裳，來與群仙侑一觴。", "葉展圓盤如許大，絲連曲柄更能長。", "清高勝飲金莖露，甘滑疑餐玉薤霜。", "醉手傳杯猶未穩，碧痕微損迸瓊漿。"]'),
('c5dfdd5f-db68-465f-82ec-865918f5030d','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其一○','陸文圭','宋','宋诗','song-poetry','','[]','樽罍自古宴嘉賓，末世風流意轉新。',64,'全唐诗/poet.song.248000.json','["樽罍自古宴嘉賓，末世風流意轉新。", "筒葉捲來由鄭氏，杯荷製出始唐人。", "一時花草空傳玩，他日賓僚但飲醇。", "外直中通比君子，輸他光霽滿懷春。"]'),
('d3dda69b-6380-4bba-9b4a-97bdf758e9af','洛中鄭慤三伏之際率賓僚避暑于使君林取大蓮葉盛酒以簪刺葉令與柄通屈莖輪囷如象鼻焉傳吸之名碧筒杯故坡詩云碧碗猶作象鼻彎白酒時带蓮心苦丙寅五月宜興州賞誠以此爲題爲賦十一首  其一一','陸文圭','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','刺葉爲筩製頗奇，鄭公故事老坡詩。',64,'全唐诗/poet.song.248000.json','["刺葉爲筩製頗奇，鄭公故事老坡詩。", "擎來入手成欹器，注在當心即漏巵。", "玉露有香黏翡翠，碧雲無影浸琉璃。", "假饒吸盡西江水，鉢內生蓮是幾時。"]'),
('2b503874-d8b5-410a-ae84-e0b37f4a674b','孟德孔明','陸文圭','宋','宋诗','song-poetry','','[]','孔明孟德兩馳驅，三國人才信有餘。',64,'全唐诗/poet.song.248000.json','["孔明孟德兩馳驅，三國人才信有餘。", "未肯草廬終此世，不知精舍讀何書。", "木牛古不傳遺法，銅雀今成一廢墟。", "畢竟忠邪天不識，當年成敗復何如。"]'),
('6f288640-e710-487a-95f6-fd07f30ded51','與琴師談琴','陸文圭','宋','宋诗','song-poetry','','[]','至樂無聲識者希，有聲終是假人爲。',64,'全唐诗/poet.song.248000.json','["至樂無聲識者希，有聲終是假人爲。", "一時得趣惟元亮，千載知音欠子期。", "欲寫性情初動處，當原律呂未生時。", "夜寒月照虛堂壁，鶴唳猿吟總是詩。"]'),
('6029f00d-1336-4ef8-98d7-60d7ae244e84','癸酉三月園亭小飲之明日又適澹齋所薄暮醉歸廣文寄佳句二首走筆次韻  其一','陸文圭','宋','宋诗','song-poetry','','[]','名花濃淡總相宜，對此如何不醉歸。',64,'全唐诗/poet.song.248000.json','["名花濃淡總相宜，對此如何不醉歸。", "絲竹既無娛朗日，園林可是樂清時。", "蛙聲閣閣那成部，蝶陣團團戲作圍。", "酸杏不堪嘗煮酒，纍垂空自壓青枝。"]'),
('4f1a7f5b-e822-42e9-9895-9d67649aa905','癸酉三月園亭小飲之明日又適澹齋所薄暮醉歸廣文寄佳句二首走筆次韻  其二','陸文圭','宋','宋诗','song-poetry','','[]','綠陰未暗漸紅稀，逢閏春遲一月歸。',64,'全唐诗/poet.song.248000.json','["綠陰未暗漸紅稀，逢閏春遲一月歸。", "古有惜花如子美，今無好客似當時。", "酒雖薄薄聊澆渴，棋亦平平旋解圍。", "斜日倚闌人半醒，試尋青子摘梅枝。"]'),
('8b305c80-51d5-4920-aa76-ce696013aa3b','同善之仲實無逸遊飲夜歸分韻得星字','陸文圭','宋','宋诗','song-poetry','','[]','歲華摇落江頭樹，客子漂流海上萍。',64,'全唐诗/poet.song.248000.json','["歲華摇落江頭樹，客子漂流海上萍。", "盡染緇衣無復素，空留白眼爲誰青。", "對牀便可供高卧，把酒何妨弔獨醒。", "太息此心徒炯炯，奈何余髪已星星。"]'),
('95b4f603-7ebf-4299-a750-bc591795f784','八月初游君山誼齋有詩同賦二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','曉渚風移畫舫輕，秋原日射繡衣明。',64,'全唐诗/poet.song.248000.json','["曉渚風移畫舫輕，秋原日射繡衣明。", "自携玉麈看山色，盡屏繁絃聽水聲。", "季子高風喬木古，春申往事暮潮平。", "塔鈴自語無人會，飲散江空霽月生。"]'),
('8b667ecd-49ed-4348-92c6-44bb574d1d09','八月初游君山誼齋有詩同賦二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','此山猶姓楚春申，珠履風流幾斛塵。',64,'全唐诗/poet.song.248000.json','["此山猶姓楚春申，珠履風流幾斛塵。", "樽俎一時俱上客，興亡千載屬何人。", "蕭蕭病葉悲霜木，采采幽花識澗蘋。", "白鷺不知今古事，臨江一笑岸綸巾。"]'),
('e750f472-b222-4096-84b1-1b09112a7194','句容賦歸','陸文圭','宋','宋诗','song-poetry','','[]','誰教老子誤諸君，幸自庵中卧白雲。',64,'全唐诗/poet.song.248000.json','["誰教老子誤諸君，幸自庵中卧白雲。", "舊令尹非新令尹，今將軍是故將軍。", "相知自謂樂莫樂，一見不如聞所聞。", "逋客急須回俗駕，北山早已有移文。"]'),
('ca8e2277-3441-4512-9156-f83e3d89bd5b','迴途入玉晨觀圖經云周時太史郭真人宅周安得有真人哉有丹井養龍池白馬老君瑞像在焉壁間刻林靈素塵字韻詩戲次二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','洗凈人間萬斛塵，玉虛壇上夜朝真。',64,'全唐诗/poet.song.248000.json','["洗凈人間萬斛塵，玉虛壇上夜朝真。", "井深莫探丹泉髓，屋小難容老檜身。", "符召得龍聊小戲，料分與鶴未全貧。", "名山採藥無空返，不見仙方見異人。"]'),
('5a5b7f3d-4047-4f6b-8bf1-a1713deaedf1','迴途入玉晨觀圖經云周時太史郭真人宅周安得有真人哉有丹井養龍池白馬老君瑞像在焉壁間刻林靈素塵字韻詩戲次二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','太虛自是隔凡塵，惟恨神霄事不真。',64,'全唐诗/poet.song.248000.json','["太虛自是隔凡塵，惟恨神霄事不真。", "泥馬空遺玄聖像，池魚恐是小龍身。", "久知天上仙官貴，不救山中道士貧。", "舊宅固應存太史，徽稱早已號真人。"]'),
('27c7bebe-fc7f-4b86-b8c0-15883e4ec9e2','無文上人捨財鳩工建新安橋普濟衆生聞者讚歎隨喜賦詩一首','陸文圭','宋','宋诗','song-poetry','','[]','高僧自有神通力，杖錫橫空搭兩堤。',64,'全唐诗/poet.song.248000.json','["高僧自有神通力，杖錫橫空搭兩堤。", "會見大夫乘駟馬，寧無學士助腰犀。", "一溪帆影浪花轉，百尺欄桿石笋齊。", "有客天津閑信步，杜鵑聲裏夕陽西。"]'),
('4ae3ef19-9280-4cfd-a97d-8048849e35e2','七月二十九日夜大醉宿陸宣慰廨旦日以一詩謝之','陸文圭','宋','宋诗','song-poetry','','[]','夜行被酒止公亭，耳熱呼烏坐盡驚。',64,'全唐诗/poet.song.248000.json','["夜行被酒止公亭，耳熱呼烏坐盡驚。", "甕下自慚非畢子，吐中不覺卧王生。", "相寬吏舍情何厚，誤污車茵罪亦輕。", "戲馬倘容賓落帽，更拚投轄飲天明。"]'),
('851ed8bf-0c5a-4f0c-aef6-1073323ffe6a','柬人索酒','陸文圭','宋','宋诗','song-poetry','','[]','不到青州已月餘，麴生風味近何如。',64,'全唐诗/poet.song.248000.json','["不到青州已月餘，麴生風味近何如。", "東坡杯小君應怪，北海樽空客漸稀。", "奇士正堪來問字，癡人那復肯還書。", "分田種秫嗟何晚，獨盼庭柯望白衣。"]'),
('5cd88dfe-9cb4-48bf-9dee-93a46e210dd3','中秋見梅','陸文圭','宋','宋诗','song-poetry','','[]','雁叫霜寒木葉飛，西風亭下立瑶姬。',64,'全唐诗/poet.song.248000.json','["雁叫霜寒木葉飛，西風亭下立瑶姬。", "從來冷淡能禁雪，不意孤高也競時。", "松友舊盟寒歲晚，桂華佳約赴秋期。", "倚窗索笑空姝媚，汝解能寬宋玉悲。"]'),
('75beca48-57fc-48e5-b609-4af267c4e9c9','十月下旬驟寒小雪','陸文圭','宋','宋诗','song-poetry','','[]','朔風翻屋浪喧豗，潑墨濃陰掃不開。',64,'全唐诗/poet.song.248000.json','["朔風翻屋浪喧豗，潑墨濃陰掃不開。", "天下撒來雲母粉，人間喚作豆稭灰。", "細民共喜宜新麥，老子先須探早梅。", "爲怕玉容禁不得，數枝和淚折將來。"]'),
('7186d6d4-dd09-4f50-a202-ac87c7635bcf','雪江獨釣','陸文圭','宋','宋诗','song-poetry','','[]','極浦寒雲壓雁低，石磯老叟手如龜。',64,'全唐诗/poet.song.248000.json','["極浦寒雲壓雁低，石磯老叟手如龜。", "茫茫沙上銀千頃，裊裊風前玉一絲。", "鷺失蘆花驚月早，魚吹柳絮上冰遲。", "故人物色嫌相認，縱有羊裘不敢披。"]'),
('5c17f0da-fe7d-4b7d-b919-66a762dad9b8','虎丘留題辛卯三月書于劍池','陸文圭','宋','宋诗','song-poetry','','[]','霸業荒丘春草長，只聽兒女話真娘。',64,'全唐诗/poet.song.248000.json','["霸業荒丘春草長，只聽兒女話真娘。", "虎來墓上猶應怪，鹿入宮中儘可傷。", "太息乾坤空浩蕩，不留豪傑管興亡。", "屬鏤抱恨沈江底，潭碧猶生古劍光。"]'),
('d45e829d-b795-4563-877a-aa02ef9e07eb','辛卯入杭呈王察判  其一','陸文圭','宋','宋诗','song-poetry','','[]','中州人物古猶今，復見風流正始音。',64,'全唐诗/poet.song.248000.json','["中州人物古猶今，復見風流正始音。", "當日乘驄持繡斧，他年化鶴度青林。", "誰知救世安民術，即是求仙訪道心。", "鯨浪駕風吹未散，溪山何處獨追尋。"]'),
('9cdc8548-cca3-49ce-a1bc-2b55a8b77281','辛卯入杭呈王察判  其二','陸文圭','宋','宋诗','song-poetry','','[]','古人糟粕在遺經，聖學非由積累成。',64,'全唐诗/poet.song.248000.json','["古人糟粕在遺經，聖學非由積累成。", "每向同中參孔釋，時於異處別朱程。", "一川水滿源頭活，半夜天高月色明。", "下學工夫遲十載，小儒終是霧中行。"]'),
('a2c27c21-508d-42be-b238-a49946149beb','入杭懷古呈史药房','陸文圭','宋','宋诗','song-poetry','','["\u897f\u6e56"]','某丘某水記兒時，陳迹迷茫問不知。',64,'全唐诗/poet.song.248000.json','["某丘某水記兒時，陳迹迷茫問不知。", "觀裏看花空有菜，山南種豆落爲萁。", "林疏想弋逋仙鶴，壁壞應墁坡老詩。", "只怪西湖頑面目，濃妝猶自學西施。"]'),
('ba3e0b1f-2d28-478b-8e32-f9e43dd41884','浙西道院并題雙檜詩','陸文圭','宋','宋诗','song-poetry','','[]','黄堂曾著宰官身，彷彿兒時記不真。',64,'全唐诗/poet.song.248000.json','["黄堂曾著宰官身，彷彿兒時記不真。", "圖誌雖存千載舊，棟梁安有百年新。", "繁華開落無三日，雙檜輪囷經幾春。", "應比首陽高節士，採薇不食爲求仁。"]'),
('e3c13a1a-a471-4a44-9e1a-35ae5260f14f','苦雨','陸文圭','宋','宋诗','song-poetry','','[]','積雨能令朱夏寒，少曾見日上三竿。',64,'全唐诗/poet.song.248000.json','["積雨能令朱夏寒，少曾見日上三竿。", "風吹滄海俄然立，水瀉銀河透底乾。", "誰辦好心來拯溺，姑留老眼去觀瀾。", "蛙聲只在牆根草，却怪泥龍不久蟠。"]'),
('24e8e3f1-604d-4421-b7eb-da524b5626f1','居高明','陸文圭','宋','宋诗','song-poetry','','[]','每愁仲夏多溽暑，更逢今歲少南風。',64,'全唐诗/poet.song.248000.json','["每愁仲夏多溽暑，更逢今歲少南風。", "身無臺榭可獨處，眼到山川便不同。", "直從月令高明處，參透中庸問學功。", "虛靜若能超物外，炎凉何必介胸中。"]'),
('81151f5c-89b1-44aa-a982-d6a8fc364aa1','七夕祈雨','陸文圭','宋','宋诗','song-poetry','','[]','彩雲朵朵西風散，銀漢昭昭北斗傾。',64,'全唐诗/poet.song.248000.json','["彩雲朵朵西風散，銀漢昭昭北斗傾。", "車上耕夫愁欲泣，橋邊織女笑相迎。", "蝗飛近境行將及，龍卧深淵自不驚。", "病枕怕聞簫鼓閙，誰家乞巧到天明。"]'),
('334b0395-6720-47d3-a6e7-483da9bc10ed','偶書邸壁','陸文圭','宋','宋诗','song-poetry','','[]','俯仰隨人似桔槔，功名落落倦英豪。',64,'全唐诗/poet.song.248000.json','["俯仰隨人似桔槔，功名落落倦英豪。", "婆娑僅可供賓戲，寂寞安能免客嘲。", "空有雲心懷鶴髪，竟無風力舉鴻毛。", "祖劉起舞成何事，歲晚柴桑是故交。"]'),
('38a95c6d-a70e-4973-8416-96f2212797bc','效後村體','陸文圭','宋','宋诗','song-poetry','','[]','十載村居學養恬，未忘習氣有人嫌。',64,'全唐诗/poet.song.248000.json','["十載村居學養恬，未忘習氣有人嫌。", "課僮薙草心先快，助僕移梅力尚兼。", "不分烏鴉啼錦樹，絕憐紫燕傍茅簷。", "路逢野老閒相問，新歲凶穰可豫占。"]'),
('ad84f3e9-0cf2-4ad8-a41e-9d11b683fb4e','有感三首  其一','陸文圭','宋','宋诗','song-poetry','','[]','場屋當年負雋聲，白頭牢落竟何成。',64,'全唐诗/poet.song.248000.json','["場屋當年負雋聲，白頭牢落竟何成。", "一生受用兔園冊，千載應無麟閣名。", "被服易招山鳥怪，題詩難學野狐精。", "羊裘老棄漁灘上，印綬新加少傅榮。"]'),
('4f2b2c43-cadb-4c22-adca-d6164fb0b57c','有感三首  其二','陸文圭','宋','宋诗','song-poetry','','[]','子美間關離亂際，堯夫生長太平年。',64,'全唐诗/poet.song.248000.json','["子美間關離亂際，堯夫生長太平年。", "可憐橡栗天寒拾，不似鶑花日晏眠。", "憂樂在人均是命，盛衰有數總由天。", "腐儒老矣無奇計，獨立斜陽意惘然。"]'),
('536deb76-a9a8-4961-bfb7-31bfe680ea31','有感三首  其三','陸文圭','宋','宋诗','song-poetry','','[]','歲晚田園半已蕪，緇塵衮衮落征途。',64,'全唐诗/poet.song.248000.json','["歲晚田園半已蕪，緇塵衮衮落征途。", "送窮不見昌黎富，乞巧翻成子厚愚。", "瓿下早知嘲尚白，缶邊何似醉呼烏。", "鳶肩枉作常何客，只合新豐伴酒徒。"]'),
('4330be68-f9f2-4e96-bceb-b047e64e6ff6','闕題','陸文圭','宋','宋诗','song-poetry','','[]','區區抱甕不辭勞，俯仰安能似桔槔。',64,'全唐诗/poet.song.248000.json','["區區抱甕不辭勞，俯仰安能似桔槔。", "兒子從教耀車服，丈夫何用樹旌旄。", "但思有酒身無事，始信求田策最高。", "妄想虛憍無處著，退然斂手是英豪。"]'),
('8fd6ed3a-4fb1-46e3-8532-599e9a5f2868','黄山上先冢舊葬處','陸文圭','宋','宋诗','song-poetry','','[]','一盂麥飯一豚肩，寒食風花淚眼邊。',64,'全唐诗/poet.song.248000.json','["一盂麥飯一豚肩，寒食風花淚眼邊。", "倘得黄泉相見母，勝如白日上升天。", "萬家置去成何用，雙鶴飛來亦偶然。", "事死如生莫言孝，幾曾廬墓過三年。"]'),
('ddd65364-34c1-4187-9d21-ca8ee709a00b','庚午三月初九日寒食有感','陸文圭','宋','宋诗','song-poetry','','[]','祭筵跪拜膝難擡，連歲何曾上冢來。',64,'全唐诗/poet.song.248000.json','["祭筵跪拜膝難擡，連歲何曾上冢來。", "老子七旬看又過，幻身多病復相催。", "人間願棄姑云耳，地下從遊亦壯哉。", "寒食江村舊行路，道旁相弔總悲哀。"]'),
('a3274a5c-5ecb-40fe-9489-d5a3517c975c','連日食粥兒輩慍見示之以詩','陸文圭','宋','宋诗','song-poetry','','[]','抄書燈下語吾兒，歉歲艱辛汝未知。',64,'全唐诗/poet.song.248000.json','["抄書燈下語吾兒，歉歲艱辛汝未知。", "坡老忍饑常并日，少游厭粥亦多時。", "但令後世師吾儉，深怪諸人遺以危。", "天意從今吾儘解，窮人大抵欲昌詩。"]'),
('c774eef7-19c2-4c55-b66f-ff4d6219a780','耳聵二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','幾年本分做家公，雖是癡頑幸不聾。',64,'全唐诗/poet.song.248000.json','["幾年本分做家公，雖是癡頑幸不聾。", "何必張皇驚鬬蟻，更須辛苦望攀龍。", "濕窗暗想催花雨，開戶遥知戛竹風。", "問夜何其將夜半，元來野寺已鳴鐘。"]'),
('b7b4a215-0ec8-4c28-8cb0-0e38be6e0523','耳聵二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','血氣衰微性不靈，非非是是幾曾聽。',64,'全唐诗/poet.song.248000.json','["血氣衰微性不靈，非非是是幾曾聽。", "胸中不著許多事，天下本來無正聲。", "但覺颼颼戰風雨，誰知虩虩震雷霆。", "先生耐靜坐終日，怪底作勞吾耳鳴。"]'),
('de1c2130-ba8a-4eed-b358-edf79b878b4b','齎科詔使臣索詩','陸文圭','宋','宋诗','song-poetry','','[]','紫泥詔下九重天，文治初興正急賢。',64,'全唐诗/poet.song.248000.json','["紫泥詔下九重天，文治初興正急賢。", "草木輝光霑雨露，鳶魚鼓舞樂天淵。", "雲衢接武懷新渥，雪案潜心理舊編。", "禮樂三千攄素藴，丹墀他日聽臚傳。"]'),
('e015cd05-d09d-49d0-97f1-d79d566abf1c','贄楊子裕中丞','陸文圭','宋','宋诗','song-poetry','','[]','堂堂四世三公後，今日乘驄出案臨。',64,'全唐诗/poet.song.248000.json','["堂堂四世三公後，今日乘驄出案臨。", "坐上即時聞減樂，袖中雖暮不懷金。", "官民乘訪皆公論，獄卒平成有恕心。", "古柏臺邊霜氣冽，肯分春意到寒林。"]'),
('0ce16964-bd14-4d17-a41e-a1c9feb15722','贄尤端木二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','漢家陵闕已蒼烟，魯國靈光獨巋然。',64,'全唐诗/poet.song.248000.json','["漢家陵闕已蒼烟，魯國靈光獨巋然。", "衛玠音聞永嘉末，陶潜詩著義熙前。", "可憐閣下投幾死，不及車中寢獲全。", "寄語牙郎莫酬價，匵中韞玉可求旃。"]'),
('264b4280-f635-46dc-9025-12e010b603db','贄尤端木二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','萬里梯航走貢珍，乾坤無地著孤臣。',64,'全唐诗/poet.song.248000.json','["萬里梯航走貢珍，乾坤無地著孤臣。", "湘江空記庚寅渡，石壁曾題癸巳人。", "國士猶嫌先事范，仙家莫問幾經秦。", "願提草履從君後，煮茗寒泉代拾薪。"]'),
('3e1fa787-2af9-4090-bce9-e5617f50890c','代上樂平傅知州初庵','陸文圭','宋','宋诗','song-poetry','','[]','一代風流獨老庵，再扶道脈起東南。',64,'全唐诗/poet.song.248000.json','["一代風流獨老庵，再扶道脈起東南。", "家聲可與諸洪繼，易學曾同小阮參。", "晝錦羨君榮世胄，寒氈容我坐清談。", "願爲藥籠中間物，才匪芝苓愧不堪。"]'),
('679f7dee-51ae-48f3-a0c8-bcb89ee01b28','壽常州路達嚕噶齊','陸文圭','宋','宋诗','song-poetry','','[]','蓬山閣上冠群賢，出擁朱旛浙水邊。',64,'全唐诗/poet.song.248000.json','["蓬山閣上冠群賢，出擁朱旛浙水邊。", "但看兩州歌善政，宜膺多福享遐年。", "當生自是長生佛，未老應爲不老仙。", "欲就瓣香稱壽去，梅林一夕漲江天。"]'),
('c8f605ee-6d0b-4bfe-ba6f-5baaa23b46ac','壽與可錄判','陸文圭','宋','宋诗','song-poetry','','[]','濯錦峨嵋誇最勝，子昂太白記前生。',64,'全唐诗/poet.song.248000.json','["濯錦峨嵋誇最勝，子昂太白記前生。", "一川風雨睡正熟，千頃波濤心不驚。", "手試功名棋勝負，眼看富貴槿枯榮。", "壽杯肯向人間飲，携傍蓮峰玉井傾。"]'),
('9e2fbbd0-3b97-4266-bd3c-5f6771881d8f','壽陸雲閑道判','陸文圭','宋','宋诗','song-poetry','','[]','誕日曾生陸地花，雙鸞扶下五雲車。',64,'全唐诗/poet.song.248000.json','["誕日曾生陸地花，雙鸞扶下五雲車。", "安期共約游三島，方朔應留醉九霞。", "盛集儒流勝仙侶，多培陰德種丹砂。", "冷齋書客來稱壽，自笑東風兩鬢華。"]'),
('9542190e-2004-47f0-9a2a-0af49c66c64b','史药房壽與東坡同日','陸文圭','宋','宋诗','song-poetry','','[]','日月同生豈偶然，聲名不減雪堂仙。',64,'全唐诗/poet.song.248000.json','["日月同生豈偶然，聲名不減雪堂仙。", "岷峨西去八千里，蘇史相望二百年。", "赤壁舊磯如昨否，李生新曲至今傳。", "祝公壽比南飛鶴，共結梅花歲歲緣。"]'),
('fd845d0a-4fdf-4322-9ede-c1d5ac7636a5','壽陸義齋  其一','陸文圭','宋','宋诗','song-poetry','','[]','歸棹石門江水長，肯留一片廣州香。',64,'全唐诗/poet.song.248000.json','["歸棹石門江水長，肯留一片廣州香。", "不須人祝千年壽，但願公流百世芳。", "長侍潘輿游故里，勝持漢節落南荒。", "芙蓉金菊秋風逕，好和陶辭引玉觴。"]'),
('0e9cd9d9-f04e-4c1e-b7a3-a7bea62c29ce','壽陸義齋  其二','陸文圭','宋','宋诗','song-poetry','','[]','綠髪仙童馭彩鸞，九秋彌節下人間。',64,'全唐诗/poet.song.248000.json','["綠髪仙童馭彩鸞，九秋彌節下人間。", "明分月影山河動，清入霜華草木寒。", "已報除書來北闕，不妨拄笏看西山。", "霞杯淺注黄花酒，留取餘香晚節看。"]'),
('b45ac585-1210-4064-990e-b3e2dcfa2bb6','壽李侍郎母','陸文圭','宋','宋诗','song-poetry','','[]','雙成遥下五雲車，獻壽仙杯吸紫霞。',64,'全唐诗/poet.song.248000.json','["雙成遥下五雲車，獻壽仙杯吸紫霞。", "愛惜孫枝長萱草，摩挲老樹著桃花。", "斑衣就養榮三釜，錦誥分封備六珈。", "他日肩輿扶上殿，侍郎正踏相堤沙。"]'),
('f8a1d064-d542-46a6-9527-9ff3b4ceb00c','寄戴帥初先生','陸文圭','宋','宋诗','song-poetry','','[]','詞章科目溯當年，璧水名流孰子先。',64,'全唐诗/poet.song.248000.json','["詞章科目溯當年，璧水名流孰子先。", "杜甫生逢天寶末，陶潜空憶義熙前。", "明庭結綬懷新渥，暗壁移燈理舊編。", "約對青山譚出處，一冬澗雪長新泉。"]'),
('0e3d38bb-3c70-47bb-8933-f970b7dbd03b','和陳無逸見贈草堂詩韻','陸文圭','宋','宋诗','song-poetry','','[]','綈袍誰念故人寒，轉徙蕭然老伯鸞。',64,'全唐诗/poet.song.248000.json','["綈袍誰念故人寒，轉徙蕭然老伯鸞。", "幸喜雲山無屋礙，始知天地出門寬。", "悠悠歲月蟻旋磨，落落功名魚上竿。", "金谷已無歌舞地，輞川猶有畫圖看。"]'),
('711fe52a-5086-4d31-84a0-279190616174','郡幕請講書和药房先生韻','陸文圭','宋','宋诗','song-poetry','','[]','不爲祁寒暫輟冬，肯移蓮幕下芹宮。',64,'全唐诗/poet.song.248000.json','["不爲祁寒暫輟冬，肯移蓮幕下芹宮。", "深青豈必從藍出，美玉何煩就石礱。", "殘雪五更侵几白，一燈深夜照書紅。", "他年共赴長安召，正恐諸儒却誚通。"]'),
('1662f81b-fa00-45cb-8801-b54e26c47e41','和蔣公秉思歸韻','陸文圭','宋','宋诗','song-poetry','','[]','不愁世路太行難，自歎行藏愧孔顔。',64,'全唐诗/poet.song.248000.json','["不愁世路太行難，自歎行藏愧孔顔。", "借榻寺中分兩寺，思鄉山上又重山。", "凄然碧草天連遠，輸與白雲僧對閒。", "我亦天涯流落客，何時同賦大刀還。"]'),
('234aaff9-c0fc-4f1b-a873-0b24c89c0a10','和郭有章見贈韻','陸文圭','宋','宋诗','song-poetry','','[]','敬亭山屬謝家詩，太白重來又一奇。',64,'全唐诗/poet.song.248000.json','["敬亭山屬謝家詩，太白重來又一奇。", "天既生才宜用世，士多有志不逢時。", "屠龍合讓高人手，捫虱纔堪童子師。", "大厦支顛要梁木，獨甘杞菊老天隨。"]'),
('3a6016ad-e9ab-4272-92e2-8f7e1c13d30e','和陸振之見寄韻','陸文圭','宋','宋诗','song-poetry','','[]','日長不廢讀書功，我與宗人老頗同。',64,'全唐诗/poet.song.248000.json','["日長不廢讀書功，我與宗人老頗同。", "病起自羞黄面老，興來人笑白頭翁。", "剖瓜未信能祈巧，結柳終須學送窮。", "樽酒論文定何日，碧雲暮合憶江東。"]'),
('54cbe369-2483-4850-b9d2-a53c521c73c9','代和翟知事舟中寄登光陽樓詩韻','陸文圭','宋','宋诗','song-poetry','','[]','登臨送目際天涯，人物風流勝永嘉。',64,'全唐诗/poet.song.248000.json','["登臨送目際天涯，人物風流勝永嘉。", "已泝清流乘畫鷁，尚留醉墨看塗鴉。", "長空黯淡吹雲葉，別浦微茫蹴浪花。", "老守江城閑兀坐，秋宵短夢苦思家。"]'),
('e737269a-1904-404d-a476-940727f7947b','和劉濬見贄韻','陸文圭','宋','宋诗','song-poetry','','[]','踽踽凉凉莫我知，讀書漸懶任嘲師。',64,'全唐诗/poet.song.248000.json','["踽踽凉凉莫我知，讀書漸懶任嘲師。", "荷鋤亦欲耕綿上，把釣因思入漢陂。", "姑讓著鞭先士稚，何須舉扇障元規。", "巴人白雪難同調，今古應無兩子期。"]'),
('f7bb37f7-b2e5-4a81-9ef4-ce783c616501','和鄧善之寄王一初并見柬韻','陸文圭','宋','宋诗','song-poetry','','[]','抱拙投閑計未疏，但看歲晏復何如。',64,'全唐诗/poet.song.248000.json','["抱拙投閑計未疏，但看歲晏復何如。", "丹山碧水吟招隠，白髪蒼顔賦遂初。", "逸少幽情誰與暢，元龍豪氣未全除。", "柴門有客迂雙屐，何不相逢許史廬。"]'),
('96e58899-0fca-46c5-841c-d7bafa576ea1','和戴帥初寄詩韻','陸文圭','宋','宋诗','song-poetry','','[]','入海逢車陸用艘，仁人不遇歎游遨。',64,'全唐诗/poet.song.248000.json','["入海逢車陸用艘，仁人不遇歎游遨。", "登龍有意師元禮，刻鵠何心效伯高。", "每笑囚山非國語，絕憐投閣反離騷。", "此身幸免官驅使，兩手猶能把酒螯。"]'),
('6b9b4512-6f44-4e5e-9717-96b8652c8266','次樊晉山長贄見韻二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','閉戶柴車久不巾，但思言行謹書紳。',64,'全唐诗/poet.song.248000.json','["閉戶柴車久不巾，但思言行謹書紳。", "可憐麋鹿山中友，不是麒麟閣上人。", "作賦也應曾感舊，爲師那敢望知新。", "老饕誰獻先生壽，自酌蒲桃舞鬰輪。"]'),
('1f738d36-4942-45b4-8da8-f522bc4d73db','次樊晉山長贄見韻二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','我羨君才桂一枝，天門步擔束書歸。',64,'全唐诗/poet.song.248000.json','["我羨君才桂一枝，天門步擔束書歸。", "藥方按古藏芝籠，花樣翻新織錦機。", "不恥緼袍身自貴，能知璞玉世尤稀。", "天寒野曠來時路，一笑應疑吾道非。"]'),
('891b416d-dfab-46e4-bf08-b60d5546e33f','次韻袁艮所投贈','陸文圭','宋','宋诗','song-poetry','','[]','意氣沖霄義薄雲，白頭傾蓋即相親。',64,'全唐诗/poet.song.248000.json','["意氣沖霄義薄雲，白頭傾蓋即相親。", "耳邊久不聞瑰論，眼底初驚見玉人。", "歷代文章空自變，致君風俗幾時淳。", "世間別有經綸手，不屬柴門老病身。"]'),
('d57dacfc-516b-4a1f-ba4b-3b2cfbae2cf3','次鄭前山絲字韻','陸文圭','宋','宋诗','song-poetry','','[]','人笑學官如兔絲，誰能千里遠尋師。',64,'全唐诗/poet.song.248000.json','["人笑學官如兔絲，誰能千里遠尋師。", "歸田便覺知機早，舂市應嫌見事遲。", "縱欲著鞭何所往，奚須按劍復相疑。", "世人多享容容福，白璧從來不可爲。"]'),
('253acc8b-ed78-42c3-8c7c-8ba8f41a4f40','留別王伯洪平章高顯卿左丞','陸文圭','宋','宋诗','song-poetry','','[]','幼從翰墨場中出，晚見車書宇內同。',64,'全唐诗/poet.song.248000.json','["幼從翰墨場中出，晚見車書宇內同。", "四十年前沾雨露，三千里外犯霜風。", "蛾眉共妬嬋娟女，鶴髪誰憐矍鑠翁。", "回首束書歸舊隠，江南笋蕨滿山中。"]'),
('9085e74e-5dd4-4421-b4db-c8f72d3b8fb8','別管韶夫','陸文圭','宋','宋诗','song-poetry','','[]','胸中耿耿挾孤征，刺口逢人輒論兵。',64,'全唐诗/poet.song.248000.json','["胸中耿耿挾孤征，刺口逢人輒論兵。", "投筆少年真燕頷，著鞭中夜忽鷄聲。", "功名險處方成就，節義窮時要講明。", "別有中庸書一卷，勸君西謁范高平。"]'),
('dc506af7-a800-4098-93a8-9346938db391','送元帥移屯太倉','陸文圭','宋','宋诗','song-poetry','','[]','十乘元戎又啟行，澄川老稚送傾城。',64,'全唐诗/poet.song.248000.json','["十乘元戎又啟行，澄川老稚送傾城。", "北風吹轉旌旗影，東海歡騰鼓吹聲。", "桑麥千村無吠犬，波濤萬里息奔鯨。", "新年鳳詔催歸覲，殿內金甌覆姓名。"]'),
('078f7f06-c2a6-4626-85ad-33ebc967efe1','送陸誼齋按察','陸文圭','宋','宋诗','song-poetry','','[]','使星出照三吳地，原隰馳驅遠有光。',64,'全唐诗/poet.song.248000.json','["使星出照三吳地，原隰馳驅遠有光。", "鷹擊何如學鸞鳳，狐多且莫問豺狼。", "懷金昌邑難污震，置酒清河反怒章。", "今日故人無請託，他年鴻燕勿相忘。"]'),
('4af92df7-f200-4656-81f7-ab8df3d7166d','送葉敏卿提領','陸文圭','宋','宋诗','song-poetry','','[]','牆東老檜屋三間，几案亭亭背遠山。',64,'全唐诗/poet.song.248000.json','["牆東老檜屋三間，几案亭亭背遠山。", "時事浮雲蒼狗變，機心滄海白鷗閒。", "歸與乍出紅蓮幕，行矣催歸玉筍班。", "老子婆娑今得計，底須坐客唱陽關。"]'),
('b29fe7cc-271f-4e5e-9d86-f1df30153a92','送嚴簡卿之燕爲司徒掾','陸文圭','宋','宋诗','song-poetry','','[]','漢儒多辟司徒掾，掾屬雖卑地望高。',64,'全唐诗/poet.song.248000.json','["漢儒多辟司徒掾，掾屬雖卑地望高。", "聞有袁安在公府，可無陳寵作辭曹。", "修鯨未肯隨鱗介，威鳳終須現羽毛。", "少壯功名當拾取，金臺落日射征袍。"]'),
('843e7efe-1153-4dcd-9857-f4b8b948fd8f','送劉侯之官吉州','陸文圭','宋','宋诗','song-poetry','','[]','暨州美政不三年，江右遺民借二天。',64,'全唐诗/poet.song.248000.json','["暨州美政不三年，江右遺民借二天。", "皂蓋朱旙新牧守，青原白鷺舊山川。", "邦衡奏疏雲中有，永叔詩章洛下傳。", "故里諸孫無恙否，下車第一表先賢。"]'),
('65b39cf0-8088-4327-835c-e635db858a19','送侯仲逵安豐之任','陸文圭','宋','宋诗','song-poetry','','[]','江上故人今送別，淮頭往事獨凄凉。',64,'全唐诗/poet.song.248000.json','["江上故人今送別，淮頭往事獨凄凉。", "陂成孫叔能强楚，城破劉公不負唐。", "千載與君期事業，一區憐我老耕桑。", "昇平幕府應多暇，書問時時遠寄將。"]'),
('58192d8b-2fbe-4c7b-9250-5e42c80a2fe1','送州官解任','陸文圭','宋','宋诗','song-poetry','','[]','小郡凋零不可爲，長官賢厚莫能欺。',64,'全唐诗/poet.song.248000.json','["小郡凋零不可爲，長官賢厚莫能欺。", "政聲鄰邑皆傳說，心事同僚盡得知。", "堪笑青蠅工點污，敢將白璧强瑕疵。", "清時公論終難冺，遺愛空留去後思。"]'),
('0990e886-677e-4558-b63f-fd0188c4b6bb','送張文友州判','陸文圭','宋','宋诗','song-poetry','','[]','太息君侯有祖風，棲棲五載簿書叢。',64,'全唐诗/poet.song.248000.json','["太息君侯有祖風，棲棲五載簿書叢。", "功臣昔繪雲臺上，循吏今標漢傳中。", "綠水江風送行色，紫金關月照孤忠。", "預人家國非吾事，但喜詩書氣味同。"]'),
('cc43945e-8a47-41d0-83dd-15f709a3a1d5','送丘景唐赴安豐教','陸文圭','宋','宋诗','song-poetry','','[]','元樞出督宣威地，名姓江淮草木知。',64,'全唐诗/poet.song.248000.json','["元樞出督宣威地，名姓江淮草木知。", "今見聞孫騎款段，去爲博士擁臯比。", "詩書澤遠真難繼，功業時來亦可爲。", "往事百年無處問，慶豐亭下稻連陂。"]'),
('3b802616-ac07-4f16-885f-e19b645569ad','送朱伯海入京','陸文圭','宋','宋诗','song-poetry','','[]','燕黍寒生春未回，可堪早別故園梅。',64,'全唐诗/poet.song.248000.json','["燕黍寒生春未回，可堪早別故園梅。", "新豐斗酒馬周去，京兆束書韓愈來。", "賦就不須呈狗監，敕除先合拜鸞臺。", "青雲附驥非吾願，自守書燈撥冷灰。"]'),
('ff51ba06-3c06-4b33-bf87-d91a2aa5455c','送朱鶴皋入京','陸文圭','宋','宋诗','song-poetry','','[]','故人天上調金鼎，應念先生苜蓿盤。',64,'全唐诗/poet.song.248000.json','["故人天上調金鼎，應念先生苜蓿盤。", "博士不煩重講席，拾遺無復歎儒冠。", "蓬萊海闊還須險，太華峰高不道寒。", "茅屋三間老書客，逢人懶問日長安。"]'),
('6b260b69-8391-4cfb-8f79-3a98f5a0e1a5','送王居實遊金陵','陸文圭','宋','宋诗','song-poetry','','[]','破氈吟雪擁清寒，有客虬髯急扣關。',64,'全唐诗/poet.song.248000.json','["破氈吟雪擁清寒，有客虬髯急扣關。", "歲月蒼茫千里暮，乾坤博大幾人閑。", "依乘自許風雲際，邂逅相逢草澤間。", "西上月林春未半，白鷗黄鵠看江山。"]'),
('653b8467-f880-4fcc-9b56-7c71b78ee429','送李義夫出遊二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','與君丱角志相期，歲晏行藏各有違。',64,'全唐诗/poet.song.248000.json','["與君丱角志相期，歲晏行藏各有違。", "老樹晚花空自媚，秋林病葉更先稀。", "時情淡薄元無味，世路艱危總是機。", "門外北風吹自冽，旅人瑣瑣欲安歸。"]'),
('602d275f-a57d-48ca-afa9-082e9bd5d17b','送李義夫出遊二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','少年有志東山卧，晚歲方圖北海遊。',64,'全唐诗/poet.song.248000.json','["少年有志東山卧，晚歲方圖北海遊。", "餬口饑寧甘半菽，拄胸氣尚食全牛。", "問唐元振今誰在，欲趙平原何處求。", "赤白洪崖兩相厄，不妨詩句各風流。"]'),
('da25e6f1-f933-4484-a84c-df39fc34803f','送魏叔華歸杭州得行字  其一','陸文圭','宋','宋诗','song-poetry','','[]','青山出郭兩相迎，潮去潮回客子程。',64,'全唐诗/poet.song.248000.json','["青山出郭兩相迎，潮去潮回客子程。", "門外送車今幾輛，筵中祝酒已三行。", "對牀有弟酬佳約，擁髻何人訴別情。", "桂樹結花當灑掃，重來曾指白鷗盟。"]'),
('1703390e-c399-4e29-979d-c88e77ff06ef','送魏叔華歸杭州得行字  其二','陸文圭','宋','宋诗','song-poetry','','[]','杜康橋下水如傾，九里岡頭路轉城。',64,'全唐诗/poet.song.248000.json','["杜康橋下水如傾，九里岡頭路轉城。", "風雨小樓清夢遠，山河古道幾人行。", "別懷漸覺傷安石，祖席何曾傲正平。", "珍重去逢南國友，爲言白髪老書檠。"]'),
('ff3e6a67-53ea-4472-9907-d23a3bed346d','餞劉繼明西歸','陸文圭','宋','宋诗','song-poetry','','[]','人生有三事如一，父子師友皆人倫。',64,'全唐诗/poet.song.248000.json','["人生有三事如一，父子師友皆人倫。", "入向親闈奉甘旨，出當書案服辛勤。", "老成識見無如子，少壯功名肯讓人。", "老我卑枝棲鷃爵，仰看黄鵠上青雲。"]'),
('b9da7b11-ccf3-4779-8fa6-ee86983b979e','送劉中齋孫歸三衢','陸文圭','宋','宋诗','song-poetry','','[]','百花頭上和羹手，乃祖聲名似孝先。',64,'全唐诗/poet.song.248000.json','["百花頭上和羹手，乃祖聲名似孝先。", "太息北朝開府老，真成故里爛柯仙。", "慶流冢嗣承先澤，學到孫枝又一傳。", "野叟臨岐無別語，勤修世業復青氈。"]'),
('0f5998dd-9590-4e5e-97bb-4faacb61905c','題桃源手卷','陸文圭','宋','宋诗','song-poetry','','[]','種柳栽桃總是春，興亡千古一沾巾。',64,'全唐诗/poet.song.248000.json','["種柳栽桃總是春，興亡千古一沾巾。", "只評隠者非仙者，莫悟秦人即晉人。", "年號記曾題甲子，兒孫肯使識君臣。", "南陽高士空遐想，不向柴桑去問津。"]'),
('10f8ad6c-a0a1-4dc1-bca1-3662bbf77e2e','題三洲詩卷','陸文圭','宋','宋诗','song-poetry','','[]','潮擁寒沙疋練長，東南人物老江鄉。',64,'全唐诗/poet.song.248000.json','["潮擁寒沙疋練長，東南人物老江鄉。", "藕花秋晚吳霜落，杜若春深楚水香。", "閑對漁樵談治亂，貪看鷗鷺失興亡。", "無人會得乘桴意，東面區區嘆海洋。"]'),
('1adfa91f-b11f-4777-b0d3-6369c560cb35','題陸義齋雙蓮圖','陸文圭','宋','宋诗','song-poetry','','[]','紅粉香中雙並蒂，碧絲藕下暗連株。',64,'全唐诗/poet.song.248000.json','["紅粉香中雙並蒂，碧絲藕下暗連株。", "主人一笑偶然爾，客子競誇前所無。", "堂上塤箎兄友弟，房中琴瑟婦隨夫。", "君家和氣濃如酒，此即雙蓮瑞慶圖。"]'),
('c50b7c3f-5229-446c-a438-48fd6c0c8f71','强南坡自作墓銘生求挽詩','陸文圭','宋','宋诗','song-poetry','','[]','年光催客過郵亭，八十餘翁尚典刑。',64,'全唐诗/poet.song.248000.json','["年光催客過郵亭，八十餘翁尚典刑。", "見說近成遺老傳，未當上應少微星。", "履香竊笑空題墓，寶玩何須自乞銘。", "今古達觀惟一士，山童負鍤醉劉伶。"]'),
('20125009-1e49-4c64-ae8a-ee0f962580a9','挽吉州劉總管','陸文圭','宋','宋诗','song-poetry','','[]','畫戟清香彼一時，歸舟素幔不勝悲。',64,'全唐诗/poet.song.248000.json','["畫戟清香彼一時，歸舟素幔不勝悲。", "墳成共負犍爲土，堂在空留蜀郡祠。", "亂起赤眉徐自定，憂侵白髪已先衰。", "平原歲晚多賓客，泉下難酬國士知。"]'),
('33dc260b-29b2-445a-8c86-0b58456a289f','挽李宣慰','陸文圭','宋','宋诗','song-poetry','','[]','公騎箕尾上秋旻，忍見龜趺對石麟。',64,'全唐诗/poet.song.248000.json','["公騎箕尾上秋旻，忍見龜趺對石麟。", "盛德固應祠百世，陰功何止活千人。", "壯圖落落心空在，華髪蕭蕭事轉新。", "耆老凋零關世運，可能知己獨沾巾。"]'),
('d32653a9-473c-4677-8a3a-9ca53067541d','挽晉千戶','陸文圭','宋','宋诗','song-poetry','','[]','燐草原頭十七霜，宛丘改卜日辰良。',64,'全唐诗/poet.song.248000.json','["燐草原頭十七霜，宛丘改卜日辰良。", "可憐先軫如生面，疑住靈均不死鄉。", "抔土豈能埋宿憤，遺民聊與發幽光。", "護喪諸子皆稱孝，萬室他年置墓傍。"]'),
('d61963f4-d6bb-44a4-abd6-b78afac2629e','挽唐可竹','陸文圭','宋','宋诗','song-poetry','','[]','穿楊折桂黄粱夢，庭下哦松白髪秋。',64,'全唐诗/poet.song.248000.json','["穿楊折桂黄粱夢，庭下哦松白髪秋。", "興廢乃關千古事，榮枯肯爲一身謀。", "江南有客朝金闕，天上無人記玉樓。", "丹旐西風范陽路，行人回首憶林丘。"]'),
('0d66f407-bd4e-47e8-8e72-6c288a907bcb','挽孫石山二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','今年星度歲爲龍，掩袂竟嗟吾道窮。',64,'全唐诗/poet.song.248000.json','["今年星度歲爲龍，掩袂竟嗟吾道窮。", "正始遺音從此絕，貞元舊曲爲誰工。", "飾棺不待百年盡，隠几元知萬事空。", "里有水心銘筆古，宜書潜德賁幽宮。"]'),
('06351417-f0da-4602-a766-7f856c7067cf','挽孫石山二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','榮華露槿落紛紛，蒼狗依然是白雲。',64,'全唐诗/poet.song.248000.json','["榮華露槿落紛紛，蒼狗依然是白雲。", "荆渚止稱前進士，灞亭不識故將軍。", "人間無樂徒勞子，天上求文即召君。", "楚些西風將淚去，隻鷄他日酹秋墳。"]'),
('361d78bf-0895-4b2b-95c7-c737594ac366','弔李古巖','陸文圭','宋','宋诗','song-poetry','','[]','堂堂山立萬人英，一夕霜風玉樹傾。',64,'全唐诗/poet.song.248000.json','["堂堂山立萬人英，一夕霜風玉樹傾。", "公去隠然關世道，客來何止哭交情。", "安知死不如生樂，但恨才難與命爭。", "幸喜肯堂丹雘手，隴西依舊振家聲。"]'),
('ed609631-5763-48e5-8932-b7a6669df96c','挽闕南夫','陸文圭','宋','宋诗','song-poetry','','[]','惡夢無端歲在蛇，先賢遺落重堪嗟。',64,'全唐诗/poet.song.248000.json','["惡夢無端歲在蛇，先賢遺落重堪嗟。", "粹然踐履終身實，老矣婆娑兩鬢華。", "不見鯉庭人獨立，忽驚鵩舍日西斜。", "窆碑好爲書潜德，窮巷誰尋仵作家。"]'),
('075c3079-99a4-49a0-a0f6-e9a178df2c94','挽陸義齋二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','四持憲節遍南方，屢表陳情返故鄉。',64,'全唐诗/poet.song.248000.json','["四持憲節遍南方，屢表陳情返故鄉。", "殊俗今猶歌德政，老天胡不愛忠良。", "山空虎逝狐狸出，春去花殘蛺蝶忙。", "五十人生不稱夭，獨憐華髪在高堂。"]'),
('5e28577d-a675-4097-b097-a61213426ecc','挽陸義齋二首  其二','陸文圭','宋','宋诗','song-poetry','','[]','生平意氣每相期，歲晚行藏各自知。',64,'全唐诗/poet.song.248000.json','["生平意氣每相期，歲晚行藏各自知。", "見事略同因撫掌，憂時不語共攢眉。", "闔棺已矣公何憾，聞笛凄然我獨悲。", "回首秋山寒雨外，青松滴淚作枯枝。"]'),
('ca02358a-105d-49b5-8579-b0a19fad7c27','挽東平張彥明','陸文圭','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','夢覺黄粱僅一炊，人生適意不多時。',64,'全唐诗/poet.song.248000.json','["夢覺黄粱僅一炊，人生適意不多時。", "杜陵老病親桃竹，白傅清閒憶柳枝。", "有意出山尋樹檟，傷心歸櫬頼門楣。", "秋風淚滴長江水，遥寄東原薤露詩。"]'),
('ee2af571-7bb6-4176-8b57-a4e64af73990','挽黄子高','陸文圭','宋','宋诗','song-poetry','','[]','場屋初興選異才，先生闊步上金臺。',64,'全唐诗/poet.song.248000.json','["場屋初興選異才，先生闊步上金臺。", "蓬山渺渺仙舟隔，泮水悠悠講席開。", "同是甲辰雌正伏，胡然庚子鵩爲災。", "天寒病叟那能出，一束生芻寄淚來。"]'),
('dd07f306-7691-4cc6-a4c7-4c8e3ffc5b21','挽丘景南','陸文圭','宋','宋诗','song-poetry','','[]','紫荆庭下列三株，十五年中次第枯。',64,'全唐诗/poet.song.248000.json','["紫荆庭下列三株，十五年中次第枯。", "餘慶後來英俊有，老成先輩典刑無。", "每懷素志甘瓢飲，不覺長身要杖扶。", "頭白少公門下客，酸風吹淚灑輤塗。"]'),
('cbda1ac9-a783-4fcb-9ba7-4e9b8b263fee','蔡梅邊挽詩二首  其一','陸文圭','宋','宋诗','song-poetry','','[]','樽酒吟梅憶舊遊，忍聽笳鼓咽原頭。',64,'全唐诗/poet.song.248000.json','["樽酒吟梅憶舊遊，忍聽笳鼓咽原頭。", "曾廬柏下三年墓，退卧花間百尺樓。", "淮海壯心空落落，山林晚興寄悠悠。", "寒窗寂寞留孤月，勸孝坊前客淚流。"]'),
('f2389b66-d9da-4023-85f2-72a6492b8da0','蔡梅邊挽詩二首  其二','陸文圭','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','憶昔艱難共避兵，轉於貴賤見交情。',64,'全唐诗/poet.song.248000.json','["憶昔艱難共避兵，轉於貴賤見交情。", "長江一水分南北，異姓兩家真弟兄。", "回首忽驚人世換，傷心敢負歲寒盟。", "空亭花月如春夢，惟有清溪一带橫。"]'),
('c1e1bf5d-2c30-456e-9a7e-240585f8830a','挽張州尹夫人','陸文圭','宋','宋诗','song-poetry','','[]','新頒五色金花誥，彩服兒孫正滿堂。',64,'全唐诗/poet.song.248000.json','["新頒五色金花誥，彩服兒孫正滿堂。", "不見魚軒隨五馬，空令鸞鏡照孤凰。", "車中鬢老愁潘岳，案上眉低憶孟光。", "流水無情飄素幔，凉宵燕寢獨凝香。"]'),
('7c8ebab5-e207-45da-86af-3e94a2943c15','絕句三首  其一','陸文圭','宋','宋诗','song-poetry','','[]','車薪勝杯水，輿羽重鈎金。',24,'全唐诗/poet.song.248000.json','["車薪勝杯水，輿羽重鈎金。", "物理元無定，權衡只在心。"]'),
('feb8d971-7ac6-40fd-bd82-31eb8d619cf7','絕句三首  其二','陸文圭','宋','宋诗','song-poetry','','[]','買絲繡平原，儗金鑄子期。',24,'全唐诗/poet.song.248000.json','["買絲繡平原，儗金鑄子期。", "君子病無能，不病人不知。"]'),
('d29c3c25-5034-4805-8305-2a52a175319c','絕句三首  其三','陸文圭','宋','宋诗','song-poetry','','[]','杜欲誅雲師，韓將訟風伯。',24,'全唐诗/poet.song.248000.json','["杜欲誅雲師，韓將訟風伯。", "水旱不由天，那是詩人責。"]'),
('f90c389f-a764-4141-b581-160a15a8a661','雪夜不寐偶成短句十首用渭北春天樹江東日暮雲爲韻  其一','陸文圭','宋','宋诗','song-poetry','','[]','丈夫慎出處，功成乃身退。',24,'全唐诗/poet.song.248000.json','["丈夫慎出處，功成乃身退。", "古人夫何如，八十釣清渭。"]'),
('eda9f448-368c-47c3-a728-89ef2998646b','雪夜不寐偶成短句十首用渭北春天樹江東日暮雲爲韻  其二','陸文圭','宋','宋诗','song-poetry','','[]','四時循化機，萬物隨動息。',24,'全唐诗/poet.song.248000.json','["四時循化機，萬物隨動息。", "衆星紛熒熒，天運齊拱北。"]'),
('1d09793d-4be2-4ce9-9b89-343717f00ad3','雪夜不寐偶成短句十首用渭北春天樹江東日暮雲爲韻  其三','陸文圭','宋','宋诗','song-poetry','','[]','縞素製野服，誤染京華塵。',24,'全唐诗/poet.song.248000.json','["縞素製野服，誤染京華塵。", "舊業在何處，梅花江上春。"]'),
('06976650-5b76-4630-b839-e4be03f0ed56','雪夜不寐偶成短句十首用渭北春天樹江東日暮雲爲韻  其四','陸文圭','宋','宋诗','song-poetry','','[]','男兒不得志，壯心惜徂年。',24,'全唐诗/poet.song.248000.json','["男兒不得志，壯心惜徂年。", "長空起鵰鶚，目送入寥天。"]'),
('a804a330-fc7e-4230-bd6d-b83e0836b1c8','雪夜不寐偶成短句十首用渭北春天樹江東日暮雲爲韻  其五','陸文圭','宋','宋诗','song-poetry','','[]','布衾生凄寒，夜夜夢歸去。',24,'全唐诗/poet.song.248000.json','["布衾生凄寒，夜夜夢歸去。", "心恐秋風深，摧殘紫荆樹。"]'),
